-- Poems batch 125
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f4bac0f6-2833-4abf-ac06-1ebfcdc3f7c7','雜詠四首  其四','陸游','宋','宋诗','song-poetry','','[]','舊聞五嶽多靈藥，晚遇高人得秘文。',32,'全唐诗/poet.song.135000.json','["舊聞五嶽多靈藥，晚遇高人得秘文。", "夢境此身常是客，幾時歸卧華山雲。"]'),
('7e85b193-5460-47df-a6e2-cda592ac503f','曉起折梅','陸游','宋','宋诗','song-poetry','','[]','織女斜河漏已殘，長庚配月夜將闌。',32,'全唐诗/poet.song.135000.json','["織女斜河漏已殘，長庚配月夜將闌。", "小橋幽徑無人見，折得梅花伴曉寒。"]'),
('04f27409-97f5-413f-90ce-8f45e047e05c','累日濃雲作雪不成遂有春意','陸游','宋','宋诗','song-poetry','','[]','釀雪經旬竟不成，一霜却作十分晴。',64,'全唐诗/poet.song.135000.json','["釀雪經旬竟不成，一霜却作十分晴。", "雲歸岫穴千峰立，暖入郊原萬耦耕。", "菖葉離離豐歲候，梅花眷眷故人情。", "道傍孤店新醅熟，已有幽禽一兩聲。"]'),
('7e06d819-dbb5-4c59-95e7-40e81d78bd2a','晚晴出行近村閑詠景物','陸游','宋','宋诗','song-poetry','','[]','雪雲吹盡木陰移，正是先生曳杖時。',64,'全唐诗/poet.song.135000.json','["雪雲吹盡木陰移，正是先生曳杖時。", "老㹀行將新長犢，空桑卧出寄生枝。", "醫翁暮過囊探藥，筮叟晨占手布蓍。", "誰謂人間足憂患，未妨古俗自熙熙。"]'),
('688d64ef-1ec0-4ae4-beaa-646b263f1e4a','道室戲詠','陸游','宋','宋诗','song-poetry','','[]','道身隠太華，壯歲客青城。',48,'全唐诗/poet.song.135000.json','["道身隠太華，壯歲客青城。", "采藥何辭遠，燒丹久未成。", "傅生已醉死，韓子得狂名。", "猶有殘詩在，他年遺後生。"]'),
('bab4965d-c198-452e-a7c7-4c3a7389432c','書感三首  其一','陸游','宋','宋诗','song-poetry','','[]','人生百憂坐一官，况與群飛接羽翰。',64,'全唐诗/poet.song.135000.json','["人生百憂坐一官，况與群飛接羽翰。", "兩具吳牛給耕足，三間茅屋著身寬。", "焄蒿凄愴會不免，簡儉寂默差可安。", "康莊坦坦不整駕，可憐平地生濤瀾。"]'),
('0c69dbc1-9340-4c44-92cf-f9423618436e','書感三首  其二','陸游','宋','宋诗','song-poetry','','[]','舞非得譜拍拍錯，行未知津步步危。',64,'全唐诗/poet.song.135000.json','["舞非得譜拍拍錯，行未知津步步危。", "劫石消磨會當盡，太行突兀乃可移。", "清晨瓦釜煮藜粥，遥夜地爐燒豆萁。", "此中正自有佳處，區區外慕寧非癡。"]'),
('57f3fc47-3d4e-40f6-abcd-382bad124e30','書感三首  其三','陸游','宋','宋诗','song-poetry','','[]','茅簷住穩勝華屋，芋糝味甘如大烹。',64,'全唐诗/poet.song.135000.json','["茅簷住穩勝華屋，芋糝味甘如大烹。", "靜觀萬事付一默，掃空白髮非黄精。", "丈人祠西鶴傳信，小姑山前鼉報更。", "興闌却揮短棹去，曉渡清伊聽玉笙。"]'),
('6006c2f4-e05c-4739-a80c-1008f9ed5b9c','臘月','陸游','宋','宋诗','song-poetry','','[]','今冬少霜雪，臘月厭重裘。',48,'全唐诗/poet.song.135000.json','["今冬少霜雪，臘月厭重裘。", "漸動園林興，頓寬薪炭憂。", "山陂泉脈活，村市柳枝柔。", "春餠吾何患，嘉蔬日可求。"]'),
('09eb4543-14bd-4a9c-ab5b-31944b234c83','雪作','陸游','宋','宋诗','song-poetry','','[]','今年冬暖異常時，造物收功乃爾奇。',64,'全唐诗/poet.song.135000.json','["今年冬暖異常時，造物收功乃爾奇。", "平野忽看吹雪片，清池俄復結冰澌。", "飛蝗掃地無遺種，瑞麥連雲有兩岐。", "想見市樓增酒價，深居袖手嘆吾衰。"]'),
('000344a6-9756-4c54-9bc8-41607045e86b','即事','陸游','宋','宋诗','song-poetry','','[]','雲本無心木不材，平生得喪信悠哉。',64,'全唐诗/poet.song.135000.json','["雲本無心木不材，平生得喪信悠哉。", "釣魚每過桐江宿，賣藥新從剡縣回。", "山圃萵蔓晨灌溉，地爐芋栗夜燔煨。", "人情萬變吾何預，笑口何妨處處開。"]'),
('6a375a62-4667-4ee6-8116-ef4412221b7c','或遺以兩大瓢因寓物外興','陸游','宋','宋诗','song-poetry','','[]','槲葉爲衣草結廬，生涯正付兩葫蘆。',64,'全唐诗/poet.song.135000.json','["槲葉爲衣草結廬，生涯正付兩葫蘆。", "名山歷遍家何有，塵念空來夢欲無。", "野鶴巢雲元自瘦，澗松埋雪定非枯。", "悠然但覓高樓醉，何處人間無酒徒。"]'),
('a61af107-31c2-455e-b29f-6c92e5508f9e','歲未盡前數日偶題長句五首  其一','陸游','宋','宋诗','song-poetry','','[]','老向人間迹轉孤，參差烟火出菰蒲。',64,'全唐诗/poet.song.135000.json','["老向人間迹轉孤，參差烟火出菰蒲。", "數畦綠菜寒猶茁，一勺清泉手自𣂏。", "穀賤窺籬無狗盜，夜長暖足有狸奴。", "歲闌更喜人强健，小草書成鬰壘符。"]'),
('76be5613-132a-4a0a-96c4-27873f216814','歲未盡前數日偶題長句五首  其二','陸游','宋','宋诗','song-poetry','','[]','短褐蕭蕭一幅巾，明時乞與水雲身。',64,'全唐诗/poet.song.135000.json','["短褐蕭蕭一幅巾，明時乞與水雲身。", "平生不售屠龍技，投老真爲種菜人。", "釜粥芬香餉鄰父，闌豬豐腯祭家神。", "聯翩節物驚人眼，儺鼓停撾又見春。"]'),
('1f103173-45b2-4ae7-93c1-ee430dc8d32a','歲未盡前數日偶題長句五首  其三','陸游','宋','宋诗','song-poetry','','[]','栟櫚小弁野人裝，八十三年舊話長。',64,'全唐诗/poet.song.135000.json','["栟櫚小弁野人裝，八十三年舊話長。", "真笑形骸無藉在，本知生世不牢强。", "茅簷啼鳥初相命，烟渚歸鴻漸著行。", "想得城中盛冠蓋，家家來往薦椒觴。"]'),
('c4c8d69e-8aa9-4d64-89c1-8823ce297f60','歲未盡前數日偶題長句五首  其四','陸游','宋','宋诗','song-poetry','','[]','風號四野雲如墨，徂歲消磨不滿旬。',64,'全唐诗/poet.song.135000.json','["風號四野雲如墨，徂歲消磨不滿旬。", "瑞雪便應平地尺，野梅又報一年春。", "長河斷渡冰將合，古寺題詩手爲皴。", "僵卧閉門行路絕，安知今代獨無人。"]'),
('81c98188-4538-462e-bca5-f0f5b3a68503','歲未盡前數日偶題長句五首  其五','陸游','宋','宋诗','song-poetry','','[]','漸近新年日愈長，不辭扶病舉椒觴。',64,'全唐诗/poet.song.135000.json','["漸近新年日愈長，不辭扶病舉椒觴。", "了無一事干靈府，只合終身住醉鄉。", "鬭飣春盤兒女喜，擣簁臘藥婢奴忙。", "蜀州白首猶癡絕，更與梅花賦斷腸。"]'),
('61ac4ca1-c705-4303-9de0-36857d28af9f','余得蘆竹拄杖于舍傍民家似蘆非蘆堅勁輕滑色如栗玉入手錯然微有聲它杖莫及作五字唐律記之','陸游','宋','宋诗','song-poetry','','[]','輕堅蘆竹杖，入用自龜堂。',48,'全唐诗/poet.song.135000.json','["輕堅蘆竹杖，入用自龜堂。", "挺節冰霜後，論交歲月長。", "心空無寵辱，時異有行藏。", "老病登臨少，何妨日倚床。"]'),
('af235a45-5e44-4f44-9e7f-bee6a80c6206','八十四吟二首  其一','陸游','宋','宋诗','song-poetry','','[]','新歲八十四，自宜形影孤。',48,'全唐诗/poet.song.135000.json','["新歲八十四，自宜形影孤。", "睡憑書擯相，愁頼酒枝梧。", "兒問離騷字，僧傳本草圖。", "孰言生計薄，種芋已成區。"]'),
('76593f18-28a8-459c-acee-8ca8b15dc91c','八十四吟二首  其二','陸游','宋','宋诗','song-poetry','','[]','七十人稀到，吾過十四年。',48,'全唐诗/poet.song.135000.json','["七十人稀到，吾過十四年。", "交遊無輩行，懷抱有曾玄。", "飲敵騎鯨客，行追縮地仙。", "城南春事動，小蹇又翩翩。"]'),
('d7a80b68-4a89-459b-b2ee-4fecb618ba83','歲暮六首  其一','陸游','宋','宋诗','song-poetry','','[]','書房偷得蝸廬樣，僅僅能容老病身。',32,'全唐诗/poet.song.135000.json','["書房偷得蝸廬樣，僅僅能容老病身。", "紙被蒙頭方坐穩，却愁轉眼又新春。"]'),
('4a950777-02a7-4693-bef5-b1719f8b0063','歲暮六首  其二','陸游','宋','宋诗','song-poetry','','[]','淺色染成官柳絲，水沉熏透野梅枝。',32,'全唐诗/poet.song.135000.json','["淺色染成官柳絲，水沉熏透野梅枝。", "客來莫怪逢迎懶，正伴曾孫竹馬嬉。"]'),
('be41be5c-8ff1-4e42-ba62-b42b88f5958a','歲暮六首  其三','陸游','宋','宋诗','song-poetry','','[]','挹泉石鼎煎崖蜜，候火銅爐炷海沉。',32,'全唐诗/poet.song.135000.json','["挹泉石鼎煎崖蜜，候火銅爐炷海沉。", "一坐便應論十劫，不知歲月去駸駸。"]'),
('428fa350-8289-405f-ad4c-45fe78d673ce','歲暮六首  其四','陸游','宋','宋诗','song-poetry','','[]','久衰豈是見人時，健忘偏于養性宜。',32,'全唐诗/poet.song.135000.json','["久衰豈是見人時，健忘偏于養性宜。", "噉飯著衣常苦懶，爲誰欲理一團絲。"]'),
('e2827d57-5c50-4016-9fb5-86a72ae732d6','歲暮六首  其五','陸游','宋','宋诗','song-poetry','','[]','燕脂斑出古銅鼎，彈子窩深湖石山。',32,'全唐诗/poet.song.135000.json','["燕脂斑出古銅鼎，彈子窩深湖石山。", "老去柴門誰復過，天教二友伴清閑。"]'),
('668821b2-aa59-4280-bccf-bb21ff9ddbb2','歲暮六首  其六','陸游','宋','宋诗','song-poetry','','[]','少慕浮名百種癡，老知世事盡兒嬉。',32,'全唐诗/poet.song.135000.json','["少慕浮名百種癡，老知世事盡兒嬉。", "從今春困不須賣，睡到日高三丈時。"]'),
('68a10efb-8cd7-4a5d-bd84-866b44a4cc2e','書感','陸游','宋','宋诗','song-poetry','','[]','襁負客淮潁，髧髦逢亂離。',48,'全唐诗/poet.song.135000.json','["襁負客淮潁，髧髦逢亂離。", "中原遂乖隔，北望每傷悲。", "泛渭題新賦，遊嵩續舊詩。", "死生雖異世，此意未應移。"]'),
('3f170c03-e14d-4109-8f8b-486eabca1ee4','書適','陸游','宋','宋诗','song-poetry','','[]','細讀養生主，長歌歸去來。',48,'全唐诗/poet.song.135000.json','["細讀養生主，長歌歸去來。", "山僧借水品，溪父送琴材。", "病退稀求藥，身閑日探梅。", "今宵喜無寐，岷下有書回。"]'),
('88313ada-3ec4-4585-9825-f003b92fc927','學道','陸游','宋','宋诗','song-poetry','','[]','學道知專氣，尊生得養形。',48,'全唐诗/poet.song.135000.json','["學道知專氣，尊生得養形。", "精神生尺宅，虛白集中扃。", "出岫孤雲靜，凌霜老柏青。", "晨興取澗水，漱齒讀黄庭。"]'),
('3a9c1a1a-eebe-458b-b719-feca16b67186','舟中作','陸游','宋','宋诗','song-poetry','','[]','東浦菰蒲合，南莊桑柘繁。',48,'全唐诗/poet.song.135000.json','["東浦菰蒲合，南莊桑柘繁。", "潮生無斷港，寺廢有頹垣。", "糴米尋山步，移舟泊水村。", "野人多舊識，相對兩無言。"]'),
('85393e7b-2997-4e81-a4f8-6fb39699d163','得蜀信','陸游','宋','宋诗','song-poetry','','[]','齒髮凋零志氣衰，强臨尊酒祇成悲。',64,'全唐诗/poet.song.135000.json','["齒髮凋零志氣衰，强臨尊酒祇成悲。", "少年半是投閑日，春事常當卧病時。", "憂患頗疑書作祟，功名不似老如期。", "青城舊友頻相約，歸養金丹尚未遲。"]'),
('c4c2b510-d1e8-4a0c-ada1-53aabc6246ee','送蘇趙叟赴省試','陸游','宋','宋诗','song-poetry','','[]','關路誰非觀國賓，此君肝膽獨輪囷。',64,'全唐诗/poet.song.135000.json','["關路誰非觀國賓，此君肝膽獨輪囷。", "故家遺俗欲墜地，博士議郎方要人。", "久矣扁舟弄江月，往哉駸馬踏京塵。", "敕中墨色如鴉溼，日待東歸一笑新。"]'),
('6554b1dc-9c12-49df-b6c4-0fb886db69c4','新春感事八首終篇因以自解  其一','陸游','宋','宋诗','song-poetry','','[]','九陌風和不起塵，平湖冰解欲生鱗。',32,'全唐诗/poet.song.135000.json','["九陌風和不起塵，平湖冰解欲生鱗。", "往來朝暮紛如蟻，得見新春有幾人。"]'),
('6cab3467-5aea-4936-ad93-e02a4424f708','新春感事八首終篇因以自解  其二','陸游','宋','宋诗','song-poetry','','[]','興來遊衍不辭遥，吹帽風輕過畫橋。',32,'全唐诗/poet.song.135000.json','["興來遊衍不辭遥，吹帽風輕過畫橋。", "猩血未看開露蕊，麴塵先已上烟條。"]'),
('9639d267-8a62-4f0a-b74e-1ba56c1bcea9','新春感事八首終篇因以自解  其三','陸游','宋','宋诗','song-poetry','','[]','一年最好早春天，風日初和未脫綿。',32,'全唐诗/poet.song.135000.json','["一年最好早春天，風日初和未脫綿。", "坎坎圓鼙賽神社，翻翻小繖下湖船。"]'),
('d1e0e1d7-ec48-433d-b800-511bfc2bb641','新春感事八首終篇因以自解  其四','陸游','宋','宋诗','song-poetry','','[]','憶到夔門正月初，竹枝歌舞擁肩輿。',32,'全唐诗/poet.song.135000.json','["憶到夔門正月初，竹枝歌舞擁肩輿。", "當時光景應如昨，綠鬢治中八十餘。"]'),
('5745ef5b-4515-4f71-983f-2a025bf11c1e','新春感事八首終篇因以自解  其五','陸游','宋','宋诗','song-poetry','','[]','錦城舊事不堪論，回首繁華欲斷魂。',32,'全唐诗/poet.song.135000.json','["錦城舊事不堪論，回首繁華欲斷魂。", "繡轂金羈三十里，至今猶夢小東門。"]'),
('34845b29-fa90-4071-8b99-a7cb0f08a7ac','新春感事八首終篇因以自解  其六','陸游','宋','宋诗','song-poetry','','[]','玻璃江上柳如絲，行樂家家要及時。',32,'全唐诗/poet.song.135000.json','["玻璃江上柳如絲，行樂家家要及時。", "只怪今朝空巷出，使君人日宴蟆頤。"]'),
('2e5b8f26-5720-428c-acf3-4fca3ec553bc','新春感事八首終篇因以自解  其七','陸游','宋','宋诗','song-poetry','','[]','梁州陌上女成群，銅綠春衫罨畫裙。',32,'全唐诗/poet.song.135000.json','["梁州陌上女成群，銅綠春衫罨畫裙。", "相喚遊家園裏去，鞦韆高挂欲侵雲。"]'),
('0787268f-2531-4be1-a637-5519ceef3fa2','新春感事八首終篇因以自解  其八','陸游','宋','宋诗','song-poetry','','[]','烏藤即是碧油幢，百萬天魔指顧降。',32,'全唐诗/poet.song.135000.json','["烏藤即是碧油幢，百萬天魔指顧降。", "酣枕不知霜縞瓦，下床已見日烘窗。"]'),
('9ab142e1-8790-4a45-ba91-8c9fd6f76db8','自嘆','陸游','宋','宋诗','song-poetry','','[]','晨興袖手觀空寂，飯罷寬腰習按摩。',32,'全唐诗/poet.song.135000.json','["晨興袖手觀空寂，飯罷寬腰習按摩。", "堪嘆一生閑日月，爲身時少爲人多。"]'),
('8ce2a67c-b4d7-435a-85dd-e23d022e7f7d','初春二首  其一','陸游','宋','宋诗','song-poetry','','[]','春入陂湖已折冰，流年誰解繫長繩。',64,'全唐诗/poet.song.135000.json','["春入陂湖已折冰，流年誰解繫長繩。", "土膏動後麥苗長，桑眼綻來蠶事興。", "稅足了無徵欠吏，飯香時有乞齋僧。", "開正父老頻占候，已决今年百稼登。"]'),
('ba59bd46-496c-41ba-b86c-4d5162836085','初春二首  其二','陸游','宋','宋诗','song-poetry','','[]','漠漠春寒罷對棋，霏霏春雨却催詩。',64,'全唐诗/poet.song.135000.json','["漠漠春寒罷對棋，霏霏春雨却催詩。", "梅花一樹映疏竹，茅屋三間圍短籬。", "醉倒幸無官長駡，出遊自有老人期。", "年光滿眼吾何憾，又近吳蠶浴種時。"]'),
('19c0c43f-7f7e-48d4-a87a-80203c9b7ba1','簡傅十八官','陸游','宋','宋诗','song-poetry','','[]','朋舊凋零盡，新交得雋人。',48,'全唐诗/poet.song.135000.json','["朋舊凋零盡，新交得雋人。", "文章諧律呂，議論足精神。", "甚欲邀聯騎，無如困負薪。", "蘭亭修禊近，爲記永和春。"]'),
('20bafa6f-9fea-4a45-8bdf-2a9e8ed85bdf','開歲愈貧戲詠','陸游','宋','宋诗','song-poetry','','[]','謝事貧過筮仕初，歸裝僅有一柴車。',64,'全唐诗/poet.song.135000.json','["謝事貧過筮仕初，歸裝僅有一柴車。", "笥衣盡典仍耽酒，囷米無炊尚買書。", "澗底飽觀苗鬰鬰，夢中聊喜蝶蘧蘧。", "商山幾許功名事，老子如今却笑渠。"]'),
('af20e857-a25d-410c-9877-ec37a08423cb','戊辰立春日二首  其一','陸游','宋','宋诗','song-poetry','','[]','昨夜風搖斗柄回，典衣也復一傳杯。',64,'全唐诗/poet.song.135000.json','["昨夜風搖斗柄回，典衣也復一傳杯。", "故人久作天涯別，新句空從枕上來。", "清鏡豈堪看鬢色，小園剩欲覓桃栽。", "頹然却恨貪春睡，不盡城頭畫角哀。"]'),
('10ee131b-a645-4cc5-999d-7c758cf7ee7f','戊辰立春日二首  其二','陸游','宋','宋诗','song-poetry','','[]','卧聽城門出土牛，羅旛應笑雪蒙頭。',64,'全唐诗/poet.song.135000.json','["卧聽城門出土牛，羅旛應笑雪蒙頭。", "但須晨起一卮酒，聊洗人間千種愁。", "處處樓臺多俠客，家家船舫待春遊。", "梅花未遍枝南北，定爲餘寒得小留。"]'),
('ad72f3fb-5194-4172-be80-8a563fdb9da9','早春出遊','陸游','宋','宋诗','song-poetry','','[]','地爐久厭撥寒灰，一笑真成病眼開。',64,'全唐诗/poet.song.135000.json','["地爐久厭撥寒灰，一笑真成病眼開。", "不恨城笳催日落，且欣巷柳報春回。", "蹇馿破帽人人看，南陌東阡處處來。", "聞道禹祠遊漸盛，也謀隨例一持杯。"]'),
('a19d5a24-f069-40b2-8dcf-532dfb824f61','春寒','陸游','宋','宋诗','song-poetry','','[]','故歲無多雪，新春乃爾寒。',48,'全唐诗/poet.song.135000.json','["故歲無多雪，新春乃爾寒。", "柴車歸里社，茅舍老江干。", "客熟沽醨啜，孫癡索飯摶。", "更憐菘芥長，殊勝仰園官。"]'),
('7b7821d1-0264-46e0-b361-aecca4aec35b','園居','陸游','宋','宋诗','song-poetry','','[]','欲出還中止，微陰却快晴。',48,'全唐诗/poet.song.135000.json','["欲出還中止，微陰却快晴。", "檻花栽盡活，籠鳥教初成。", "身寄江湖久，心知富貴輕。", "還嬰吾所證，手自寫庵名。"]'),
('f37c1035-92cb-4353-8fab-73a8b655baf4','郊行','陸游','宋','宋诗','song-poetry','','[]','山色掃石黛，江流漲麴塵。',48,'全唐诗/poet.song.135000.json','["山色掃石黛，江流漲麴塵。", "春晴不終日，老病動經旬。", "竹密有啼鳥，村深多醉人。", "東阡與南陌，處處寄閑身。"]'),
('9fbe5f8b-f56c-4f21-b526-49946a6b962c','野望','陸游','宋','宋诗','song-poetry','','[]','偶携一小豎，徙倚望南山。',48,'全唐诗/poet.song.135000.json','["偶携一小豎，徙倚望南山。", "船笛爲誰怨，溪雲如我閑。", "洲長歸雁下，天迥暮鴉還。", "安得一竿去，終年烟水間。"]'),
('ea8600eb-b143-4ee5-85a8-8be51d60405e','晨起','陸游','宋','宋诗','song-poetry','','[]','日高霜漸釋，睡起髮猶蓬。',48,'全唐诗/poet.song.135000.json','["日高霜漸釋，睡起髮猶蓬。", "小圃經行外，新蔬檢校中。", "水開聞躍鯉，天遠看飛鴻。", "粥熟還歸舍，吾生亦未窮。"]'),
('3ca70843-4d42-4a16-b78c-3af99f292202','午坐','陸游','宋','宋诗','song-poetry','','[]','茶杯凝細乳，香岫起微雲。',48,'全唐诗/poet.song.135000.json','["茶杯凝細乳，香岫起微雲。", "樹影窗間見，禽聲屋角聞。", "流年易拋擲，舊學失鋤耘。", "師友今零落，何人爲運斤。"]'),
('40b8ee2d-c137-4358-9722-70f65af8618f','自警','陸游','宋','宋诗','song-poetry','','[]','生世如夢境，淹速無定時。',96,'全唐诗/poet.song.135000.json','["生世如夢境，淹速無定時。", "少壯不可恃，况汝迫耄期。", "五官及百骸，自揣日益衰。", "客來能送迎，要是强支持。", "百口皆新人，所至無舊知。", "紹興同朝者，掃地靡復遺。", "雖云窮耐久，造物豈汝私。", "餘日真幾何，得酒且伸眉。"]'),
('a2d6a300-effb-4e4b-b845-433fc4dac000','春雨','陸游','宋','宋诗','song-poetry','','[]','春陰不肯晴，春雨斷人行。',48,'全唐诗/poet.song.135000.json','["春陰不肯晴，春雨斷人行。", "慘澹柴荆色，蕭條鷄犬聲。", "香分豆子粥，美啜芋魁羹。", "猶勝梁州路，蒙氈夜下程。"]'),
('ee2b21f6-1eed-4fc3-8dcc-36fcf8a99747','春寒','陸游','宋','宋诗','song-poetry','','[]','冉冉年華過上元，梅花如雪照江村。',64,'全唐诗/poet.song.135000.json','["冉冉年華過上元，梅花如雪照江村。", "雲歸翠竇初收雨，人怕清寒懶出門。", "香燼已殘爐未冷，客談方劇酒重溫。", "尚嫌塵境妨幽致，過埭船聲暮正喧。"]'),
('be03d25b-f076-4565-bcde-7c3c6645a57e','自喜二首  其一','陸游','宋','宋诗','song-poetry','','[]','了了復惺惺，蓍龜未是靈。',48,'全唐诗/poet.song.135000.json','["了了復惺惺，蓍龜未是靈。", "閑中有富貴，壽外更康寧。", "身備鄉三老，家傳子一經。", "春回元不記，出戶四山青。"]'),
('1c31d9dd-1d67-47c8-816f-c1fb28c7ad7e','自喜二首  其二','陸游','宋','宋诗','song-poetry','','[]','身寄人間世，心常古鏡如。',48,'全唐诗/poet.song.135000.json','["身寄人間世，心常古鏡如。", "喚醒狂蝶夢，掃盡老狐書。", "年出鄉閭右，貧過仕宦初。", "村村是桃李，豈獨愛吾廬。"]'),
('ae4e3b90-8093-4db5-86f1-c25c16637220','簡湖中隠者','陸游','宋','宋诗','song-poetry','','[]','夫子終年醉不醒，若爲問我故丁寧。',64,'全唐诗/poet.song.135000.json','["夫子終年醉不醒，若爲問我故丁寧。", "書因遣僕馱黄檗，詩許登山斸茯苓。", "疇昔但知悲驥老，即今誰不羨鴻冥。", "清宵定許敲門否，擬問黄庭兩卷經。"]'),
('402510f7-71b8-4f3f-bf57-98ec5b2f2d66','短歌示諸稚','陸游','宋','宋诗','song-poetry','','[]','流年去不還，老狀來無那。',168,'全唐诗/poet.song.135000.json','["流年去不還，老狀來無那。", "雖甚顔原貧，尚勝夷齊餓。", "再歸又六年，疲馬欣解馱。", "姑幸箠轡空，敢復希豆莝。", "好山懶出遊，敗屋得偃卧。", "饑能儲粟盎，病亦有藥裹。", "酒蟻溢皤罌，茗雪落小䃺。", "香火失惰偷，編簡謹程課。", "豈惟洗幻妄，亦以起衰懦。", "向來名宦事，回首如棄唾。", "義理開諸孫，閔閔待其大。", "賢愚未易知，尚冀得一个。", "如其盡爲農，亦未可吊賀。", "歸耕豈不佳，努力求寡過。"]'),
('dfee6173-d4e7-432e-80c0-c5d2b2ca55f8','王子猷謂竹爲此君白樂天謂酒爲此君余野處無客每對竹獨酌得小詩','陸游','宋','宋诗','song-poetry','','[]','新種疏篁對小軒，旋沽薄酒實空尊。',32,'全唐诗/poet.song.135000.json','["新種疏篁對小軒，旋沽薄酒實空尊。", "門無車轍亦何恨，有此兩君堪與言。"]'),
('1a3a0893-92fe-4c2e-9998-2ad23c56aa20','會稽行','陸游','宋','宋诗','song-poetry','','[]','我欲遊蓬壺，安得身插羽。',192,'全唐诗/poet.song.135000.json','["我欲遊蓬壺，安得身插羽。", "我欲隠嵩華，嘆息非吾土。", "會稽多名山，開迹自往古。", "豈惟頌刻秦，乃有廟祀禹。", "山形舞鸞鳳，泉脈流湩乳。", "家家富水竹，處處生蘭杜。", "方舟泛曹娥，健席拂天姥。", "朱樓入烟霄，白塔臨雲雨。", "修梁看龍化，遺箭遣鶴取。", "茶荈可作經，楊梅亦著譜。", "湖蓴山蕨輩，一一難遽數。", "終年遊不厭，冰玉生肺腑。", "誦詩有樵童，乞字到俚嫗。", "况復青青衿，盛不減鄒魯。", "古詩三千篇，安知闕吳楚。", "土風聊補亡，吾言豈夸詡。"]'),
('5bd5a733-a53d-4755-9c0a-4232ae24da4a','野飲','陸游','宋','宋诗','song-poetry','','[]','春雨行路難，春寒客衣薄。',72,'全唐诗/poet.song.135000.json','["春雨行路難，春寒客衣薄。", "客衣薄尚可，泥深畏馿弱。", "溪橋有孤店，村酒亦可酌。", "鳬茈小甑炊，丹柿青篾絡。", "人生憂患窟，駭機日夜作。", "野飲君勿輕，名宦無此樂。"]'),
('6b8451eb-cd17-4612-9c5e-728e25582c19','作野飲詩後一日復作此篇反之','陸游','宋','宋诗','song-poetry','','[]','世事如海沙，巧曆不能數。',96,'全唐诗/poet.song.135000.json','["世事如海沙，巧曆不能數。", "身居憂患中，殆若墮阱虎。", "又如住敗屋，岌岌日撐拄。", "中夜風雨至，摧壓固其所。", "孰能知其然，徙義以爲主。", "要于一念間，不敢欺仰俯。", "兢兢日三省，寧可自莽鹵。", "君看昔先師，乃愧不若禹。"]'),
('ef8239d8-ae6f-4ed8-86f3-04b0e15b4354','春晴二首  其一','陸游','宋','宋诗','song-poetry','','[]','雨斷雲歸兩作晴，夕陽鼓角動高城。',64,'全唐诗/poet.song.135000.json','["雨斷雲歸兩作晴，夕陽鼓角動高城。", "客愁正得酒排去，草色直疑烟染成。", "鶑爲風和初命友，鷗緣水長欲尋盟。", "不須苦問春深淺，陌上吹簫已賣餳。"]'),
('d25333b0-9792-4988-a230-803cf2bb121c','春晴二首  其二','陸游','宋','宋诗','song-poetry','','[]','常年春日少春晴，拂面今朝暖吹輕。',64,'全唐诗/poet.song.135000.json','["常年春日少春晴，拂面今朝暖吹輕。", "水閣家家橫小舫，園亭處處聽新鶑。", "桃花不管詩人老，菖葉空催野叟耕。", "自笑此生餘幾許，銅駝荆棘尚關情。"]'),
('bfb380c4-a559-495e-8b1d-a0f54d42402f','遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','莫笑龜堂礌磈胸，此中元可貯虛空。',64,'全唐诗/poet.song.135000.json','["莫笑龜堂礌磈胸，此中元可貯虛空。", "尚饒靈運先成佛，那計辛毗不作公。", "采藥偶逢丹井客，買蓑因過玉霄翁。", "不須更問歸何許，散髮飄然萬里風。"]'),
('82060d4b-cef5-42ee-b1c9-d18247d0e461','遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','我是仙蓬舊主人，一生常得自由身。',64,'全唐诗/poet.song.135000.json','["我是仙蓬舊主人，一生常得自由身。", "退歸自合稱山長，變化猶應侍帝晨。", "得酒不妨開口笑，學人難作捧心顰。", "塵中且復隨緣住，又見湖邊草木新。"]'),
('a7bf51e5-2a82-45a9-b973-b8f128eb625d','開歲屢作雨不成正月二十六日夜乃得雨明日行家圃有賦','陸游','宋','宋诗','song-poetry','','[]','東風催雨破天慳，行圃歸來剩解顔。',64,'全唐诗/poet.song.135000.json','["東風催雨破天慳，行圃歸來剩解顔。", "百草吹香蝴蝶閙，一溪漲綠鷺鷥閑。", "老來每嘆論心少，貧甚方知覓醉艱。", "猶頼籃輿無恙在，呼兒結束入南山。"]'),
('2d171bf6-74a2-49a9-a62a-16110156ce99','書屋壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','築室鏡湖濱，于今四十春。',48,'全唐诗/poet.song.135000.json','["築室鏡湖濱，于今四十春。", "放生魚自樂，施食鳥常馴。", "土潤觀鋤藥，燈清論養真。", "桃源處處有，不獨武陵人。"]'),
('cbaffeb4-c4f8-42dc-9efd-d1cd9b6344f3','書屋壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','鳥道經行穩，巢居卧起寬。',48,'全唐诗/poet.song.135000.json','["鳥道經行穩，巢居卧起寬。", "鹿衣裁短褐，龜屋製危冠。", "舊慕嵇中散，今師靖長官。", "蛟龍雲雨上，未必勝泥蟠。"]'),
('6473d541-8da9-4d37-a086-d40f5d301bfa','與兒孫同舟泛湖至西山旁憩酒家遂詠任氏茅庵而歸','陸游','宋','宋诗','song-poetry','','[]','過埭維舟古柳根，却扶拄杖入烟村。',64,'全唐诗/poet.song.135000.json','["過埭維舟古柳根，却扶拄杖入烟村。", "印泥接迹牛羊過，投宿爭林鳥雀喧。", "酒保殷勤邀瀹茗，道翁傴僂出迎門。", "郊居不與人間事，惟有耕桑得細論。"]'),
('eb5b7727-ddea-4aa0-a41f-a921f07cf3fc','日暮自大匯村歸','陸游','宋','宋诗','song-poetry','','[]','筍輿伊軋暮山昏，水敗陂塘路僅存。',64,'全唐诗/poet.song.135000.json','["筍輿伊軋暮山昏，水敗陂塘路僅存。", "出谷鐘聲知過寺，隔林人語喜逢村。", "廟壖荒寂新犁地，堤草凄迷舊燒痕。", "兒子念翁霜露冷，遥持炬火出柴門。"]'),
('01036ccf-f1d9-43f5-be16-ded9b33f4982','八十四吟','陸游','宋','宋诗','song-poetry','','[]','八十仍逾四，遲留未告行。',48,'全唐诗/poet.song.135000.json','["八十仍逾四，遲留未告行。", "筮言災退散，醫賀脈和平。", "耕牧猶能力，癡頑每自驚。", "所嗟經學廢，心愧濟南生。"]'),
('3bd5c3d0-8c74-4554-bf39-10a11946f41c','晚步至湖上','陸游','宋','宋诗','song-poetry','','[]','柴車無與駕，篷艇亦須人。',48,'全唐诗/poet.song.135000.json','["柴車無與駕，篷艇亦須人。", "頼有拄杖子，能扶羸病身。", "雲山翠屏合，烟月玉鈎新。", "蕭散湖塘路，微風吹葛巾。"]'),
('ad3a1d31-732b-4d5a-8251-f88d3d9bc07c','春陰','陸游','宋','宋诗','song-poetry','','[]','窗昏不見字，今日罷觀書。',48,'全唐诗/poet.song.135000.json','["窗昏不見字，今日罷觀書。", "迹寄浮生內，心遊曠劫初。", "太山均蟻垤，聖域亦蘧廬。", "兀坐還成倦，荒畦去荷鋤。"]'),
('ff59d230-2268-4fda-98ba-414184506e0b','題野店壁','陸游','宋','宋诗','song-poetry','','[]','斷稿投衣橐，殘壺挂馬鞍。',48,'全唐诗/poet.song.135000.json','["斷稿投衣橐，殘壺挂馬鞍。", "寺荒尋店久，橋敗涉溪寒。", "道里逢人問，題名拂壁看。", "平生慣行役，隨處得加餐。"]'),
('8c552033-621f-4e75-8594-ac2cff70e504','題寺壁','陸游','宋','宋诗','song-poetry','','[]','庵居渾似罷參僧，除却癡憨百不能。',64,'全唐诗/poet.song.135000.json','["庵居渾似罷參僧，除却癡憨百不能。", "意倦有時憑曲几，興來隨處曳枯藤。", "雲山直去寧須伴，蘚磴高攀不計層。", "聞道鼉鳴天欲雨，松門小住看雲興。"]'),
('e8d75667-60cb-4c1c-aab0-0fa39e2fa1f8','題幽居壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','青山四抱路盤紆，天與先生卜草廬。',64,'全唐诗/poet.song.135000.json','["青山四抱路盤紆，天與先生卜草廬。", "雲冷數聲聞斷雁，溪清百尺見遊魚。", "新醪薄薄閑尋醉，殘髮蕭蕭悶憶梳。", "莫謂躬耕便無事，百年京洛尚丘墟。"]'),
('37b3feaa-bdf1-4ec1-a466-55ec0126e7ec','題幽居壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','聲利場中偶解圍，悠然高枕謝招揮。',64,'全唐诗/poet.song.135000.json','["聲利場中偶解圍，悠然高枕謝招揮。", "山前曳杖尋僧去，林下收棋送客歸。", "城市氛埃那許到，比鄰烟火自相依。", "纓冠束带前身事，散髮今惟勃落衣。"]'),
('4041f93c-5bbf-4b12-ad72-ec2008321f3b','思夔州二首  其一','陸游','宋','宋诗','song-poetry','','[]','老來百念盡消磨，無奈雲安入夢何。',32,'全唐诗/poet.song.135000.json','["老來百念盡消磨，無奈雲安入夢何。", "壯憶公孫劍器舞，愁思賓客竹枝歌。"]'),
('473a5faa-b7de-4c73-97e4-eb06faac10b7','思夔州二首  其二','陸游','宋','宋诗','song-poetry','','[]','武侯八陣孫吳法，工部十詩韶頀音。',32,'全唐诗/poet.song.135000.json','["武侯八陣孫吳法，工部十詩韶頀音。", "遺磧故祠春草合，略無人解兩公心。"]'),
('6b66fbea-c05e-4716-ae1c-a6cd7b35365d','梅開絕晚有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','年年踏雪探梅開，二月今年始見梅。',32,'全唐诗/poet.song.135000.json','["年年踏雪探梅開，二月今年始見梅。", "從此逢春心轉懶，小詩不擬覓花裁。"]'),
('a6b7be9e-7397-4b41-8fbc-762e5136ec75','梅開絕晚有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','尋梅不負雪中期，醉倒猶須插一枝。',32,'全唐诗/poet.song.135000.json','["尋梅不負雪中期，醉倒猶須插一枝。", "莫諱衰遲殺風景，卷中今歲欠梅詩。"]'),
('2cfd7cd2-e076-4ee6-ad65-8d8b6d2335bc','園中晚飯示兒子','陸游','宋','宋诗','song-poetry','','[]','一飽何心慕萬鍾，小園父子自相從。',64,'全唐诗/poet.song.135000.json','["一飽何心慕萬鍾，小園父子自相從。", "蚍蜉布陣雨將作，蛺蝶成團春已濃。", "澗底束薪供晚爨，街頭糴米續晨舂。", "盤餐莫恨無兼味，自繞荒畦摘芥菘。"]'),
('5a6ae97d-510e-414e-b582-a53816f98134','自詰','陸游','宋','宋诗','song-poetry','','[]','修行力量淺，觸事常寡悰。',96,'全唐诗/poet.song.135000.json','["修行力量淺，觸事常寡悰。", "端居本無事，奈此百憂攻。", "今晨默自語，世豈不汝容。", "漱濯臨清流，嘯歌蔭長松。", "緩步有夷途，遠眺多奇峰。", "野叟時相尋，村酒亦自醲。", "于道忽少進，一掃芥蒂胸。", "轑釜本常情，寧說飯後鐘。"]'),
('079fc6a4-7a56-4900-a629-d6461ed51dde','野飲','陸游','宋','宋诗','song-poetry','','[]','農事未興思一笑，春薺可采魚可釣。',96,'全唐诗/poet.song.135000.json','["農事未興思一笑，春薺可采魚可釣。", "霏霏小雨忽已晴，堤上相携踏殘照。", "村場酒薄亦有力，把盞相娛不辭釂。", "眼花耳熱言語多，霍然已醒如過燒。", "人生百年會有盡，世事萬變誰能料。", "酒空人散寂無聲，爲君試作蘇門嘯。"]'),
('864cb21e-e30e-4d9a-8eb5-05900b260554','茆亭','陸游','宋','宋诗','song-poetry','','[]','讀罷楞伽四卷經，其餘終日坐茆亭。',64,'全唐诗/poet.song.135000.json','["讀罷楞伽四卷經，其餘終日坐茆亭。", "靜聽溪碓舂雲母，細斸松根采茯苓。", "大道粗嘗聞海若，高情未至愧山靈。", "寒泉新渫甘于乳，晨起何妨挈半瓶。"]'),
('496c1c1d-0f74-4afe-a192-ed87ff50a115','身世','陸游','宋','宋诗','song-poetry','','[]','身世飄然似斷雲，時人誤許與斯文。',64,'全唐诗/poet.song.135000.json','["身世飄然似斷雲，時人誤許與斯文。", "旋償碑債動千里，强理詩情無一分。", "子美舊悲殘酒炙，幼安今老白襦裙。", "餘生自喜渾無事，清夜銅爐炷寶熏。"]'),
('c47c08cb-6d57-44fd-8c5c-7d8b0d3f28f0','家有兩瓢分貯酒藥出則使一童負之戲賦五字句','陸游','宋','宋诗','song-poetry','','[]','長物消磨盡，猶存兩大瓢。',48,'全唐诗/poet.song.135000.json','["長物消磨盡，猶存兩大瓢。", "藥能扶困憊，酒可沃枯焦。", "童負來山店，人看度野橋。", "畫工殊好事，傳寫入生綃。"]'),
('d1e8bff6-8910-4661-be48-1a5b616ffbec','禹寺','陸游','宋','宋诗','song-poetry','','[]','禹寺荒殘鐘鼓在，我來又見物華新。',32,'全唐诗/poet.song.135000.json','["禹寺荒殘鐘鼓在，我來又見物華新。", "紹興年上曾題壁，觀者多疑是古人。"]'),
('016d6f2a-d88e-49d5-898f-e08869463b56','旅遊二首  其一','陸游','宋','宋诗','song-poetry','','[]','壯志蹉跎雪滿頭，久將餘日付滄洲。',64,'全唐诗/poet.song.135000.json','["壯志蹉跎雪滿頭，久將餘日付滄洲。", "閑雲不入老人夢，鄰笛似知孤客愁。", "小築聊須傍蘭渚，片帆那復到樟樓。", "生涯草草真堪笑，三十年來一破裘。"]'),
('1fa2a049-30db-4281-b3bd-74270e977d30','旅遊二首  其二','陸游','宋','宋诗','song-poetry','','[]','本自無心落市朝，不妨隨處狎漁樵。',64,'全唐诗/poet.song.135000.json','["本自無心落市朝，不妨隨處狎漁樵。", "螺青點出暮山色，石綠染成春浦潮。", "縣驛下時人語閙，寺樓倚處客魂消。", "流年不貸君知否，素扇團團又可搖。"]'),
('5cb8e782-6079-4c13-a8e9-c4541bb71bc2','貧嘆','陸游','宋','宋诗','song-poetry','','[]','貧到今年極，蕭然四壁家。',48,'全唐诗/poet.song.135000.json','["貧到今年極，蕭然四壁家。", "弊袍生蟣虱，粗飯雜泥沙。", "浩浩乾坤大，茫茫歲月賒。", "故鄉烟水窟，別擬卜生涯。"]'),
('05ac6696-8281-486f-a179-96c862fc8ade','東窗四首  其一','陸游','宋','宋诗','song-poetry','','[]','九折危途寸步艱，至今回首尚心寒。',32,'全唐诗/poet.song.135000.json','["九折危途寸步艱，至今回首尚心寒。", "元來自有安身處，茆屋三間似海寬。"]'),
('ee56f272-4a3a-4eda-8085-810ab0d019a5','東窗四首  其二','陸游','宋','宋诗','song-poetry','','[]','才薄常爲世俗輕，還山力不給躬耕。',32,'全唐诗/poet.song.135000.json','["才薄常爲世俗輕，還山力不給躬耕。", "即今贏得都無事，袖手東窗聽雨聲。"]'),
('f1b18c1e-2d1e-4c5b-8337-9711d0f32092','東窗四首  其三','陸游','宋','宋诗','song-poetry','','[]','俗事紛紛意不攄，兀如頭垢念爬梳。',32,'全唐诗/poet.song.135000.json','["俗事紛紛意不攄，兀如頭垢念爬梳。", "東窗且復焚香坐，閑看微雲自卷舒。"]'),
('815a7a8b-6d96-4c2f-b6b2-68b5a4d78b5c','東窗四首  其四','陸游','宋','宋诗','song-poetry','','[]','寂寂東窗午夢殘，更堪春雨作春寒。',32,'全唐诗/poet.song.135000.json','["寂寂東窗午夢殘，更堪春雨作春寒。", "蠻童未報煎茶熟，一卷南華枕上看。"]'),
('7cbda486-247b-43e0-b026-af6525a31607','近村','陸游','宋','宋诗','song-poetry','','[]','家居每思出，出亦無與遊。',120,'全唐诗/poet.song.135000.json','["家居每思出，出亦無與遊。", "江山豈不佳，乃復生我愁。", "不如適近村，家家業農疇。", "深巷鳴鷄犬，長陂下羊牛。", "棗熟稻當穫，桑落酒可篘。", "寧無賓祭須，柿栗良易求。", "醫翁日過門，得藥疾自瘳。", "婚嫁不出村，百世加綢繆。", "我來每絕嘆，恨不終歲留。", "人生正應爾，底事須王侯。"]'),
('3260cac2-b604-49b2-b688-ba782dbf1a7d','石帆山下作','陸游','宋','宋诗','song-poetry','','[]','石帆山下古苔磯，回首人間萬事非。',64,'全唐诗/poet.song.135000.json','["石帆山下古苔磯，回首人間萬事非。", "能飲上池何患死，不營尺宅欲安歸。", "寒龜瑟縮搘床老，倦鶴翩躚带箭飛。", "堪笑年來殊省事，就憑樵女綻春衣。"]'),
('ed27187a-2784-4f63-b6a7-266a75b7bd74','旦起二首  其一','陸游','宋','宋诗','song-poetry','','[]','殘燈冷火待窗明，稍覺今朝病體輕。',32,'全唐诗/poet.song.135000.json','["殘燈冷火待窗明，稍覺今朝病體輕。", "已頼林鳩知宿雨，更煩簷鵲報新晴。"]'),
('2e0d45e8-47b5-41d2-a264-3e0798adcfb8','旦起二首  其二','陸游','宋','宋诗','song-poetry','','[]','地爐晨起撥寒灰，困睫濛濛尚懶開。',32,'全唐诗/poet.song.135000.json','["地爐晨起撥寒灰，困睫濛濛尚懶開。", "正倚蒲團覓殘夢，一聲啼鳥又驚回。"]'),
('54c6be03-bb7a-4426-934a-62a5d973dc0d','書况','陸游','宋','宋诗','song-poetry','','[]','自從請老鏡湖濱，萬事不關林下人。',64,'全唐诗/poet.song.135000.json','["自從請老鏡湖濱，萬事不關林下人。", "鴉去鴉歸還過日，花開花落又經春。", "官微也過千重浪，身在依然一幅巾。", "晨突有烟吾事了，濁醪不復惱比鄰。"]'),
('7e54da04-b7e3-4145-acbe-dc97912114e2','閑中戲賦村落景物二首  其一','陸游','宋','宋诗','song-poetry','','[]','遊宦才能薄，還山日月長。',96,'全唐诗/poet.song.135000.json','["遊宦才能薄，還山日月長。", "買牛捐寶劍，取酒解金章。", "泉脈疏供啜，松肪煉按方。", "北窗貪兀傲，南陌喜彷徉。", "僧過傳蓍法，醫來寄藥囊。", "泛舟經姥廟，策蹇上傖塘。", "懶似嵇中散，癡如顧長康。", "人間須掃迹，隨處是羊腸。"]'),
('7a51e59b-4c99-4b06-aed9-cc83c01665a4','閑中戲賦村落景物二首  其二','陸游','宋','宋诗','song-poetry','','[]','覆篠初成屋，編荆旋作門。',96,'全唐诗/poet.song.135000.json','["覆篠初成屋，編荆旋作門。", "孤雲生釣瀨，微雨過棋軒。", "柳種來傍縣，花栽乞近村。", "石欹聊可坐，地褊不成園。", "酒榼刳楓癭，香爐斷竹根。", "海鷗呼可下，隴鳥教能言。", "摶飯迎雙鶴，聯縚繫小猿。", "山家雖寂寞，隨事有盤餐。"]'),
('db70902f-7344-4eea-a5cb-d941207f2568','予好把酒常以小戶爲苦戲述','陸游','宋','宋诗','song-poetry','','[]','我非惡旨酒，好飲而不能。',96,'全唐诗/poet.song.135000.json','["我非惡旨酒，好飲而不能。", "方其臨觴時，直欲舉斗升。", "若有物制之，合龠已不勝。", "豈獨觀者笑，心亦甚自憎。", "正如疾逆虜，憤切常橫膺。", "蹭蹬忽衰老，何由效先登。", "上天無長梯，繫日無長繩。", "可嘆固非一，壯志空飛騰。"]'),
('4518db36-239a-4396-b4a6-15d11c8c7ddc','春日對花有感','陸游','宋','宋诗','song-poetry','','[]','夭夭枝頭花，鬰鬰地上草。',96,'全唐诗/poet.song.135000.json','["夭夭枝頭花，鬰鬰地上草。", "方春萬物遂，我乃獨衰槁。", "少時喜方藥，晚亦學黄老。", "又非愛名宦，壯歲迹已掃。", "如何過八十，尚復未聞道。", "傴行阡陌間，齒搖而髮縞。", "名山可巢居，决去恨不早。", "宴坐精思床，猶能養梨棗。"]'),
('faa20cac-a1e3-4a45-9060-d9f9e69565ee','出遊遇雨而返二首  其一','陸游','宋','宋诗','song-poetry','','[]','柴門方出雨霏霏，未到湖邊促駕歸。',32,'全唐诗/poet.song.135000.json','["柴門方出雨霏霏，未到湖邊促駕歸。", "深炷爐香掩屏卧，誰知不爲溼春衣。"]'),
('bf6acd0b-5940-40ab-8268-baf82576ce24','出遊遇雨而返二首  其二','陸游','宋','宋诗','song-poetry','','[]','荒山前頭野水邊，東行西行不自憐。',32,'全唐诗/poet.song.135000.json','["荒山前頭野水邊，東行西行不自憐。", "天公豈亦哀老子，風雨留教終日眠。"]'),
('dc993253-3299-4fef-81c4-a9145f9a26fd','記閑','陸游','宋','宋诗','song-poetry','','[]','白雲堆裏看青山，猿鳥爲鄰日往還。',32,'全唐诗/poet.song.135000.json','["白雲堆裏看青山，猿鳥爲鄰日往還。", "黄綺後身應我是，再來依舊一生閑。"]'),
('507baa30-cbdd-424c-b0c8-8383637bb326','二感','陸游','宋','宋诗','song-poetry','','[]','狸奴睡被中，鼠橫若不聞。',72,'全唐诗/poet.song.135000.json','["狸奴睡被中，鼠橫若不聞。", "殘我架上書，禍乃及斯文。", "乾鵲下屋簷，鳴噪不待晨。", "但爲得食計，何曾問行人。", "惰得暖而安，饑得飽而馴。", "汝計則善矣，我憂難具陳。"]'),
('b4d4e8f9-859e-4fd9-b3e5-24aec3c427b5','題柴言山水四首  其一','陸游','宋','宋诗','song-poetry','','[]','陰陰山木合，幽處著柴荆。',24,'全唐诗/poet.song.135000.json','["陰陰山木合，幽處著柴荆。", "喧中有靜意，水車終日鳴。"]'),
('4d1ee30e-365c-427e-a38e-bded44db2d1c','題柴言山水四首  其二','陸游','宋','宋诗','song-poetry','','[]','懸水三十仞，疾雷聞數里。',24,'全唐诗/poet.song.135000.json','["懸水三十仞，疾雷聞數里。", "正暑凜生秋，倚杖者誰子。"]'),
('4f0805f8-d4e1-461b-b368-7fe32f83547d','題柴言山水四首  其三','陸游','宋','宋诗','song-poetry','','[]','高秋風雨天，幽居詩酒地。',24,'全唐诗/poet.song.135000.json','["高秋風雨天，幽居詩酒地。", "君看此氣象，其可折簡致。"]'),
('25562eec-bbeb-4964-924d-336016799f0c','題柴言山水四首  其四','陸游','宋','宋诗','song-poetry','','[]','草亭臨峭絕，霜嶂起嶙峋。',24,'全唐诗/poet.song.135000.json','["草亭臨峭絕，霜嶂起嶙峋。", "危磴儻可上，老夫思卜鄰。"]'),
('03f3ac2a-1f8f-43eb-9572-5f17c9ec3998','草亭獨坐','陸游','宋','宋诗','song-poetry','','[]','掃地垂簾坐草亭，東風吹頰醉初醒。',64,'全唐诗/poet.song.135000.json','["掃地垂簾坐草亭，東風吹頰醉初醒。", "睡蛇死後魔無力，疾豎降來藥有靈。", "在手殘梅香淡泊，傍簷幽鳥語丁寧。", "老人不是神通妙，世事元來要飽經。"]'),
('4a9f2b71-a2a0-4053-9d32-f7340eeec704','修居室賦詩自警','陸游','宋','宋诗','song-poetry','','[]','荒園二三畝，敗屋八九間。',144,'全唐诗/poet.song.135000.json','["荒園二三畝，敗屋八九間。", "初至如逆旅，忽逾四十年。", "屋日已朽蠹，我老不自還。", "茅可刈之野，木可伐之山。", "尚復不能具，日夜憂其顛。", "况我虛幻身，念念隨化遷。", "齒墮髮亦縞，鏡中失朱顔。", "其危甚于屋，何恃能牢堅。", "豐汝梨與棗，養汝汞與鉛。", "防疾如待敵，愛氣如守關。", "謀于履霜初，懼在橫流前。", "書紳銘席端，雖老尚可全。"]'),
('3049e93c-7d9e-4f11-b886-e812149de274','遯迹','陸游','宋','宋诗','song-poetry','','[]','遯迹荒村慣忍貧，秋毫不使喪其真。',64,'全唐诗/poet.song.135000.json','["遯迹荒村慣忍貧，秋毫不使喪其真。", "家居亦以古爲鑒，事過始知天勝人。", "臨食致思方下箸，讀書有得每書紳。", "放翁耄矣當知幸，布褐藜羹畢此身。"]'),
('46acd639-9850-4713-aa64-ec8034ca0856','春晴登小臺','陸游','宋','宋诗','song-poetry','','[]','不管筇枝破綠苔，閑穿萬竹上荒臺。',64,'全唐诗/poet.song.135000.json','["不管筇枝破綠苔，閑穿萬竹上荒臺。", "幽花經雨自開落，啼鳥喜晴時去來。", "河岸家家裝彩舫，兒曹處處唱青梅。", "誰家老子癡頑甚，看改新元十一回。"]'),
('d64b7b70-acf3-4f55-845c-d3f18835edae','魯墟舟中作','陸游','宋','宋诗','song-poetry','','[]','春浦南來元不到，畫橈偶復入鷗群。',64,'全唐诗/poet.song.135000.json','["春浦南來元不到，畫橈偶復入鷗群。", "人家遠火林間見，船底微波枕上聞。", "山口正銜初出月，渡頭未散欲歸雲。", "錦囊詩草新寥落，得句猶堪寄一欣。"]'),
('2d30f489-ac86-4057-916b-0644c5d985e7','貧病戲書二首  其一','陸游','宋','宋诗','song-poetry','','[]','得米還憂無束薪，今年真欲甑生塵。',32,'全唐诗/poet.song.135000.json','["得米還憂無束薪，今年真欲甑生塵。", "椎奴跣婢皆辭去，始覺盧仝未苦貧。"]'),
('e47cb8f0-1f94-461b-bce0-7e2e72d75068','貧病戲書二首  其二','陸游','宋','宋诗','song-poetry','','[]','頭痛涔涔齒動搖，醫驕折簡不能招。',32,'全唐诗/poet.song.135000.json','["頭痛涔涔齒動搖，醫驕折簡不能招。", "亦知客疾無根柢，少健還能起負樵。"]'),
('ae430ff4-efc8-4ca5-94a2-66004ad330f1','又作二首自解  其一','陸游','宋','宋诗','song-poetry','','[]','盡日溪邊艇子斜，治生不種邵平瓜。',32,'全唐诗/poet.song.135000.json','["盡日溪邊艇子斜，治生不種邵平瓜。", "已分鄰舍紅蓮米，更啜僧房紫筍茶。"]'),
('f8f019d0-167a-4971-bbfa-0f97786fc092','又作二首自解  其二','陸游','宋','宋诗','song-poetry','','[]','靈府安平四體和，經時止酒頰常酡。',32,'全唐诗/poet.song.135000.json','["靈府安平四體和，經時止酒頰常酡。", "老生要是常談爾，吐納餘閑即按摩。"]'),
('1362a9a3-1863-4635-9e9f-76975a7611e9','挾書一卷至湖上戲作','陸游','宋','宋诗','song-poetry','','[]','買地孤村結草廬，蕭然身世落樵漁。',32,'全唐诗/poet.song.135000.json','["買地孤村結草廬，蕭然身世落樵漁。", "一編在手君無怪，曾典蓬山四庫書。"]'),
('9a85f05b-6be0-4b53-9ff7-c6519c330946','謝客相過','陸游','宋','宋诗','song-poetry','','[]','我力日愈衰，人事不敢倡。',48,'全唐诗/poet.song.135000.json','["我力日愈衰，人事不敢倡。", "窮巷春多泥，何以稅客鞅。", "諸君顧何取，勤懇問亡恙。", "賦詩代尺書，跂望徒悢悢。"]'),
('0f961f65-2b68-4b83-a637-2d731d5e7a73','書幸','陸游','宋','宋诗','song-poetry','','[]','土盎常餘菜，山庖不絕烟。',48,'全唐诗/poet.song.135000.json','["土盎常餘菜，山庖不絕烟。", "罷醫翻少疾，無術自長年。", "小舫烟波宅，閑身陸地仙。", "東窗最佳處，日對坐忘編。"]'),
('18f8ae73-d9f1-4dc4-84d3-2d97735d0bcc','書嘆','陸游','宋','宋诗','song-poetry','','[]','髧髦承學紹興前，歷看人間七十年。',64,'全唐诗/poet.song.135000.json','["髧髦承學紹興前，歷看人間七十年。", "撲滿終歸棄道側，鴟夷猶得載車邊。", "釣船夜泛吳江月，醉眼秋看楚澤天。", "造物未容書鬼錄，殘春又藉落花眠。"]'),
('66997ebc-ef0d-4b49-a609-503e2cb41d84','古興二首  其一','陸游','宋','宋诗','song-poetry','','[]','草衰何預人，每起徂年悲。',60,'全唐诗/poet.song.135000.json','["草衰何預人，每起徂年悲。", "日月纔幾何，又見青青時。", "青青雖滿眼，行矣當復衰。", "盛衰還無端，其理可前知。", "人生死則已，千載無還期。"]'),
('e9d428dd-cdd0-48fd-bcb4-c6eb5013896c','古興二首  其二','陸游','宋','宋诗','song-poetry','','[]','月出橫林上，宿鳥無定枝。',60,'全唐诗/poet.song.135000.json','["月出橫林上，宿鳥無定枝。", "物生各畏禍，所託輒蹈危。", "老人倚壁坐，大鼾驚群兒。", "雖云差自適，見事亦太遲。", "猶有一可喜，永謝世俗羈。"]'),
('4ffab3c3-f3dd-4b82-9d89-c8f78d3791d8','病中有述二首  其一','陸游','宋','宋诗','song-poetry','','[]','萬事有常理，中智皆能知。',60,'全唐诗/poet.song.135000.json','["萬事有常理，中智皆能知。", "禍福如白黑，不待諏蓍龜。", "疾患初萌芽，未有旦夕危。", "每能自省察，百鬼安能窺。", "一怠生百疾，速死乃自詒。"]'),
('a39736b0-2265-4144-997f-1a117848f679','病中有述二首  其二','陸游','宋','宋诗','song-poetry','','[]','爲國恃久安，變起最莫測。',60,'全唐诗/poet.song.135000.json','["爲國恃久安，變起最莫測。", "釋楚爲外懼，此實計之得。", "吾儕學養生，事事當自克。", "老無聲色娛，戒懼在飲食。", "要須銘盤盂，下箸如對敵。"]'),
('75d39ab2-b280-4521-ba19-c7a580f8eec0','黄鴉吟','陸游','宋','宋诗','song-poetry','','[]','嗟哉黄鴉一何陋，性喜隠翳藏荒囿。',131,'全唐诗/poet.song.135000.json','["嗟哉黄鴉一何陋，性喜隠翳藏荒囿。", "烟深翅重飛不起，鳴聲穀穀知雨候。", "夜與妖鵩群，又似惡白晝。", "羽毛不足辱彈射，滋味不足登俎豆。", "捕之既無用，鬻之又不售。", "譬之人以支離而全，木以擁腫而壽。", "若予者智不能知農圃，學不能舉孝秀。", "名不譁世，動得嘲詬。", "是亦天下不材之尤，尚何議乎汝後。"]'),
('5b90c1d0-b0ce-4f1e-8391-2061a7393826','恩封渭南伯唐詩人趙嘏爲渭南尉當時謂之趙渭南後來將以予爲陸渭南乎戲作長句','陸游','宋','宋诗','song-poetry','','[]','老向人間久倦遊，君恩乞與渭川秋。',64,'全唐诗/poet.song.135000.json','["老向人間久倦遊，君恩乞與渭川秋。", "虛名定作陳驚坐，好句真慚趙倚樓。", "棧豆十年霑病馬，烟波萬里著浮鷗。", "就封他日輕裘去，應過三峰處處留。"]'),
('299ca85c-2f4b-4612-ae62-484e4eb6f37c','幽居','陸游','宋','宋诗','song-poetry','','[]','宿志在人外，清心游物初。',48,'全唐诗/poet.song.135000.json','["宿志在人外，清心游物初。", "猶輕天上福，那習世間書。", "薺菜挑供餠，槐芽采作葅。", "朝晡兩摩腹，未可笑幽居。"]'),
('6078eb94-3fcf-4621-8ff5-d07a7f25e4d8','肩輿至湖桑埭','陸游','宋','宋诗','song-poetry','','[]','籃輿隨意出衡門，日已沉山野未昏。',64,'全唐诗/poet.song.135000.json','["籃輿隨意出衡門，日已沉山野未昏。", "小市叢祠湖上路，短垣高柳埭西村。", "麥苗極目無閑土，塘水平堤失舊痕。", "明詔裕民聞屢下，老農何以報君恩。"]'),
('6e6f4ff3-1af5-4418-8f11-5ed3b2536eec','半俸自戊辰二月置不復言作絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','力請還山又幾年，何功月費水衡錢。',32,'全唐诗/poet.song.135000.json','["力請還山又幾年，何功月費水衡錢。", "君恩深厚猶慚懼，敢向他人更乞憐。"]'),
('add94ae1-530b-44a3-bbfe-de782c8dbd82','半俸自戊辰二月置不復言作絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','俸券新同廢紙收，迎賓僅有一絁裘。',32,'全唐诗/poet.song.135000.json','["俸券新同廢紙收，迎賓僅有一絁裘。", "日鋤幽圃君無笑，猶騰牆東學儈牛。"]'),
('a296cbc9-39da-4503-bbe2-819137447146','頭風戲作','陸游','宋','宋诗','song-poetry','','[]','出門處處皆桃李，我獨呻吟一室中。',32,'全唐诗/poet.song.135000.json','["出門處處皆桃李，我獨呻吟一室中。", "只道有詩驅瘧鬼，誰知無檄愈頭風。"]'),
('b01a3094-3e86-4301-bf31-ea91ce091ef9','茅齋','陸游','宋','宋诗','song-poetry','','[]','茆齋雖絕小，老子策新勛。',48,'全唐诗/poet.song.135000.json','["茆齋雖絕小，老子策新勛。", "磑落霏霏雪，爐生裊裊雲。", "心將鷗共遠，巢與鶴中分。", "幾許人間事，吾廬寂不聞。"]'),
('65ee65f5-a3f8-4ea9-b067-c887edd45c25','耕桑','陸游','宋','宋诗','song-poetry','','[]','老病雖俱至，耕桑亦未遲。',48,'全唐诗/poet.song.135000.json','["老病雖俱至，耕桑亦未遲。", "兒童誇犢健，婦女閔蠶饑。", "月落梟鳴夜，燈殘鼠嚙時。", "但當尋熟睡，萬事不須思。"]'),
('6ae2a7e7-ad8e-4b12-a3e8-bf9e7eaa1b0e','春詠四首  其一','陸游','宋','宋诗','song-poetry','','[]','方舟衝破湖波綠，聯騎蹋殘花徑紅。',32,'全唐诗/poet.song.135000.json','["方舟衝破湖波綠，聯騎蹋殘花徑紅。", "七十年間人換盡，放翁依舊醉春風。"]'),
('f4600f5a-c02d-46c6-b792-6a96a313d940','春詠四首  其二','陸游','宋','宋诗','song-poetry','','[]','熟食從來少天色，東吳况是足春寒。',32,'全唐诗/poet.song.135000.json','["熟食從來少天色，東吳况是足春寒。", "城南藉草可痛飲，安得酒腸如海寬。"]'),
('49a0fd16-d6cb-471e-9af7-30b01f3e2366','春詠四首  其三','陸游','宋','宋诗','song-poetry','','[]','蘭亭路上換春衣，梅市橋邊送夕暉。',32,'全唐诗/poet.song.135000.json','["蘭亭路上換春衣，梅市橋邊送夕暉。", "聞有水仙翁是否，輕舟如葉槳如飛。"]'),
('0c2e7b5d-a227-43bf-8bca-e9de7d9019a1','春詠四首  其四','陸游','宋','宋诗','song-poetry','','[]','沈家園裏花如錦，半是當年識放翁。',32,'全唐诗/poet.song.135000.json','["沈家園裏花如錦，半是當年識放翁。", "也信美人終作土，不堪幽夢太匆匆。"]'),
('9ba16669-78c7-4686-9aa8-3f5745e7b504','蔬飯','陸游','宋','宋诗','song-poetry','','[]','春事已闌珊，山村未褪寒。',48,'全唐诗/poet.song.135000.json','["春事已闌珊，山村未褪寒。", "筍生初入饌，薺老尚登盤。", "僧飯時分鉢，園蔬不仰官。", "枯腸更禁攪，姑置密雲團。"]'),
('e9610bef-c6cf-4f6c-90b9-7e9124bc368a','海棠歌','陸游','宋','宋诗','song-poetry','','[]','我初入蜀鬢未霜，南充樊亭看海棠。',128,'全唐诗/poet.song.135000.json','["我初入蜀鬢未霜，南充樊亭看海棠。", "當時已謂目未睹，豈知更有碧鷄坊。", "碧鷄海棠天下絕，枝枝似染猩猩血。", "蜀姬艷粧肯讓人，花前頓覺無顔色。", "扁舟東下八千里，桃李真成僕奴爾。", "若使海棠根可移，揚州芍藥應羞死。", "風雨春殘杜鵑哭，夜夜寒衾夢還蜀。", "何從乞得不死方，更看千年未爲足。"]'),
('0f48969e-cc2f-4372-ae29-78793a80b6d2','園中作','陸游','宋','宋诗','song-poetry','','[]','湖曲舊誅茆，松陰近結巢。',48,'全唐诗/poet.song.135000.json','["湖曲舊誅茆，松陰近結巢。", "安閑多熟睡，衰退少新交。", "雨漬丁香結，春生豆蔻梢。", "良晨不把酒，新燕解相嘲。"]'),
('3a024685-46b8-4013-bd93-08eb802dccf4','書意三首  其一','陸游','宋','宋诗','song-poetry','','[]','整書拂几當閑嬉，時取曾孫竹馬騎。',32,'全唐诗/poet.song.135000.json','["整書拂几當閑嬉，時取曾孫竹馬騎。", "故故小勞君會否，戶樞流水即吾師。"]'),
('a37b3b89-09d6-4dfa-b4f1-61937041ff0a','書意三首  其二','陸游','宋','宋诗','song-poetry','','[]','人生祇要常無事，忿欲紛紛喜見侵。',32,'全唐诗/poet.song.135000.json','["人生祇要常無事，忿欲紛紛喜見侵。", "贈子秘傳安樂法，秋毫莫遣動吾心。"]'),
('5362f997-cbcf-48a1-aaa2-0eae0918f49e','書意三首  其三','陸游','宋','宋诗','song-poetry','','[]','籬角緋桃落漸稀，晚風吹去點苔磯。',32,'全唐诗/poet.song.135000.json','["籬角緋桃落漸稀，晚風吹去點苔磯。", "揮金豈必如疏傅，二畝春秧也是歸。"]'),
('d1046661-04e0-4db4-a4eb-9397b1a8857a','晚春二首  其一','陸游','宋','宋诗','song-poetry','','[]','世事紛紛不足論，流年去似海濤翻。',64,'全唐诗/poet.song.135000.json','["世事紛紛不足論，流年去似海濤翻。", "莫因齒髮悲殘景，且喜柴荆是故園。", "千里桑麻無曠土，數家鷄犬自成村。", "鄰翁過我誇秧信，雨後春泥一尺渾。"]'),
('bda40ac2-9fed-40cc-9ed0-cb42f5d69a5f','晚春二首  其二','陸游','宋','宋诗','song-poetry','','[]','莫笑花前醉墮巾，放翁又看一年春。',64,'全唐诗/poet.song.135000.json','["莫笑花前醉墮巾，放翁又看一年春。", "尋巢燕熟頻穿戶，釀蜜蜂喧不避人。", "楚廟恙豚初散社，稽山筍蕨正嘗新。", "要知不負年光處，南陌東阡自在身。"]'),
('537b667c-5dd3-4e57-b62d-87559e0d438e','湖上','陸游','宋','宋诗','song-poetry','','[]','綸巾羽扇影翩翩，湖上彷徉莫計年。',64,'全唐诗/poet.song.135000.json','["綸巾羽扇影翩翩，湖上彷徉莫計年。", "桃李已忘疇昔分，禽魚猶結後來緣。", "山前虛市初多筍，江外人家不禁烟。", "莫恨幽情無與共，一雙白鷺導吾前。"]'),
('d59865f1-4dc0-4178-83da-e91fa6aecde1','即事','陸游','宋','宋诗','song-poetry','','[]','成敗歸青史，悲歡付浩歌。',48,'全唐诗/poet.song.135000.json','["成敗歸青史，悲歡付浩歌。", "病從今歲減，詩比去春多。", "高枕觀浮世，持杯養太和。", "功名亦易爾，難負此漁蓑。"]'),
('306e2250-924b-4a98-9413-fa58fdd57b8a','東籬雜書四首  其一','陸游','宋','宋诗','song-poetry','','[]','芳草初侵路，青梅已破枝。',48,'全唐诗/poet.song.135000.json','["芳草初侵路，青梅已破枝。", "雨來鳩逐婦，日出雉求雌。", "莽莽江湖遠，悠悠歲月移。", "老人觀物化，隠几獨多時。"]'),
('e45162f3-cd36-4121-a597-ee84fef37dec','東籬雜書四首  其二','陸游','宋','宋诗','song-poetry','','[]','桃李成塵土，來禽始著花。',48,'全唐诗/poet.song.135000.json','["桃李成塵土，來禽始著花。", "病夫猶枕上，春事又天涯。", "巷陌鞦韆夢，簾櫳燕子家。", "野僧來問訊，强把半甌茶。"]'),
('1588d48a-4192-4c33-becf-4a83b9577d59','東籬雜書四首  其三','陸游','宋','宋诗','song-poetry','','[]','老厭人間事，閑知造物功。',48,'全唐诗/poet.song.135000.json','["老厭人間事，閑知造物功。", "草生三徑綠，花發一窗紅。", "幽境囂塵外，流年嘯傲中。", "所嗟儕輩盡，論舊只春風。"]'),
('9816b3a9-a089-4fcb-b39e-8343791e9549','東籬雜書四首  其四','陸游','宋','宋诗','song-poetry','','[]','身與春俱老，愁隨日漸長。',48,'全唐诗/poet.song.135000.json','["身與春俱老，愁隨日漸長。", "簾櫳聽語燕，澗谷擷幽芳。", "酒榼常從後，詩囊亦在傍。", "閑行無定處，隨意據胡床。"]'),
('05ca77ba-80d2-424d-853e-4cde41d7c80d','山行','陸游','宋','宋诗','song-poetry','','[]','山鳥啼孤戍，烟蕪入廢亭。',48,'全唐诗/poet.song.135000.json','["山鳥啼孤戍，烟蕪入廢亭。", "堤成陂水白，雨細稻秧青。", "草市少行旅，叢祠多乞靈。", "最憐投宿處，微火暮晶熒。"]'),
('090735c3-fb84-4b84-ac19-06e2eb86de0f','稻陂','陸游','宋','宋诗','song-poetry','','[]','白水滿稻陂，投種未三宿。',72,'全唐诗/poet.song.135000.json','["白水滿稻陂，投種未三宿。", "新秧出水面，已作纖纖綠。", "年來殘俸絕，所望在一熟。", "見之喜欲舞，不復憂半菽。", "想當西成時，載重壓車軸。", "病齒幸已牢，往矣分社肉。"]'),
('63dc4985-8a8c-42d3-b140-06f2ddbc8480','雨夜思子虛','陸游','宋','宋诗','song-poetry','','[]','兀兀過遥夜，悠悠擁破衾。',48,'全唐诗/poet.song.135000.json','["兀兀過遥夜，悠悠擁破衾。", "峭寒侵病骨，殘雨滴愁心。", "人別易千里，書來真萬金。", "醉眠差似可，誰與伴孤斟。"]'),
('a599be2a-37cf-4dc4-aae2-2783a0031ea8','醉中示客','陸游','宋','宋诗','song-poetry','','[]','四座無譁聽我歌，百年生計一烟蓑。',64,'全唐诗/poet.song.135000.json','["四座無譁聽我歌，百年生計一烟蓑。", "清尊瀲瀲猶狂在，白髮蕭蕭奈老何。", "遠適安能縮地脈，高眠聊足養天和。", "吾徒看盡人間事，莫愛車前印幾窠。"]'),
('e3867c48-9b2d-4e49-8086-eff8a6d8b5d9','散髮','陸游','宋','宋诗','song-poetry','','[]','散髮垂肩懶更簪，一窗竹水對蕭森。',64,'全唐诗/poet.song.135000.json','["散髮垂肩懶更簪，一窗竹水對蕭森。", "從來耻作資身策，老去終懷報國心。", "雷起鼻端秋枕石，泉鳴指下夜橫琴。", "不緣羸病愁迎客，經歲何人肯見臨。"]'),
('a0dbaaae-b74e-4e1f-8d11-0b7ec27dc08d','病中觀辛夷花','陸游','宋','宋诗','song-poetry','','[]','餘生垂九十，一病理一衰。',72,'全唐诗/poet.song.135000.json','["餘生垂九十，一病理一衰。", "旬月不自保，敢作期歲期。", "粲粲女郎花，忽滿庭前枝。", "繁華雖少減，高雅亦足奇。", "持杯酹花前，事亦未可知。", "明年儻未死，一笑當解頤。"]'),
('1d50fc8a-e3c9-4a1f-af51-054146f6254f','小艇','陸游','宋','宋诗','song-poetry','','[]','放翁小艇輕如葉，只載蓑衣不載家。',32,'全唐诗/poet.song.135000.json','["放翁小艇輕如葉，只載蓑衣不載家。", "清曉長歌何處去，武陵溪上看桃花。"]'),
('eb8e063a-59bd-49ba-a6f0-79de47920657','雜題四首  其一','陸游','宋','宋诗','song-poetry','','[]','賀公在朝雅吳語，莊舄仕楚猶越吟。',32,'全唐诗/poet.song.135000.json','["賀公在朝雅吳語，莊舄仕楚猶越吟。", "我幸歸休在閭巷，燈前感慨不須深。"]'),
('056af9e3-0b50-4cf1-9803-39a65c5f7089','雜題四首  其二','陸游','宋','宋诗','song-poetry','','[]','茆屋三間已太奢，柴乾米白喜無涯。',32,'全唐诗/poet.song.135000.json','["茆屋三間已太奢，柴乾米白喜無涯。", "非賢敢竊優賢祿，願折蓴絲與蕨芽。"]'),
('f38e5119-c9ff-4705-8045-3d12ac231269','雜題四首  其三','陸游','宋','宋诗','song-poetry','','[]','野花紅碧自爭春，村酒酸甜也醉人。',32,'全唐诗/poet.song.135000.json','["野花紅碧自爭春，村酒酸甜也醉人。", "解放船頭便千里，不愁無處著閑身。"]'),
('78039fca-9e95-498e-8879-b031ac1303f5','雜題四首  其四','陸游','宋','宋诗','song-poetry','','[]','湖堤疏瘦水楊柳，村舍殷紅山石榴。',32,'全唐诗/poet.song.135000.json','["湖堤疏瘦水楊柳，村舍殷紅山石榴。", "推戶本來隨意入，乞漿因得片時留。"]'),
('e4eeb1fd-5ab3-4a85-a64e-1f068ad5c8fb','閑遊','陸游','宋','宋诗','song-poetry','','[]','柴車去去度橫陂，正是春殘入夏時。',64,'全唐诗/poet.song.135000.json','["柴車去去度橫陂，正是春殘入夏時。", "果熟多藏新密葉，鶑啼偏占最高枝。", "迷途每就傭耕問，薄飯時從逆旅炊。", "隨意題詩無傑思，還家猶足詫吾兒。"]'),
('5e19c78f-7049-404d-8427-144c122b3c6c','病起初夏','陸游','宋','宋诗','song-poetry','','[]','頭風間作已全輕，山雨雖頻却快晴。',64,'全唐诗/poet.song.135000.json','["頭風間作已全輕，山雨雖頻却快晴。", "窗外時時度花片，林梢處處送鶑聲。", "地偏無客談閑事，麥熟逢人樂太平。", "不爲衰遲辜節物，一甌羊駱薦朱櫻。"]'),
('ea049bc7-e8ee-4964-abfe-b326e800adde','衡門獨立','陸游','宋','宋诗','song-poetry','','[]','春歸堪笑又匆匆，水白秧青細雨濛。',64,'全唐诗/poet.song.135000.json','["春歸堪笑又匆匆，水白秧青細雨濛。", "溪鳥低飛畫橋外，路人相值綠陰中。", "宋清藥券貧來積，李賀詩囊病後空。", "惟有劇談能一洗，芳尊那得故人同。"]'),
('f12fcd31-8847-427f-bfb7-fbed05a055cf','雨夜','陸游','宋','宋诗','song-poetry','','[]','吳中地多雨，海角客常愁。',48,'全唐诗/poet.song.135000.json','["吳中地多雨，海角客常愁。", "羸疾須醫藥，殘年憶輩流。", "解裝孤驛晚，捩柁小江秋。", "莫起瀟湘興，無才賦遠遊。"]'),
('0b189359-ff03-4d55-b8c9-f7e787934bb0','山麓','陸游','宋','宋诗','song-poetry','','[]','草合路如綫，偶隨樵子行。',24,'全唐诗/poet.song.135000.json','["草合路如綫，偶隨樵子行。", "林間遇磐石，少憩看春耕。"]'),
('0c01747e-9491-4fba-bda5-55acfafd19e1','北齋','陸游','宋','宋诗','song-poetry','','[]','質衣葺北齋，欹壞略撐拄。',72,'全唐诗/poet.song.135000.json','["質衣葺北齋，欹壞略撐拄。", "窗扉則虛名，聊足度寒暑。", "獨學無與論，推覈實勞苦。", "審觀古人意，十亦得四五。", "無功與子光，相可豈待語。", "一床寬有餘，高卧聽簷雨。"]'),
('5e7849ec-9096-405b-94c2-d2c38f8e5e2c','禽言四首  其一','陸游','宋','宋诗','song-poetry','','[]','架犁架犁，南村北村雨凄凄。',45,'全唐诗/poet.song.135000.json','["架犁架犁，南村北村雨凄凄。", "夜起飯牛鷄未啼，日暮矻矻行千畦。", "沒足勿恨一尺泥，西成收薄汝噬臍。"]'),
('0059164b-6a0a-4446-8bb5-9360fcedec97','禽言四首  其二','陸游','宋','宋诗','song-poetry','','[]','拔筍拔筍，入箐不辭風雨窘。',45,'全唐诗/poet.song.135000.json','["拔筍拔筍，入箐不辭風雨窘。", "養成會見高拂雲，取供口腹初不忍。", "獨持兩把慰倚門，慈顔一笑如春溫。"]'),
('1bdfa4aa-2f6d-4cb7-955b-71f5c9d32dcb','禽言四首  其三','陸游','宋','宋诗','song-poetry','','[]','老翁老尚健，打麥持作飯。',56,'全唐诗/poet.song.135000.json','["老翁老尚健，打麥持作飯。", "終歲隴畝間，勞苦孰敢怨。", "人生爲農最可願，得飽正如持左券。", "碓舂樵爨小甑香，豈不勝汝耗太倉。"]'),
('efc6cf4a-fa5f-4a06-92b0-08c822cb1edb','禽言四首  其四','陸游','宋','宋诗','song-poetry','','[]','堂前捉績子，力作忘朝餐。',60,'全唐诗/poet.song.135000.json','["堂前捉績子，力作忘朝餐。", "鵝黄雪白相照耀，插茅作簇高如山。", "蠢女採桑至煮繭，何暇膏沐梳髻鬟。", "繅成蜀錦與楚縠，舞妹纏頭不論束。"]'),
('59113237-3cbd-4952-ad8b-909d8a410966','道院偶述二首  其一','陸游','宋','宋诗','song-poetry','','[]','景德祥符草野臣，登封曾望屬車塵。',32,'全唐诗/poet.song.135000.json','["景德祥符草野臣，登封曾望屬車塵。", "已經成住壞空劫，猶是東西南北人。"]'),
('b65743a3-e037-4a5e-8f43-4960ba2686fe','道院偶述二首  其二','陸游','宋','宋诗','song-poetry','','[]','憶在青城煉大丹，丹成垂欲上仙班。',32,'全唐诗/poet.song.135000.json','["憶在青城煉大丹，丹成垂欲上仙班。", "飄零未忍塵中老，猶待時平隠華山。"]'),
('d3fc184b-e5d7-488a-9247-e6696e3fb27f','初夏書感','陸游','宋','宋诗','song-poetry','','[]','春與人俱老，花隨夢已空。',48,'全唐诗/poet.song.135000.json','["春與人俱老，花隨夢已空。", "遊蜂黏落蕊，輕燕接飛蟲。", "桑悴知蠶起，牲肥賽麥豐。", "爲農當自力，相戒勿匆匆。"]'),
('bb1afdda-2b49-40a7-ae8b-24a978708ff3','贈邢芻甫','陸游','宋','宋诗','song-poetry','','[]','割愁何處有并刀，傾座誰能奪錦袍。',64,'全唐诗/poet.song.135000.json','["割愁何處有并刀，傾座誰能奪錦袍。", "堪笑陸翁鄰鬼錄，尚推邢友擅人豪。", "杜門雖少客載酒，落筆已能奴命騷。", "安得相從北窗下，丐君剩馥與殘膏。"]'),
('6a8f5c58-f57d-4a48-8473-9aa066fba369','昔從戎南鄭日范西叔爲予書小卧屏今三十有八年矣悵然有懷','陸游','宋','宋诗','song-poetry','','[]','梁州風月今何在，每憶朋儔泪濺裾。',32,'全唐诗/poet.song.135000.json','["梁州風月今何在，每憶朋儔泪濺裾。", "戎幕已如它世事，素屏猶對故人書。"]'),
('d512bf67-ea24-4c3f-9c8f-61ec0afc7d69','小雨','陸游','宋','宋诗','song-poetry','','[]','川雲疊疊密如鱗，山雨霏霏細似塵。',32,'全唐诗/poet.song.135000.json','["川雲疊疊密如鱗，山雨霏霏細似塵。", "未必便爲耕隴喜，天公分付與詩人。"]'),
('37e75116-2c34-4e04-a3de-82bed932f072','遣懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','山澤荒寒外，門庭寂寞中。',48,'全唐诗/poet.song.135000.json','["山澤荒寒外，門庭寂寞中。", "厭聞鳩喚雨，常羨鵲知風。", "逆境嗟行徧，閑愁幸掃空。", "今晨有奇事，簫鼓賽年豐。"]'),
('a7b1e8c1-e534-4162-b679-73cd8f00ceb5','遣懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','風月資吟嘯，漁樵約往還。',48,'全唐诗/poet.song.135000.json','["風月資吟嘯，漁樵約往還。", "貧猶能釀酒，病不廢遊山。", "亂石卧牛馬，流泉鳴佩環。", "豁除羈旅日，猶有半生閑。"]'),
('e84e2407-28e5-4275-bbf9-77bac41b12d0','初夏喜事','陸游','宋','宋诗','song-poetry','','[]','箕潁元非爭奪場，瀟湘自古水雲鄉。',64,'全唐诗/poet.song.135000.json','["箕潁元非爭奪場，瀟湘自古水雲鄉。", "采茶歌裏春光老，煮繭香中夏景長。", "斂版早知遊宦惡，署門晚悟世情常。", "茹芝却粒雖無術，散髮猶當效楚狂。"]'),
('59f82449-a2d6-48a2-9bef-4449aba27a69','夢蜀','陸游','宋','宋诗','song-poetry','','[]','自計前生定蜀人，錦官來往九經春。',64,'全唐诗/poet.song.135000.json','["自計前生定蜀人，錦官來往九經春。", "堆盤丙穴魚腴美，下箸峨眉栮脯珍。", "聯騎雋遊非復昔，數編殘稿尚如新。", "最憐栩栩西窗夢，路入青衣不問津。"]'),
('70d71887-e89f-4d44-af23-2916d41444dd','閑遊二首  其一','陸游','宋','宋诗','song-poetry','','[]','一見溪山病眼開，青鞋處處蹋蒼苔。',32,'全唐诗/poet.song.135000.json','["一見溪山病眼開，青鞋處處蹋蒼苔。", "平生長物掃除盡，猶带筆床茶竈來。"]'),
('eff1433a-f6b3-49f6-b337-0a849bb138c9','閑遊二首  其二','陸游','宋','宋诗','song-poetry','','[]','好事湖邊賣酒家，杖頭錢盡慣曾賒。',32,'全唐诗/poet.song.135000.json','["好事湖邊賣酒家，杖頭錢盡慣曾賒。", "壚邊爛醉眠經日，開過紅薇一架花。"]'),
('b96d4468-6612-4181-9c38-628cbdc208b3','初夏二首  其一','陸游','宋','宋诗','song-poetry','','[]','床有蒲團坐負牆，室無童子自燒香。',64,'全唐诗/poet.song.135000.json','["床有蒲團坐負牆，室無童子自燒香。", "人圖作佛雖堪笑，我愛逃禪亦太狂。", "櫻筍久忘晨入省，蓴鱸猶喜老還鄉。", "汗青未絕茶經筆，那暇投文吊戰場。"]'),
('186a62c7-833d-4c5a-99f9-dfcc1d909f5f','初夏二首  其二','陸游','宋','宋诗','song-poetry','','[]','梅子生仁已带酸，楝花墮地尚微寒。',64,'全唐诗/poet.song.135000.json','["梅子生仁已带酸，楝花墮地尚微寒。", "室無長物惟空榻，頭不加巾但小冠。", "蠶簇倚牆絲盎起，稻秧經雨水陂寬。", "郊原清潤身差健，剩欲閑遊一跨鞍。"]'),
('dd1db5bb-e3c9-4d89-9ee6-bead69566cdf','野興二首  其一','陸游','宋','宋诗','song-poetry','','[]','東望城闉十里遥，野人生計日蕭條。',64,'全唐诗/poet.song.135000.json','["東望城闉十里遥，野人生計日蕭條。", "棋枰棄置機心息，肉食蠲除業境消。", "送藥時時過鄰父，放魚日日度溪橋。", "自憐愛物還成癖，門巷春來草沒腰。"]'),
('6c341f56-c2fd-49e4-853e-e25ef7e2670c','野興二首  其二','陸游','宋','宋诗','song-poetry','','[]','涉澗穿林信意行，翠崖朱棧愜幽情。',64,'全唐诗/poet.song.135000.json','["涉澗穿林信意行，翠崖朱棧愜幽情。", "關關幽鳥將雛語，簌簌幽篁解籜聲。", "藉草一壺消永日，出門幾屐了平生。", "川雲正作遮山計，浩蕩南風又快晴。"]'),
('e245fbc7-2681-4cc5-8fcc-8b6f4885bb5c','自笑','陸游','宋','宋诗','song-poetry','','[]','宦途昔似伏轅駒，退處今如縱壑魚。',64,'全唐诗/poet.song.135000.json','["宦途昔似伏轅駒，退處今如縱壑魚。", "手自掃除松菊徑，身常枕藉老莊書。", "郊居本自依農圃，社飲何妨逐里閭。", "白髮蕭然還自笑，風流猶見過江初。"]'),
('7881f8e5-c259-4e8d-a94d-5d41d5f23c4a','喜晴','陸游','宋','宋诗','song-poetry','','[]','正厭鳩呼雨，俄聞鵲噪晴。',48,'全唐诗/poet.song.135000.json','["正厭鳩呼雨，俄聞鵲噪晴。", "路開知潦退，書展喜窗明。", "日透疏簾影，風傳暮角聲。", "兒童競相報，門有賣朱櫻。"]'),
('e78184bd-7525-42e2-9493-7575f70e390f','過鄰曲','陸游','宋','宋诗','song-poetry','','[]','黄雲卷盡綠針齊，夏木陰陰滿古堤。',64,'全唐诗/poet.song.135000.json','["黄雲卷盡綠針齊，夏木陰陰滿古堤。", "耆老往來無負戴，比鄰問道有提携。", "暑天漸近便餐酪，吳俗相傳尚鱠齏。", "共喜豐年多樂事，扶歸先判醉如泥。"]'),
('7c713bce-df6f-4b30-ac57-edd66bec8312','題蘇虞叟巖壑隠居','陸游','宋','宋诗','song-poetry','','[]','蘇子飄然古勝流，平生高興在滄洲。',64,'全唐诗/poet.song.135000.json','["蘇子飄然古勝流，平生高興在滄洲。", "千巖萬壑舊卜築，一馬二僮時出遊。", "香斷鐘殘僧閣晚，鯨吞鼉作海山秋。", "極知處處多奇語，肯草吳箋寄我不。"]'),
('91716629-b6b2-4745-bb59-3ee6844b8fa1','縱筆二首  其一','陸游','宋','宋诗','song-poetry','','[]','騎鶴翩翩過月傍，浩然風露九秋凉。',32,'全唐诗/poet.song.135000.json','["騎鶴翩翩過月傍，浩然風露九秋凉。", "忽聞捲地潮聲起，始覺江山近故鄉。"]'),
('fb1979f8-8082-4569-a457-3102d667fa05','縱筆二首  其二','陸游','宋','宋诗','song-poetry','','[]','百尺松根結茯苓，千年長養似人形。',32,'全唐诗/poet.song.135000.json','["百尺松根結茯苓，千年長養似人形。", "誰知金鼎烹初熟，恰直山翁醉欲醒。"]'),
('a5d90420-34fb-40e7-b633-e9139d14c4b3','北窗即事二首  其一','陸游','宋','宋诗','song-poetry','','[]','衡茅隨力葺幽居，掃地焚香樂有餘。',64,'全唐诗/poet.song.135000.json','["衡茅隨力葺幽居，掃地焚香樂有餘。", "分食時能下簷鵲，作洲常悔誑池魚。", "遊歸又失相尋客，睡起重開未了書。", "袖手悠然便終日，不辭世俗笑迂疏。"]'),
('26f52cf9-8579-4d72-a232-f55589fb4373','北窗即事二首  其二','陸游','宋','宋诗','song-poetry','','[]','北窗最與懶相宜，世上紛紛了不知。',64,'全唐诗/poet.song.135000.json','["北窗最與懶相宜，世上紛紛了不知。", "露井甘寒初浚後，小山葱蒨乍晴時。", "粗餐豈復須鮭菜，蓬戶何曾設扊扅。", "幸有床頭藤杖在，登臨未遽嘆吾衰。"]'),
('2ac1f9a1-4536-40d3-9d46-94574116cfb2','感物','陸游','宋','宋诗','song-poetry','','[]','提壺勸客飲，架犁課農耕。',48,'全唐诗/poet.song.135000.json','["提壺勸客飲，架犁課農耕。", "鳩方喜婦還，蟻又以族行。", "大化職雨暘，我窗更晦明。", "芸芸觀萬物，一笑了此生。"]'),
('bbb80715-bb90-4e6b-845b-911732b26249','園中把酒示鄰曲二首  其一','陸游','宋','宋诗','song-poetry','','[]','畏途半世困風波，老返家山得已多。',64,'全唐诗/poet.song.135000.json','["畏途半世困風波，老返家山得已多。", "野餉雖無食指動，村醅也解醉顔酡。", "夢殘正欲還君枕，棋罷那知爛客柯。", "松菊未荒風月在，應容老子且婆娑。"]'),
('a4c20dd4-e8b6-4b0c-9825-795e30b47cf3','園中把酒示鄰曲二首  其二','陸游','宋','宋诗','song-poetry','','[]','煮豆烹蔬當果殽，固應杯酌盡陶匏。',64,'全唐诗/poet.song.135000.json','["煮豆烹蔬當果殽，固應杯酌盡陶匏。", "池塘瀲瀲荷浮葉，門巷陰陰筍放梢。", "三畝荒園存故業，一編蠹簡得深交。", "弊廬經雨穿將徧，欲向村東自割茅。"]'),
('0647ea8d-7bd6-4bad-894d-fe4b33742094','書憂','陸游','宋','宋诗','song-poetry','','[]','時人應怪我何求，白盡從來未白頭。',32,'全唐诗/poet.song.135000.json','["時人應怪我何求，白盡從來未白頭。", "磅礴崑崙三萬里，不知何地可薶憂。"]'),
('4e17cf35-1da2-44c3-8931-ba6e07782853','門外獨立','陸游','宋','宋诗','song-poetry','','[]','朝看出市暮看歸，數盡行人尚倚扉。',32,'全唐诗/poet.song.135000.json','["朝看出市暮看歸，數盡行人尚倚扉。", "要見先生無盡興，少須高樹挂殘暉。"]'),
('b1f346a7-c26e-44e4-9081-06b794b8a021','感事六言八首  其一','陸游','宋','宋诗','song-poetry','','[]','老去轉無飽計，醉來暫豁憂端。',28,'全唐诗/poet.song.135000.json','["老去轉無飽計，醉來暫豁憂端。", "雙鬢多年作雪，寸心至死如丹。"]'),
('8746460f-dddb-4781-b4da-d152f6992434','感事六言八首  其二','陸游','宋','宋诗','song-poetry','','[]','黑犢養來純白，睡蛇死後安眠。',28,'全唐诗/poet.song.135000.json','["黑犢養來純白，睡蛇死後安眠。", "但有漉籬可賣，不妨到處隨緣。"]'),
('a2b78cf3-4304-4100-8ac1-71a20ec5f187','感事六言八首  其三','陸游','宋','宋诗','song-poetry','','[]','五尺童知大義，三家市有公言。',28,'全唐诗/poet.song.135000.json','["五尺童知大義，三家市有公言。", "但使一眠得熟，自餘萬事寧論。"]'),
('47be1ba9-371e-4346-9e94-da9e6f2a2ed8','感事六言八首  其四','陸游','宋','宋诗','song-poetry','','[]','麥熟與人同喜，虜驕爲國私憂。',28,'全唐诗/poet.song.135000.json','["麥熟與人同喜，虜驕爲國私憂。", "身似五更春夢，家如一宿山郵。"]'),
('e092ce27-13c4-4bea-b738-ef360ef24577','感事六言八首  其五','陸游','宋','宋诗','song-poetry','','[]','早歲已歸南陌，暮年常在東籬。',28,'全唐诗/poet.song.135000.json','["早歲已歸南陌，暮年常在東籬。", "短衣幸能掩脛，長劍何須拄頤。"]'),
('1f62a7aa-d65e-4595-b162-a338910c0863','感事六言八首  其六','陸游','宋','宋诗','song-poetry','','[]','高岸眼看爲谷，寸根手種成陰。',28,'全唐诗/poet.song.135000.json','["高岸眼看爲谷，寸根手種成陰。", "一卷楚騷細讀，數行晉帖閑臨。"]'),
('84d4042d-ae55-45fe-967b-0b609897e1ec','感事六言八首  其七','陸游','宋','宋诗','song-poetry','','[]','李白嶔崎歷落，嵇康潦倒粗疏。',28,'全唐诗/poet.song.135000.json','["李白嶔崎歷落，嵇康潦倒粗疏。", "生世當行所樂，巢山喜遂吾初。"]'),
('2b214a24-f2af-4dd7-9574-b1837c7b7cf5','感事六言八首  其八','陸游','宋','宋诗','song-poetry','','[]','有飯那思肉味，安居敢厭茅茨。',28,'全唐诗/poet.song.135000.json','["有飯那思肉味，安居敢厭茅茨。", "未論顔淵陋巷，老農自是吾師。"]'),
('ee8a7111-1793-43b3-a786-27b373781ce2','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','總角入家塾，學經至豳詩。',84,'全唐诗/poet.song.135000.json','["總角入家塾，學經至豳詩。", "治道本耕桑，此理在不疑。", "今茲垂九十，謝事居海涯。", "戴星理農業，未嘆筋力衰。", "四月築麥場，五月潴稻陂。", "秉火去螟蝗，磨刀剪棘茨。", "西成大作社，歌鼓樂聖時。"]'),
('a017725d-a23c-471a-a4a0-6a642a16ff06','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','上世本爲農，輟耕業詩書。',96,'全唐诗/poet.song.135000.json','["上世本爲農，輟耕業詩書。", "我少學不成，固應返其初。", "冥冥不自揣，鄉校參群居。", "中歲偶拔擢，清班久趑趄。", "典奏入南宮，細書長石渠。", "及其乞身歸，舊業已丘墟。", "衰疾或小間，力尚給荷鋤。", "寄聲謝故人，毋爲笑迂疏。"]'),
('69e77712-f50f-4806-b821-24cc29f62793','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','我昔揮短楫，終年釣吳松。',96,'全唐诗/poet.song.135000.json','["我昔揮短楫，終年釣吳松。", "亦嘗携長鑱，采藥玉霄峰。", "爲計晚大繆，朝路偶見容。", "晨趨大明班，夜聽長樂鐘。", "白髮迫歸休，居然鮮歡悰。", "上恩許乞骸，一日收孤蹤。", "蓬茅略補葺，甑碓勤炊舂。", "故交零落盡，歲晚當誰從。"]'),
('971b0f4b-95f2-4a7e-8735-f59e900af4de','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','還鄉老未死，舉目少耆宿。',96,'全唐诗/poet.song.135000.json','["還鄉老未死，舉目少耆宿。", "邑屋亦或非，所餘但喬木。", "曩時列鼎家，今不飽半菽。", "盛衰迭變遷，何者非陵谷。", "羸然九十翁，世故見已熟。", "偶能達一理，萬事等破竹。", "布縫一稱衣，藜煮半釜粥。", "餘年更何爲，枕藉糟與麴。"]'),
('751a537b-a388-46a7-a881-885a5f5fa0f7','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','癸亥辭修門，拜賜散人號。',96,'全唐诗/poet.song.135000.json','["癸亥辭修門，拜賜散人號。", "一出非本心，歡喜歸祭竈。", "故鄉多名山，幸得遂所好。", "舟輿雖難具，信步亦可到。", "清溪無塵滓，奇峰有雲冒。", "雨墊林宗巾，風落孟嘉帽。", "豈惟狂故在，望遠亦未眊。", "一醉儻可謀，敢愛將軍告。"]'),
('82b7de86-4134-40c6-af19-caa815469fc8','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其六','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','入蜀過匡廬，秋風宿東林。',96,'全唐诗/poet.song.135000.json','["入蜀過匡廬，秋風宿東林。", "月出斷山口，滿窗松竹陰。", "裊裊一枝燭，道人語夜深。", "亦設餠果供，慰此羈旅心。", "猶恨非遠公，無酒遣我斟。", "明日下山去，嘆息難重尋。", "回首四十年，駒隙何駸駸。", "舊遊不可到，悵望空長吟。"]'),
('edd50475-1759-4682-b74c-dbea1b29480b','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','昔戍西陲時，憑高望中原。',96,'全唐诗/poet.song.135000.json','["昔戍西陲時，憑高望中原。", "願欲乘天風，往吊綺與園。", "有志莫能遂，悵望商山魂。", "遥想山中人，歲時奠芳蓀。", "夕陽簫鼓散，高柳擁廟門。", "老來更事多，考古見本根。", "乃知當時事，禍福未易言。", "千載信悠悠，浩嘆掩綠尊。"]'),
('af3b976a-5bae-455d-930f-57ecabfa33ab','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其八','陸游','宋','宋诗','song-poetry','','[]','客舟挂烟帆，千里過楚都。',96,'全唐诗/poet.song.135000.json','["客舟挂烟帆，千里過楚都。", "七澤渺無際，大不數具區。", "浪翻出長蛟，雲拆浮天吳。", "峨峨來如山，碎船不須臾。", "江行幸已盡，三峽尤畏途。", "槎牙人䱹甕，小失即見屠。", "叩頭禱鬼神，已脫猶號呼。", "願君勤自勵，憂患何時無。"]'),
('26f167e2-c4a3-41f7-a9af-f13aff394736','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其九','陸游','宋','宋诗','song-poetry','','[]','昔自京口歸，卜居得剡曲。',96,'全唐诗/poet.song.135000.json','["昔自京口歸，卜居得剡曲。", "地偏無市人，民淳有古俗。", "陋屋僅結茆，粗飯財脫粟。", "典衣以沽酒，九月未能贖。", "寧負翁子薪，耻售卞和玉。", "老身已如此，兒子亦碌碌。", "藏書幸無恙，自計不啻足。", "拾穗且浩歌，行矣墮鬼錄。"]'),
('b44a768c-c44c-462a-a91e-80cbda164732','幽居記今昔事十首以詩書從宿好林園無俗情爲韵  其一○','陸游','宋','宋诗','song-poetry','','[]','少小喜讀書，終夜守短檠。',84,'全唐诗/poet.song.135000.json','["少小喜讀書，終夜守短檠。", "其實無甚解，不幸誤有聲。", "勞苦亦何得，空失東皋耕。", "暮年乃小黠，告歸學養生。", "采藥作遠游，把釣適幽情。", "高樓笛數曲，小軒棋一枰。", "餘年置勿憂，不卿何由烹。"]'),
('d1c4834f-a7aa-4958-b592-414652ef8ca6','喜雨','陸游','宋','宋诗','song-poetry','','[]','入夏久不雨，旱勢已岌岌。',96,'全唐诗/poet.song.135000.json','["入夏久不雨，旱勢已岌岌。", "蛙蛤徒自喧，蛟龍卧如蟄。", "何由白水滿，但守青秧泣。", "上天忽悔禍，川雲起呼吸。", "虛簷雨競瀉，平野苗盡立。", "兒停蹋溝車，婦免憂谷汲。", "人言雨非雨，乃是傾玉粒。", "移床亦細事，敢嘆屋漏溼。"]'),
('c0e34553-ed39-4c3d-b8f5-70e7b1127375','初夏雜興六首  其一','陸游','宋','宋诗','song-poetry','','[]','老子今朝不用扶，雨凉百病一時蘇。',64,'全唐诗/poet.song.135000.json','["老子今朝不用扶，雨凉百病一時蘇。", "扇題杜牧故園賦，屏對王維初雪圖。", "把釣溪頭蹋湍瀨，煎茶林下置風爐。", "箇中莫謂無同賞，逋客能從折簡呼。"]'),
('539600b3-bc9f-4c36-b5ea-895213868cc2','初夏雜興六首  其二','陸游','宋','宋诗','song-poetry','','[]','巾脫冠欹八尺床，竹陰槐影有餘凉。',64,'全唐诗/poet.song.135000.json','["巾脫冠欹八尺床，竹陰槐影有餘凉。", "隨風花墮殘棋上，引睡書拋倦枕傍。", "水長沙鷗向人熟，雨餘巢燕哺雛忙。", "尚嫌未愜幽情在，又喚漁舟渡野塘。"]'),
('36e6b8d9-2f93-4a53-b185-48863ba70a12','初夏雜興六首  其三','陸游','宋','宋诗','song-poetry','','[]','自斷殘年莫問天，吾儕何處不隨緣。',64,'全唐诗/poet.song.135000.json','["自斷殘年莫問天，吾儕何處不隨緣。", "家貧却得身差健，夜短何妨晝熟眠。", "未歷名山采靈藥，且從同社樂豐年。", "賣絲糶麥償逋負，猶有餘錢買釣船。"]'),
('6a018f31-5c39-47e6-829b-77d5c8e2bda4','初夏雜興六首  其四','陸游','宋','宋诗','song-poetry','','[]','繆算狂言悔莫追，杜門省事不妨奇。',64,'全唐诗/poet.song.135000.json','["繆算狂言悔莫追，杜門省事不妨奇。", "欹傾淡墨詩成後，縹緲烏巾浴出時。", "筇杖閑行穿密篠，繩床移坐照清漪。", "眼邊好景真須惜，漸近浮生結局時。"]'),
('6702fdd5-e495-4bc8-9427-85841d644b6c','初夏雜興六首  其五','陸游','宋','宋诗','song-poetry','','[]','趁雨東園去荷鋤，歸庵却展讀殘書。',64,'全唐诗/poet.song.135000.json','["趁雨東園去荷鋤，歸庵却展讀殘書。", "幸能胸著雲夢澤，何恨家無擔石儲。", "水泛時須借篷艇，山行亦或命巾車。", "懶心惟怕遊城市，非向交親故作疏。"]'),
('eee953c4-464b-4e27-bec3-abf64ef80704','初夏雜興六首  其六','陸游','宋','宋诗','song-poetry','','[]','終日頹然蠹簡中，門前烟水浩無窮。',64,'全唐诗/poet.song.135000.json','["終日頹然蠹簡中，門前烟水浩無窮。", "百年等是一枯冢，四海應無兩放翁。", "栗玉長枝挑苦筍，胭脂小把翦防風。", "地偏日永閑無事，擬著珍蔬譜一通。"]'),
('5f67d3bd-d2e6-42ce-9f2e-61b7d0c3ae6a','對酒作','陸游','宋','宋诗','song-poetry','','[]','飲酒豪如卷白波，遣愁難似塞黄河。',64,'全唐诗/poet.song.135000.json','["飲酒豪如卷白波，遣愁難似塞黄河。", "多聞只解爲身累，後死空令見事多。", "未試神仙餐玉法，且賡壯士入關歌。", "此心不道無人識，雪鬢蕭蕭奈老何。"]'),
('b4355a84-87e5-4fd9-b638-509d83ef8de8','獨坐閑詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','書生亦有功名願，與世無緣每背馳。',32,'全唐诗/poet.song.135000.json','["書生亦有功名願，與世無緣每背馳。", "一寸丹心空計國，滿頭白髮却緣詩。"]'),
('436c8027-3de7-4f4b-8745-c2184e5405ee','獨坐閑詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','深掩柴荆謝世紛，南山時看起孤雲。',32,'全唐诗/poet.song.135000.json','["深掩柴荆謝世紛，南山時看起孤雲。", "殘年所幸身猶健，閑事惟求耳不聞。"]'),
('80d1ab6b-36f1-4b90-a0ba-5adf8796dec0','水亭二首  其一','陸游','宋','宋诗','song-poetry','','[]','水亭不受俗塵侵，葛帳筠床弄素琴。',32,'全唐诗/poet.song.135000.json','["水亭不受俗塵侵，葛帳筠床弄素琴。", "一片風光誰畫得，紅蜻蜓點綠荷心。"]'),
('f84f49b8-523d-4d1d-9a5d-5ac5d58a2307','水亭二首  其二','陸游','宋','宋诗','song-poetry','','[]','莫道山翁老病侵，靜中理得舊傳琴。',32,'全唐诗/poet.song.135000.json','["莫道山翁老病侵，靜中理得舊傳琴。", "朝來有喜君知否，雨展芭蕉二尺心。"]'),
('45fa6361-4986-488e-9606-ce6ec43bc623','書興','陸游','宋','宋诗','song-poetry','','[]','占得溪山卜數椽，飽經世故氣猶全。',64,'全唐诗/poet.song.135000.json','["占得溪山卜數椽，飽經世故氣猶全。", "入門明月真堪友，滿榻清風不用錢。", "便死也勝千百輩，少留更過二三年。", "湖橋酒美能來醉，一棹何妨作水仙。"]'),
('f7cbfe5f-cc31-47da-9c19-cf104c25b8c6','書感二首  其一','陸游','宋','宋诗','song-poetry','','[]','翟公冷落客散去，蕭尹譴死人所憐。',32,'全唐诗/poet.song.135000.json','["翟公冷落客散去，蕭尹譴死人所憐。", "輸與桐君山下叟，一生散髮醉江天。"]'),
('ddcdec99-49e9-49e7-9ec6-792500bb1a7d','書感二首  其二','陸游','宋','宋诗','song-poetry','','[]','驅山不障東逝波，一尊莫惜醉顔酡。',32,'全唐诗/poet.song.135000.json','["驅山不障東逝波，一尊莫惜醉顔酡。", "斜風細雨苕溪路，我是後身張志和。"]'),
('e1072e7e-82c0-4c21-ab0f-46a2fe3f26ab','暑雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','欲雨未雨雲車奔，欲睡不睡人思昏。',32,'全唐诗/poet.song.135000.json','["欲雨未雨雲車奔，欲睡不睡人思昏。", "蠻童正報煮茶熟，忽有野僧來叩門。"]'),
('0bc9a78f-6b2f-48cf-ba43-0ddc41c5ec16','暑雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','草茂水長蛙群鳴，涯深路壞人斷行。',32,'全唐诗/poet.song.135000.json','["草茂水長蛙群鳴，涯深路壞人斷行。", "故侯老退守瓜壟，翠蔓黄花偏眼明。"]'),
('f9937c5c-005c-4989-b65f-59eec5bdfd9c','池亭夏晝二首  其一','陸游','宋','宋诗','song-poetry','','[]','造物寧非念老生，池亭幽事悉施行。',64,'全唐诗/poet.song.135000.json','["造物寧非念老生，池亭幽事悉施行。", "群魚聚散忽無迹，孤蝶去來如有情。", "小磑落茶紛雪片，寒泉得火作松聲。", "曲肱假寐翛然寤，不爲敲門夢不成。"]'),
('727481b3-0970-40c0-bb22-30ca71780760','池亭夏晝二首  其二','陸游','宋','宋诗','song-poetry','','[]','茅舍蘆藩枕小灘，蕭森那復畏炎官。',64,'全唐诗/poet.song.135000.json','["茅舍蘆藩枕小灘，蕭森那復畏炎官。", "醉床酒解香初過，懶架書橫夢未殘。", "饞愛流匙菰米滑，渴便滿杓粟漿酸。", "兒孫幸有團欒樂，未覺浮生一笑難。"]'),
('d2544654-d282-4d39-8d05-544da4344381','頃歲從戎南鄭屢往來興鳳間暇日追懷舊遊有賦','陸游','宋','宋诗','song-poetry','','[]','昔戍蠶叢北，頻行鳳集南。',120,'全唐诗/poet.song.135000.json','["昔戍蠶叢北，頻行鳳集南。", "烽傳戎壘密，驛遠客程貪。", "春盡花猶坼，雲低雨半含。", "種畬多菽粟，藝木雜松楠。", "婦汲惟陶器，民居半草庵。", "風烟迷棧閣，雷霆起湫潭。", "城郭秦風近，村墟蜀語參。", "快心逢曠野，刮目望浮嵐。", "考古時興感，無詩日每慚。", "嘉陵最堪憶，迎馬柳毿毿。"]'),
('56168e3c-86d9-499d-9b70-b9a9ac0e82c8','掃除小園未竟歸卧','陸游','宋','宋诗','song-poetry','','[]','竹葉掃仍落，莎根鋤更生。',48,'全唐诗/poet.song.135000.json','["竹葉掃仍落，莎根鋤更生。", "陰陽常代謝，今昔各施行。", "勛業須時至，衰榮忌力爭。", "徑歸差省事，高枕聽蟬聲。"]'),
('cdd85d83-1dd0-43f3-aba8-caccb455f448','暑中北窗晝卧有作','陸游','宋','宋诗','song-poetry','','[]','禦疾如治河，但當導之東。',144,'全唐诗/poet.song.135000.json','["禦疾如治河，但當導之東。", "下流既有歸，自然行地中。", "養生如藝木，培植要得宜。", "常使無夭傷，自有干雲時。", "我少本多疾，屢亦頻危殆。", "皇天實相之，警告意有在。", "中年棄嗜慾，晚歲節飲食。", "中堅却外慕，魔盛有定力。", "死生雖天命，人事常相參。", "茫茫九衢中，百禍起一貪。", "郊虛暑雨餘，巾墮脚不襪。", "高卧北窗凉，超然寄疏豁。"]'),
('c0e63e32-bf0a-45d1-93c5-40ce424b0c67','羈懷','陸游','宋','宋诗','song-poetry','','[]','羈懷不復耐悲歡，清鏡朝朝雪鬢繁。',64,'全唐诗/poet.song.135000.json','["羈懷不復耐悲歡，清鏡朝朝雪鬢繁。", "謝傅畏逢親友別，龐公思遺子孫安。", "殘骸累歲歸民伍，半俸今春上縣官。", "閉戶惟須學堅坐，不知更敗幾蒲團。"]'),
('933a9650-03db-4164-8e83-f3ca81ce8ffb','自貽四首  其一','陸游','宋','宋诗','song-poetry','','[]','寒暑衣一稱，朝晡飯數匙。',24,'全唐诗/poet.song.135000.json','["寒暑衣一稱，朝晡飯數匙。", "錢能禍撲滿，酒不負鴟夷。"]'),
('036d5f11-89b6-4978-a6ee-978c8acab230','自貽四首  其二','陸游','宋','宋诗','song-poetry','','[]','家風本韋布，生事但漁樵。',24,'全唐诗/poet.song.135000.json','["家風本韋布，生事但漁樵。", "慣就下鄉食，莫煩東閣招。"]'),
('38ca109a-9078-44a9-afd9-4698873b25c3','自貽四首  其三','陸游','宋','宋诗','song-poetry','','[]','癡孫護雀雛，饞僕放池魚。',24,'全唐诗/poet.song.135000.json','["癡孫護雀雛，饞僕放池魚。", "懷藥問鄰疾，典衣收舊書。"]'),
('bbaec92d-4d02-4d46-9672-751e6829016e','自貽四首  其四','陸游','宋','宋诗','song-poetry','','[]','退士憤驕虜，閑人憂旱年。',24,'全唐诗/poet.song.135000.json','["退士憤驕虜，閑人憂旱年。", "耄期身未病，貧困氣猶全。"]'),
('2924cd4b-f3e9-4e3e-9029-e86b2986278e','得雨霑足遂有豐年意欣然口占','陸游','宋','宋诗','song-poetry','','[]','人事銷沉渺莽中，此身元合付天公。',64,'全唐诗/poet.song.135000.json','["人事銷沉渺莽中，此身元合付天公。", "儒生可逐惟求忘，社酒常辭不怕聾。", "鬰鬰稻苗欣出穗，汪汪陂水告成功。", "老民莫道渾無用，能爲明時祝歲豐。"]'),
('30a83dda-7f2b-4da6-adef-eb425ad2afe6','浴罷閑步門外而歸','陸游','宋','宋诗','song-poetry','','[]','兩扇荆扉數掩籬，幽人浴罷得娛嬉。',64,'全唐诗/poet.song.135000.json','["兩扇荆扉數掩籬，幽人浴罷得娛嬉。", "南臨大澤風來遠，東限連山月出遲。", "沙上無泥藤屨健，水邊弄影葛巾欹。", "徑歸却就東窗卧，要及蟬聲未歇時。"]'),
('284c88e2-ac45-4888-b0b3-b6a416e11036','初晴','陸游','宋','宋诗','song-poetry','','[]','暑雨初收體爲輕，遠山盡出眼偏明。',64,'全唐诗/poet.song.135000.json','["暑雨初收體爲輕，遠山盡出眼偏明。", "詩憑寫興忘工拙，酒取澆愁任濁清。", "綠樹有陰休倦步，澄溪無滓濯塵纓。", "老人本少凋年感，不奈江城暮角聲。"]'),
('6c161469-71d3-43e9-882d-ab062177e32c','枕上二首  其一','陸游','宋','宋诗','song-poetry','','[]','青絲玉井轆轤聲，露葉風枝鵯鵊鳴。',32,'全唐诗/poet.song.135000.json','["青絲玉井轆轤聲，露葉風枝鵯鵊鳴。", "造物未容閑到死，又從枕上得詩情。"]'),
('16c004bc-44aa-4965-a86c-c7eb9b7cec08','枕上二首  其二','陸游','宋','宋诗','song-poetry','','[]','冥冥梅雨暗江天，汗浹衣裳失夜眠。',32,'全唐诗/poet.song.135000.json','["冥冥梅雨暗江天，汗浹衣裳失夜眠。", "商略明朝當少霽，南簷風珮已鏘然。"]'),
('d2ba3cbd-7d73-4080-a5b7-a211b7d23d8c','讀史','陸游','宋','宋诗','song-poetry','','[]','馬周浪迹新豐市，阮籍興懷廣武城。',32,'全唐诗/poet.song.135000.json','["馬周浪迹新豐市，阮籍興懷廣武城。", "用捨雖殊才氣似，不妨也是一書生。"]'),
('eb123918-98a3-463e-b0a4-3d994df76aa6','今歲六月望後一日立秋故比常年凉意差早','陸游','宋','宋诗','song-poetry','','[]','九衢車馬困炎曦，正是山中散髮時。',64,'全唐诗/poet.song.135000.json','["九衢車馬困炎曦，正是山中散髮時。", "秋近梧桐已搖落，陰生蟋蟀最先知。", "稻陂水白寧憂旱，灶突烟青幸續炊。", "誰謂吾廬太岑寂，茶瓜亦有野人期。"]'),
('2fd81a02-8f52-4281-bcf1-6287d7a79a99','異夢','陸游','宋','宋诗','song-poetry','','[]','山中有異夢，重鎧奮雕戈。',48,'全唐诗/poet.song.135000.json','["山中有異夢，重鎧奮雕戈。", "敷水西通渭，潼關北控河。", "凄凉鳴趙瑟，慷慨和燕歌。", "此事終當在，無如老死何。"]'),
('24edceb5-d618-45ba-a4de-2a774f56902d','貧病','陸游','宋','宋诗','song-poetry','','[]','貧至今年劇，真無地置錐。',48,'全唐诗/poet.song.135000.json','["貧至今年劇，真無地置錐。", "判愁停貰酒，忍病罷迎醫。", "性懶非關老，天窮豈坐詩。", "秋風還欲到，便可數期頤。"]'),
('19703ae7-e8f0-4342-b779-386880f15766','涉溪','陸游','宋','宋诗','song-poetry','','[]','揮汗欲成雨，聚蟁真若雷。',24,'全唐诗/poet.song.135000.json','["揮汗欲成雨，聚蟁真若雷。", "山翁在何許，赤脚步溪來。"]'),
('27ab94ba-bc31-4937-b826-55a7dfc09e2f','即事四首  其一','陸游','宋','宋诗','song-poetry','','[]','身向人間閲事多，杜門聊得養天和。',64,'全唐诗/poet.song.135000.json','["身向人間閲事多，杜門聊得養天和。", "盛衰莫問蕭京兆，壯老空悲馬伏波。", "日暮城樓傳戍角，風生嶺路下樵歌。", "君知此段神通否，豎拂能降百萬魔。"]'),
('cb055ecd-df40-4f1a-9352-df7a4d77f263','即事四首  其二','陸游','宋','宋诗','song-poetry','','[]','唐虞千載仰巍巍，太息儒生每背馳。',64,'全唐诗/poet.song.135000.json','["唐虞千載仰巍巍，太息儒生每背馳。", "經未盡亡君更考，古無不死我何悲。", "釣耕本是求賢地，宵旰今逢願治時。", "寄謝公卿各努力，爲吾君築太平基。"]'),
('cbfccfa3-c8e6-4e01-9b04-2af44b9878aa','即事四首  其三','陸游','宋','宋诗','song-poetry','','[]','我愛湖山清絕地，抱琴携鶴住茆堂。',64,'全唐诗/poet.song.135000.json','["我愛湖山清絕地，抱琴携鶴住茆堂。", "藥苗自采盤蔬美，菰米新舂鉢飯香。", "南浦風烟無限好，北軒雷雨不勝凉。", "舊交散落無消息，借問黄塵有底忙。"]'),
('49905c30-1380-4ad5-ab13-527dbd14b738','即事四首  其四','陸游','宋','宋诗','song-poetry','','[]','放翁老去未忘情，鏡裏森然白髮生。',64,'全唐诗/poet.song.135000.json','["放翁老去未忘情，鏡裏森然白髮生。", "一片常愁見花落，三聲最怕聽猿鳴。", "年年雙隻路傍堠，夜夜短長城上更。", "晚悟一條差似可，孤舟漁火看潮平。"]'),
('ea2d78e9-81ac-41c0-b17b-8f1bf2286533','野性','陸游','宋','宋诗','song-poetry','','[]','野性從來與世疏，俗塵自不到吾廬。',64,'全唐诗/poet.song.135000.json','["野性從來與世疏，俗塵自不到吾廬。", "醉中往往得新句，夢裏時時見異書。", "稚子那偷服藥酒，家僮尚護放生魚。", "今朝更有欣然處，引得清泉灌晚蔬。"]'),
('aa2345e2-3127-4aa1-baf6-72cfa3129968','閑行','陸游','宋','宋诗','song-poetry','','[]','出戶莽悠悠，東西本不謀。',48,'全唐诗/poet.song.135000.json','["出戶莽悠悠，東西本不謀。", "阻溪因小涉，逢店得中休。", "鳥沒千山暝，蟬吟一院秋。", "詩成還自笑，信筆愧冥搜。"]'),
('37147978-50ba-4918-9e08-771096e26d37','伏中熱不可過中夜起坐作詩寄五郎','陸游','宋','宋诗','song-poetry','','[]','衆星若銀礫，老桂卧海底。',168,'全唐诗/poet.song.135000.json','["衆星若銀礫，老桂卧海底。", "中夜熱不解，病叟推枕起。", "悲蟲號草根，孤螢照野水。", "樹頭風急生，喘汗真一洗。", "追憶總角初，學古頗自喜。", "祝身願耆老，常恐抱志死。", "豈知才術疏，空自凋髮齒。", "功名永無期，祿不飽妻子。", "歸耕力又憊，得粟半糠秕。", "詩書不可頼，如倚折足几。", "大兒逾六十，逐食走千里。", "路途况艱梗，累月書一紙。", "豈不念歸省，屢請輒見柅。", "幸吾未極衰，汝行姑少止。"]'),
('2c80da80-274f-4b2f-bbd3-bab77226d5b9','暑中自遣','陸游','宋','宋诗','song-poetry','','[]','名山處處得幽尋，破硯時時出苦吟。',64,'全唐诗/poet.song.135000.json','["名山處處得幽尋，破硯時時出苦吟。", "上藥和平無近效，古詩簡淡有遺音。", "蘇門隠去聞孤嘯，栗里歸來弄素琴。", "尚恐俗塵除未盡，每思雪夜宿東林。"]'),
('b46ea831-fcbc-4ec5-84c5-4712dbb476e2','夜坐中庭','陸游','宋','宋诗','song-poetry','','[]','蕭散坐中庭，三更月未生。',48,'全唐诗/poet.song.135000.json','["蕭散坐中庭，三更月未生。", "遡風凉醉頰，汲井濯塵纓。", "草露沾衣冷，天河隔樹明。", "裴回不能睡，鼓角下高城。"]'),
('30543406-5a98-425f-9881-fa95a6e92f92','夜坐門外示子遹','陸游','宋','宋诗','song-poetry','','[]','秋意遽如許，體中殊未佳。',48,'全唐诗/poet.song.135000.json','["秋意遽如許，體中殊未佳。", "灘深無宿鷺，草茂有鳴蛙。", "棲遯從吾好，吟哦與汝偕。", "雲門漸可到，剩判幾青鞋。"]'),
('b75e8037-bb25-4855-857c-8c3cc3ba4c92','夜坐小飲','陸游','宋','宋诗','song-poetry','','[]','零落槐花已滿溝，江湖又見一番秋。',64,'全唐诗/poet.song.135000.json','["零落槐花已滿溝，江湖又見一番秋。", "冰輪有轍凌空上，銀漢無聲接地流。", "丹荔甘寒勞遠致，玉醅醇冽喜新篘。", "移床坐對西南電，好雨心知不待求。"]'),
('880914d6-287c-46d0-9fde-f808f7620fa4','閑思','陸游','宋','宋诗','song-poetry','','[]','畢世爲農不復疑，還東六見歲陰移。',64,'全唐诗/poet.song.135000.json','["畢世爲農不復疑，還東六見歲陰移。", "閉門旋了和詩債，賣藥不償沽酒資。", "意倦投床效龜息，齒疏嚼飯類牛呞。", "兀然過日君無怪，一念功名恐過悲。"]'),
('1ba5dd6b-3fcc-4bff-aa68-dd109b064f46','書村店壁','陸游','宋','宋诗','song-poetry','','[]','裹茶來就店家煎，手解馿鞍古柳邊。',64,'全唐诗/poet.song.135000.json','["裹茶來就店家煎，手解馿鞍古柳邊。", "寺閣重重出山崦，漁舟兩兩破溪烟。", "近秋漸動尋幽興，絕俸難營覓醉錢。", "到處不妨閑著句，他年好事或能傳。"]'),
('57f2f903-d10b-4649-a17a-a54db0febd2d','幽居','陸游','宋','宋诗','song-poetry','','[]','毒暑流金石，吾廬乃爾幽。',48,'全唐诗/poet.song.135000.json','["毒暑流金石，吾廬乃爾幽。", "松棚香带露，竹簟冷生秋。", "盪槳蘋花浦，垂竿杜若洲。", "非關遺世事，聊以解吾愁。"]'),
('f8b06936-5e77-43c9-afd0-fe0b2ac4f375','立秋前九日大雨凉甚二首  其一','陸游','宋','宋诗','song-poetry','','[]','天暑正三伏，雨來俄九秋。',48,'全唐诗/poet.song.135000.json','["天暑正三伏，雨來俄九秋。", "寒聲入簷戶，爽氣襲巾褠。", "山色凝深黛，溪流戰怒虬。", "身輕更何苦，處處可閑遊。"]'),
('c30f8a66-2304-4b30-b80a-3e4545200909','立秋前九日大雨凉甚二首  其二','陸游','宋','宋诗','song-poetry','','[]','雨暗初疑暮，雲開已變秋。',48,'全唐诗/poet.song.135000.json','["雨暗初疑暮，雲開已變秋。", "有風生枕簟，無汗漬衣褠。", "漉酒嘗浮螘，題詩走黑虬。", "呼兒治書笈，吾欲剡中遊。"]'),
('d7ffbf8e-a16e-4b90-9e7b-8757abb04128','寄太湖隠者','陸游','宋','宋诗','song-poetry','','["\u592a\u6e56"]','青松伐作薪，白玉碎作塵。',144,'全唐诗/poet.song.135000.json','["青松伐作薪，白玉碎作塵。", "雖云質已毀，見者猶悲辛。", "磊砢任棟梁，溫潤中琮璧。", "豈以捐空山，遂比凡木石。", "酈生吏高陽，馬周客新豐。", "從來豪傑士，大指亦略同。", "具區古大澤，烟水渺千里。", "可望不可到，中有隠君子。", "圖書兼河雒，成毀窮乾坤。", "有時跨蛟鯨，指撝雷雨奔。", "嗟我獨何人，乃許望顔色。", "逝將從之遊，變化那得測。"]'),
('e48fc53d-fcd1-44df-939a-41660e708590','讀史四首  其一','陸游','宋','宋诗','song-poetry','','[]','湘帙牙籤滿架書，流泉决决竹疏疏。',32,'全唐诗/poet.song.135000.json','["湘帙牙籤滿架書，流泉决决竹疏疏。", "人生得志寧無命，一室何妨且掃除。"]'),
('bfe75012-7cf5-4de3-b486-3ef5e7680cc0','讀史四首  其二','陸游','宋','宋诗','song-poetry','','[]','王侯到底是虛名，何物能爲我重輕。',32,'全唐诗/poet.song.135000.json','["王侯到底是虛名，何物能爲我重輕。", "徒步出關胡不可，向來常笑棄繻生。"]'),
('15e090b4-0e44-4bf7-bb91-323291b3db58','讀史四首  其三','陸游','宋','宋诗','song-poetry','','[]','男子胸中正要奇，立談能立太平基。',32,'全唐诗/poet.song.135000.json','["男子胸中正要奇，立談能立太平基。", "君王玉鉞無窮恨，千載茫茫誰復知。"]'),
('7332df7d-732d-4b8c-8436-4c0d95202055','讀史四首  其四','陸游','宋','宋诗','song-poetry','','[]','自古功名亦偶諧，胸中要使浩無涯。',32,'全唐诗/poet.song.135000.json','["自古功名亦偶諧，胸中要使浩無涯。", "可憐赫赫丹陽尹，數顆檳榔尚繫懷。"]'),
('e11a256a-b538-4d59-81a2-551569e20587','病戒','陸游','宋','宋诗','song-poetry','','[]','憂身如憂國，畏病如畏亂。',96,'全唐诗/poet.song.135000.json','["憂身如憂國，畏病如畏亂。", "此身雖幸健，敢作無事看。", "禍福在呼吸，恐懼兼寢飯。", "人所忽不省，我思嘗熟爛。", "夜卧不安席，晨起寧待旦。", "雖云親藥石，得失每參半。", "人情喜一快，往往觸剽悍。", "收功寧使遲，覆敗不可玩。"]'),
('634809db-132c-46b1-a8e0-93fa6c7e7723','夏夜納凉','陸游','宋','宋诗','song-poetry','','[]','河漢微茫月漸低，風聲正在草堂西。',64,'全唐诗/poet.song.135000.json','["河漢微茫月漸低，風聲正在草堂西。", "莎根唧唧蟲相吊，木末翻翻鵲未栖。", "屯甲近聞如積水，守關不假用丸泥。", "孤臣報國嗟無地，只有東皋更飽犁。"]'),
('d19d07d4-89b2-47a3-b44c-a27c46eca5ab','銘座','陸游','宋','宋诗','song-poetry','','[]','身退仍懷退，心平更欲平。',48,'全唐诗/poet.song.135000.json','["身退仍懷退，心平更欲平。", "直嫌繩尚曲，重覺鼎猶輕。", "力學能除翳，深居可息黥。", "聖門初豈遠，妙處在躬行。"]'),
('517027b0-52d2-4826-a1f4-1b7e83823664','獨坐絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','蛙鳴乃是怒，鵩嘯固非妖。',24,'全唐诗/poet.song.135000.json','["蛙鳴乃是怒，鵩嘯固非妖。", "獨宿空山夜，何妨伴寂寥。"]'),
('4a2db40d-da3d-46a4-919d-1d9af459652d','獨坐絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','輕雷不成雨，闕月却穿雲。',24,'全唐诗/poet.song.135000.json','["輕雷不成雨，闕月却穿雲。", "獨倚南齋柱，長吟到夜分。"]'),
('01fae6e6-4344-41c1-b844-7f60dd530dc1','初秋驟凉','陸游','宋','宋诗','song-poetry','','[]','我比嚴光勝一籌，不教俗眼識羊裘。',64,'全唐诗/poet.song.135000.json','["我比嚴光勝一籌，不教俗眼識羊裘。", "滄波萬頃江湖晚，漁唱一聲天地秋。", "飲酒何嘗能作病，登樓是處可消憂。", "名山海內知何限，準擬從今更爛遊。"]'),
('1d5172cc-6ccf-46f1-a384-17483701e195','新凉','陸游','宋','宋诗','song-poetry','','[]','家住山陰剡曲傍，一番風雨送新凉。',64,'全唐诗/poet.song.135000.json','["家住山陰剡曲傍，一番風雨送新凉。", "亦知病得清秋健，無奈愁隨獨夜長。", "日落川原橫慘淡，月明洲渚遠蒼茫。", "老民無復憂時意，齒豁頭童只自傷。"]'),
('783b40fa-2372-4a1b-8c86-0db5177e0d2b','書幸','陸游','宋','宋诗','song-poetry','','[]','才薄無能役，窮途不意全。',48,'全唐诗/poet.song.135000.json','["才薄無能役，窮途不意全。", "得書娛晚暮，遇藥起沉綿。", "漂母能分食，偷兒肯恕氈。", "不知從此去，更度幾流年。"]'),
('758e1d1b-68f3-42e2-81eb-ca21ba7662d0','獨遊','陸游','宋','宋诗','song-poetry','','[]','地僻少人迹，身閑思獨遊。',48,'全唐诗/poet.song.135000.json','["地僻少人迹，身閑思獨遊。", "荒村更阻雨，衰鬢不禁秋。", "斷續呼牛笛，橫斜放鴨舟。", "殘年澹無事，隨處送悠悠。"]'),
('aa69633a-9543-4f7b-903a-030b734b12b0','記夢','陸游','宋','宋诗','song-poetry','','[]','夢遊異境不可識，翠壁蒼崖立千尺。',128,'全唐诗/poet.song.135000.json','["夢遊異境不可識，翠壁蒼崖立千尺。", "樓臺縹緲出其上，揮手直登無羽翼。", "門楣扁牓作八分，奇勁非復人間迹。", "主人鹿弁紫綺裘，相見歡如有疇昔。", "探懷示我數紙書，妙句玄言皆造極。", "我即鈔之雜行草，主人戃怳如甚惜。", "夢中亦復知是夢，意恐覺時無處覓。", "自量强記可不忘，雞唱夢回空歎息。"]'),
('1daef0b0-de5d-4b94-af76-01cabac24014','初秋自述','陸游','宋','宋诗','song-poetry','','[]','平生偶有愛山僻，垂老常無沽酒資。',64,'全唐诗/poet.song.135000.json','["平生偶有愛山僻，垂老常無沽酒資。", "破屋頹垣吾已矣，大冠長劍汝爲誰。", "郵亭歷歷關河遠，鬢髮蕭蕭歲月移。", "殘暑不禁隨手過，東籬又近菊花時。"]'),
('4aa139f0-aef7-45a8-a8de-ce171c248b86','秋暑夜起追凉二首  其一','陸游','宋','宋诗','song-poetry','','[]','漱罷寒泉弄月明，浩然風露欲三更。',32,'全唐诗/poet.song.135000.json','["漱罷寒泉弄月明，浩然風露欲三更。", "曲闌干畔踟躇久，靜聽空廊絡緯聲。"]'),
('56c80dd3-9fae-4605-a08a-afb6bcf3c013','秋暑夜起追凉二首  其二','陸游','宋','宋诗','song-poetry','','[]','道士磯邊浪蹴天，郎官湖上月侵船。',32,'全唐诗/poet.song.135000.json','["道士磯邊浪蹴天，郎官湖上月侵船。", "暮年自度無因到，且與沙鷗作後緣。"]'),
('67201cb6-0592-45d4-9150-43f5b4f47128','小築','陸游','宋','宋诗','song-poetry','','[]','小築並湖堤，茅茨不厭低。',48,'全唐诗/poet.song.135000.json','["小築並湖堤，茅茨不厭低。", "引泉澆藥圃，砟竹樹雞棲。", "夕靄山常淡，秋蕪路欲迷。", "平生草玄手，老去學鉏犂。"]'),
('14d35f98-48a3-410c-bf3c-e5174c6c1681','喜雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','黑雲橫絕天漢津，父老僉言候當雨。',64,'全唐诗/poet.song.135000.json','["黑雲橫絕天漢津，父老僉言候當雨。", "未論秋稼綿千里，且喜滂沱洗殘暑。", "我起呼兒扶再拜，汗垢得凉真一快。", "桔槔抱甕兩置之，日日齋盂飽菘芥。"]'),
('93343a2b-f213-49b8-8fc7-b91fd49c0b7c','喜雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','雨聲蕭蕭集庭樹，雨氣森森入窗戶。',64,'全唐诗/poet.song.135000.json','["雨聲蕭蕭集庭樹，雨氣森森入窗戶。", "玉川茆屋久不葺，破漏無復施床處。", "我於萬事本悠悠，危坐讀書忘百憂。", "明朝秋水增三尺，且復沙邊弄釣舟。"]'),
('9eea6e42-8252-4d57-9610-49c59adc9a11','秋夜','陸游','宋','宋诗','song-poetry','','[]','大枕空床夢不成，草堂悄悄四無聲。',64,'全唐诗/poet.song.135000.json','["大枕空床夢不成，草堂悄悄四無聲。", "月明漸見天窗白，風起忽聞簷珮鳴。", "客子未忘悲故里，老人無念到浮名。", "江村歲歲先凉冷，且復尋盟向短檠。"]'),
('7d882a01-8fa8-44b9-ae50-03ed1d37a4d7','白鷗','陸游','宋','宋诗','song-poetry','','[]','平生崖異每自笑，一接俗人三祓除。',32,'全唐诗/poet.song.135000.json','["平生崖異每自笑，一接俗人三祓除。", "惟有白鷗真我客，爾來底事向人疏。"]'),
('9873687a-8b1a-4212-97c8-28cd0b9779c4','靜室','陸游','宋','宋诗','song-poetry','','[]','靜室床橫一素琴，爾來殊覺道根深。',64,'全唐诗/poet.song.135000.json','["靜室床橫一素琴，爾來殊覺道根深。", "喚回倦枕功名夢，洗盡浮生幻妄心。", "兩屨雲烟遊少室，一窗風雪宿東林。", "細思却是關身事，無奈殘年老病侵。"]'),
('b4545e83-df20-4c90-bf26-5544566aaf69','秋興','陸游','宋','宋诗','song-poetry','','[]','秋眠怯簟冷，晨飯喜蔬香。',48,'全唐诗/poet.song.135000.json','["秋眠怯簟冷，晨飯喜蔬香。", "寧使衣百結，肯儲錢一囊。", "杜門雖局促，負氣尚軒昂。", "死去真無憾，曾孫似我長。"]'),
('abc0cadf-0573-4802-b6c0-a425b5f561b4','欲雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','徙穴中庭蟻，爭巢後圃鳩。',24,'全唐诗/poet.song.135000.json','["徙穴中庭蟻，爭巢後圃鳩。", "物情猶慮患，人事得忘憂。"]'),
('4725b03d-9d19-4f1d-915a-00d9537cc96e','欲雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','荷鍤决新渠，芟茅補舊廬。',24,'全唐诗/poet.song.135000.json','["荷鍤决新渠，芟茅補舊廬。", "共知秋必雨，有備即安居。"]'),
('d7326d18-9417-4d73-a44c-81b8976079d7','雜感十首以野曠沙岸浄天高秋月明爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','呂釣渭水濱，說築傅巖野。',48,'全唐诗/poet.song.135000.json','["呂釣渭水濱，說築傅巖野。", "雖曰古盛時，得士蓋亦寡。", "天將啟治亂，人才有用舍。", "向非萬牛力，孰與成大厦。"]'),
('4194f3b3-e354-44d4-a95d-5dc8e4dcbb2b','雜感十首以野曠沙岸浄天高秋月明爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','洙泗日已遠，儒術日已喪。',48,'全唐诗/poet.song.135000.json','["洙泗日已遠，儒術日已喪。", "學者稱孔墨，爲國雜伯王。", "書生幸有聞，力薄不能倡。", "默默世俗間，汝職無乃曠。"]'),
('74db5801-e549-4d8b-8844-85af4c6cd990','雜感十首以野曠沙岸浄天高秋月明爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','我昔下三峽，百丈堆兩車。',48,'全唐诗/poet.song.135000.json','["我昔下三峽，百丈堆兩車。", "初發公安城，已過長風沙。", "早知世路惡，恨不常浮家。", "至今清夜夢，雙櫓聞謳啞。"]'),
('d0d8c0c0-70f3-40f2-9dbb-d033ad9d13af','雜感十首以野曠沙岸浄天高秋月明爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','斗杓運四序，寒暑忽已換。',48,'全唐诗/poet.song.135000.json','["斗杓運四序，寒暑忽已換。", "人生知幾何，去日難把玩。", "憑高望烟海，青山忽中斷。", "秋風肺病蘇，爲子巾一岸。"]'),
('bd18ba43-40e7-467e-90a1-4663ad617d56','雜感十首以野曠沙岸浄天高秋月明爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','磨鏡要使明，拭几要使浄。',48,'全唐诗/poet.song.135000.json','["磨鏡要使明，拭几要使浄。", "奈何視吾心，不若几與鏡。", "垢汙倘未除，秋毫即爲病。", "吾曹亦聖徒，可不學顔孟。"]'),
('13825ece-2823-49ce-b5ea-fb643f50e1a5','雜感十首以野曠沙岸浄天高秋月明爲韵  其六','陸游','宋','宋诗','song-poetry','','[]','天人本一理，禍福常昭然。',48,'全唐诗/poet.song.135000.json','["天人本一理，禍福常昭然。", "人衆何足恃，妄謂能勝天。", "適燕當北轅，調瑟當解弦。", "五行未可忽，洪範禹所傳。"]'),
('35312445-d956-4e84-8af8-a660ab75ab4b','雜感十首以野曠沙岸浄天高秋月明爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','鏡湖一何清，稽山一何高。',48,'全唐诗/poet.song.135000.json','["鏡湖一何清，稽山一何高。", "浙江百里遠，夜枕聞驚濤。", "子胥死吳下，千載無人豪。", "遺魂招不來，我欲續楚騷。"]'),
('ad01bce6-e4f4-420b-a6d6-3c7ff1b47f95','雜感十首以野曠沙岸浄天高秋月明爲韵  其八','陸游','宋','宋诗','song-poetry','','[]','歸耕無襏襫，出戰無兜鍪。',48,'全唐诗/poet.song.135000.json','["歸耕無襏襫，出戰無兜鍪。", "已失西疇春，空懷北平秋。", "提携一束書，蹭蹬至白頭。", "鬴中有轑飯，一飽吾何求。"]'),
('8f894e11-196c-450f-8d7d-4881a5b6c239','雜感十首以野曠沙岸浄天高秋月明爲韵  其九','陸游','宋','宋诗','song-poetry','','[]','我昔遊劍南，爛醉平羌月。',48,'全唐诗/poet.song.135000.json','["我昔遊劍南，爛醉平羌月。", "一杯玻瓈春，萬里望吳越。", "豈知有天幸，故山得歸骨。", "扁舟小江上，夜半看月沒。"]'),
('10a3b0cf-ace7-493e-927c-be94f45cdc37','雜感十首以野曠沙岸浄天高秋月明爲韵  其一○','陸游','宋','宋诗','song-poetry','','[]','入東多名山，天台連四明。',48,'全唐诗/poet.song.135000.json','["入東多名山，天台連四明。", "路窮寺門出，林闕溪橋橫。", "豈無一月閑，結束與子行。", "會揀最幽處，煨芋聽雪聲。"]'),
('4b95e332-61f3-49ba-be49-71197d97f582','秋思十首  其一','陸游','宋','宋诗','song-poetry','','[]','秋雲易簇日常陰，西望山村每欲尋。',32,'全唐诗/poet.song.135000.json','["秋雲易簇日常陰，西望山村每欲尋。", "屏掩數峰臨峭絕，蛇蟠一徑入幽深。"]'),
('56ff3d0e-f180-4d7c-bb35-4aad08d9b9c1','秋思十首  其二','陸游','宋','宋诗','song-poetry','','[]','山步溪橋入早秋，飄然無處不堪遊。',32,'全唐诗/poet.song.135000.json','["山步溪橋入早秋，飄然無處不堪遊。", "僧廊偶爲題詩入，魚市常因施藥留。"]'),
('b179c0da-e52e-41c1-8489-a17699912725','秋思十首  其三','陸游','宋','宋诗','song-poetry','','[]','臨海銅燈喜夜長，蘄春笛簟怨秋凉。',32,'全唐诗/poet.song.135000.json','["臨海銅燈喜夜長，蘄春笛簟怨秋凉。", "世間生滅無窮境，盡付山房一炷香。"]'),
('788706d2-148d-4766-af21-02c3e575ce20','秋思十首  其四','陸游','宋','宋诗','song-poetry','','[]','才不才間未必全，胸中元自要超然。',32,'全唐诗/poet.song.135000.json','["才不才間未必全，胸中元自要超然。", "黄金不博身强健，且醉江湖萬里天。"]'),
('88fecd07-7204-48e4-b7c7-0ec236296671','秋思十首  其五','陸游','宋','宋诗','song-poetry','','[]','牙齒漂浮欲半空，此生已付有無中。',32,'全唐诗/poet.song.135000.json','["牙齒漂浮欲半空，此生已付有無中。", "一杯藜粥楓林下，時與鄰翁說歲豐。"]'),
('9d385269-e079-498b-a801-7952b0c1f7ac','秋思十首  其六','陸游','宋','宋诗','song-poetry','','[]','疏泉洗石誇身健，試墨燒香破日長。',32,'全唐诗/poet.song.135000.json','["疏泉洗石誇身健，試墨燒香破日長。", "若得三山安樂法，不須更覓玉函方。"]'),
('47e0d5c4-f6fb-46fd-bde2-9762fc54e0fb','秋思十首  其七','陸游','宋','宋诗','song-poetry','','[]','傍縣人來涕泗翻，蝗災暴虎不堪言。',32,'全唐诗/poet.song.135000.json','["傍縣人來涕泗翻，蝗災暴虎不堪言。", "天心似爲衰翁地，飽食安眠獨北村。"]'),
('caabfe0f-46d2-4428-8c46-1ed1c6d0e4fe','秋思十首  其八','陸游','宋','宋诗','song-poetry','','[]','閑愁正可資詩酒，小疾安能減食眠。',32,'全唐诗/poet.song.135000.json','["閑愁正可資詩酒，小疾安能減食眠。", "一畝旋租畦菜地，千錢新買釣魚船。"]'),
('d0a2db06-1b18-4d72-b0bc-fd6b54924228','秋思十首  其九','陸游','宋','宋诗','song-poetry','','[]','眼明尚見蠅頭字，暑退初親雁足燈。',32,'全唐诗/poet.song.135000.json','["眼明尚見蠅頭字，暑退初親雁足燈。", "歷歷胸中千載事，莫將輕比住庵僧。"]'),
('f5b47a08-be6e-4290-a49d-8358da7fc3ea','秋思十首  其一○','陸游','宋','宋诗','song-poetry','','[]','虛極靜篤道乃見，仁至義盡餘何憂。',32,'全唐诗/poet.song.135000.json','["虛極靜篤道乃見，仁至義盡餘何憂。", "名山采藥恐未免，策蹇孰能從我遊。"]'),
('6d6d1975-8120-4dbf-886a-9e57d21b8c05','鷄犬二首  其一','陸游','宋','宋诗','song-poetry','','[]','鄉村年久競農務，秋斂春耕恐失時。',32,'全唐诗/poet.song.135000.json','["鄉村年久競農務，秋斂春耕恐失時。", "我老元無夙興事，懶鷄啼曉恰相宜。"]'),
('e213e716-092b-4ee8-8ab0-b4351ae5d217','鷄犬二首  其二','陸游','宋','宋诗','song-poetry','','[]','貧家也復謹朝昏，小犬今年乞近村。',32,'全唐诗/poet.song.135000.json','["貧家也復謹朝昏，小犬今年乞近村。", "糠秕無多深愧汝，狺狺終夜護籬門。"]'),
('32c9f76c-ca6f-49b2-81c0-bdbcf7a3af15','秋來瘦甚而益健戲作','陸游','宋','宋诗','song-poetry','','[]','莫笑形羸不自支，清虛正與老人宜。',64,'全唐诗/poet.song.135000.json','["莫笑形羸不自支，清虛正與老人宜。", "矛頭淅米誰能食，甑裏生塵却自奇。", "獨釣又逢秋晚後，安眠常到日高時。", "邇來久雨牆垣壞，砟竹東岡自作籬。"]'),
('89c9b974-343e-4ec4-8446-e8b01acab0a0','秋夜','陸游','宋','宋诗','song-poetry','','[]','岸幘蕭然病體輕，雨餘郊館已凉生。',64,'全唐诗/poet.song.135000.json','["岸幘蕭然病體輕，雨餘郊館已凉生。", "微風掠面酒無力，明月滿窗眠不成。", "葉底涓涓秋露滴，草根咽咽暗蛩鳴。", "屏居未免傷孤寂，頼有鄰翁約耦耕。"]'),
('1b884640-4151-4735-ae0d-9563eaffa1c2','秋興','陸游','宋','宋诗','song-poetry','','[]','巢燕無情不更回，門庭日日落楸槐。',64,'全唐诗/poet.song.135000.json','["巢燕無情不更回，門庭日日落楸槐。", "新凉漸喜償碑債，多病還憂欠藥材。", "社近家方篘濁酒，客來身自掃蒼苔。", "道心已熟機心盡，寄語鸕鷀莫苦猜。"]'),
('14402626-d930-43aa-bec9-684a74145da5','閑詠','陸游','宋','宋诗','song-poetry','','[]','莫笑結廬魚稻鄉，風流殊未減華堂。',64,'全唐诗/poet.song.135000.json','["莫笑結廬魚稻鄉，風流殊未減華堂。", "茶分正焙新開箬，水挹中𤃩自候湯。", "小几研朱晨點易，重簾掃地晝焚香。", "個中富貴君知否，不必金貂侍紫皇。"]'),
('aae35663-6c6f-4078-acef-4381c1245335','人壽至耄期','陸游','宋','宋诗','song-poetry','','[]','人壽至耄期，如位至王公。',96,'全唐诗/poet.song.135000.json','["人壽至耄期，如位至王公。", "非以德將之，往往不克終。", "非必皆大惡，過取固多凶。", "吾今垂九十，追逐群衆中。", "筋骸勝拜起，耳目未盲聾。", "强健天所借，正與富貴同。", "一念愧屋漏，一言誑孩童。", "老無朋友規，日夜勤自攻。"]'),
('9e46cc13-a530-4532-ae22-692c94a37f57','訪野人','陸游','宋','宋诗','song-poetry','','[]','我行城西南，適茲素秋時。',72,'全唐诗/poet.song.135000.json','["我行城西南，適茲素秋時。", "風露雖已高，草木鬰未衰。", "敲門尋野人，一笑萬事非。", "拂榻意何勤，酒釅雁鶩肥。", "新凉天所賜，盡醉不足辭。", "擊壤歌堯年，瞑目以爲期。"]'),
('83664df4-9d59-4508-aa05-5680059281e9','熏蚊效宛陵先生體','陸游','宋','宋诗','song-poetry','','[]','澤國故多蚊，乘夜吁可怪。',48,'全唐诗/poet.song.135000.json','["澤國故多蚊，乘夜吁可怪。", "舉扇不能却，燔艾取一快。", "不如小忍之，驅逐吾已隘。", "寧聞大度士，變色爲蜂蠆。"]'),
('5ad75da5-39ab-4a24-9fea-49364a348ec4','吹笛','陸游','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','吳江楚澤閑遊遍，未豁平生萬里心。',32,'全唐诗/poet.song.135000.json','["吳江楚澤閑遊遍，未豁平生萬里心。", "醉裏獨携蒼玉筍，岳陽樓上作龍吟。"]'),
('f84ff8dc-80e2-486e-a3f6-33d222e74629','書幸','陸游','宋','宋诗','song-poetry','','[]','破屋頹垣鬼笑窮，暗中調護頼天公。',32,'全唐诗/poet.song.135000.json','["破屋頹垣鬼笑窮，暗中調護頼天公。", "頻年得疾身猶健，百種無營飯不空。"]'),
('1f613a82-bf7e-4793-9696-c0672c2938fe','感事','陸游','宋','宋诗','song-poetry','','[]','已醉猩猩猶愛屐，入秋燕燕尚爭巢。',32,'全唐诗/poet.song.135000.json','["已醉猩猩猶愛屐，入秋燕燕尚爭巢。", "老夫看盡人間事，欲向山僧學打包。"]'),
('1ce51916-013c-4e85-bc16-acdf2c9e930e','晚晴','陸游','宋','宋诗','song-poetry','','[]','雨如塵點送新凉，雲作魚鱗襯夕陽。',32,'全唐诗/poet.song.135000.json','["雨如塵點送新凉，雲作魚鱗襯夕陽。", "蓬戶清閑貧亦好，筍輿安穩病何傷。"]'),
('b962edf7-12e9-48f7-9bd1-292bd5138be0','農家','陸游','宋','宋诗','song-poetry','','[]','寂寂江村數掩籬，吾廬又及素秋時。',64,'全唐诗/poet.song.135000.json','["寂寂江村數掩籬，吾廬又及素秋時。", "橫林未脫色已盡，孤鳥欲棲鳴更悲。", "小釜蓴羹初下豉，矮瓶豆粉正燃萁。", "爲農幸有家風在，百世相傳更勿疑。"]'),
('5008be8f-04d9-4903-b7d9-92a701af54aa','寓嘆二首  其一','陸游','宋','宋诗','song-poetry','','[]','白首還鄉厭蕨薇，倀倀自嘆欲疇依。',64,'全唐诗/poet.song.135000.json','["白首還鄉厭蕨薇，倀倀自嘆欲疇依。", "門庭不掃稀迎客，碪杵無聲未贖衣。", "達士共知生是贅，古人嘗謂死爲歸。", "耕疇幸可期中熟，又報殘蝗接翅飛。"]'),
('f9269e96-f125-4eed-8e99-2b32953ee424','寓嘆二首  其二','陸游','宋','宋诗','song-poetry','','[]','憶昔建炎南渡時，兵間脫死命如絲。',64,'全唐诗/poet.song.135000.json','["憶昔建炎南渡時，兵間脫死命如絲。", "奉親百口一身在，許國寸心孤劍知。", "坐有客瘖堪共醉，身今病忘莫求醫。", "出門但畏從人事，臨水登山却未衰。"]'),
('26984a53-c337-4ef9-bf46-8f88f6c4d6dd','雨夜','陸游','宋','宋诗','song-poetry','','[]','病多漸減燈前課，老甚都忘枕上愁。',32,'全唐诗/poet.song.135000.json','["病多漸減燈前課，老甚都忘枕上愁。", "一段高情誰會得，卧聽簷雨瀉清秋。"]'),
('7d24f0b7-12c3-4ec4-b574-8061b89a1877','秋懷四首  其一','陸游','宋','宋诗','song-poetry','','[]','火食非初志，衣塵每自哀。',48,'全唐诗/poet.song.135000.json','["火食非初志，衣塵每自哀。", "危途觸灧澦，歸興薄蓬萊。", "逋客傳琴調，高僧乞藥栽。", "人間豈不好，病眼自慵開。"]'),
('69874330-1fa7-417f-8566-d530579ab23b','秋懷四首  其二','陸游','宋','宋诗','song-poetry','','[]','苦雨無時止，幽人空復情。',48,'全唐诗/poet.song.135000.json','["苦雨無時止，幽人空復情。", "少眠知夜永，久病喜秋清。", "螢傍疏簾度，蛩依壞甃鳴。", "流年那可挽，又見曉窗明。"]'),
('2939354a-21d3-46e6-91c0-c9147df04165','秋懷四首  其三','陸游','宋','宋诗','song-poetry','','[]','獨立離人境，幽居察物情。',48,'全唐诗/poet.song.135000.json','["獨立離人境，幽居察物情。", "蟻知軍陣法，蟲作緯車聲。", "身老惟貪睡，兒癡亦惰耕。", "騰騰復兀兀，何以報時平。"]'),
('fa921000-f285-4f31-984d-4fd1bfa20ebe','秋懷四首  其四','陸游','宋','宋诗','song-poetry','','[]','寓世久成贅，忘家生若浮。',48,'全唐诗/poet.song.135000.json','["寓世久成贅，忘家生若浮。", "安能三太息，惟有四宜休。", "屋壞無全堵，船輕每信流。", "鴟夷幸無恙，頼爾可消憂。"]'),
('885742f2-2d43-4599-8fd5-7ae903db0407','小室','陸游','宋','宋诗','song-poetry','','[]','窗几窮幽致，圖書發古香。',48,'全唐诗/poet.song.135000.json','["窗几窮幽致，圖書發古香。", "尺池魚鱍鱍，拳石樹蒼蒼。", "老去身猶健，秋來日自長。", "養生吾豈解，懶或似嵇康。"]'),
('e8a3c65c-b87e-431f-8b50-b8ad6ded8efb','贈道侶','陸游','宋','宋诗','song-poetry','','[]','蕊笈人多有，惟君獨造微。',48,'全唐诗/poet.song.135000.json','["蕊笈人多有，惟君獨造微。", "丹成河自塞，吟罷劍俱飛。", "酒市尋差易，雲山覓更非。", "何時醉携手，爲我發玄機。"]'),
('14f68e7b-f160-475c-add9-54c24393fc48','舟中醉題二首  其一','陸游','宋','宋诗','song-poetry','','[]','風吹蘆荻聲颼颼，晚潮入港浮孤舟。',64,'全唐诗/poet.song.135000.json','["風吹蘆荻聲颼颼，晚潮入港浮孤舟。", "老民已掃市朝迹，造物全付江湖秋。", "項里廟前是魚市，禹會橋邊多酒樓。", "醉來且復過此日，莫爲碪杵悲無裘。"]'),
('434fd0e4-4c08-4c2b-ada3-c4e60f7a61c1','舟中醉題二首  其二','陸游','宋','宋诗','song-poetry','','[]','鮑郎山前烟雨昏，疏燈小市愁偏門。',64,'全唐诗/poet.song.135000.json','["鮑郎山前烟雨昏，疏燈小市愁偏門。", "上船初發十字港，鼓棹忽過三家村。", "孤鸞對鏡空自感，老龜搘床何足論。", "但願諸公各戮力，上助明主憂元元。"]'),
('08297e3f-31f4-4aae-a10e-c394d897e12d','出遊暮歸','陸游','宋','宋诗','song-poetry','','[]','東行西行日暮歸，川雲漠漠雨霏霏。',64,'全唐诗/poet.song.135000.json','["東行西行日暮歸，川雲漠漠雨霏霏。", "蝗餘場上禾收薄，酒貴街頭客醉稀。", "買犢躬耕空自力，灼龜占歲又成非。", "稚孫索飯殊關抱，憐汝何時得瓠肥。"]'),
('37ecea02-1246-49e1-b876-5b6e882dcaaa','園中作','陸游','宋','宋诗','song-poetry','','[]','紗巾一幅立斜陽，本尚無閑况有忙。',64,'全唐诗/poet.song.135000.json','["紗巾一幅立斜陽，本尚無閑况有忙。", "鷄犬往來空自得，禽魚翔泳各相忘。", "欲衰莎草無多綠，未落梧桐已半黄。", "徂歲匆匆成絕嘆，瓦溝行復見新霜。"]'),
('0160117b-572f-4856-9b38-7174d442cad6','感舊','陸游','宋','宋诗','song-poetry','','[]','莫笑山翁老欲僵，壯年曾及事高皇。',64,'全唐诗/poet.song.135000.json','["莫笑山翁老欲僵，壯年曾及事高皇。", "雕戈北出戍窮塞，華表東歸悲故鄉。", "萬事固難輕忖度，百年猶有未更嘗。", "紛紛謗譽何勞問，但覺邯鄲一夢長。"]'),
('af839fe8-e54f-46ab-b85b-a288b178417f','東園','陸游','宋','宋诗','song-poetry','','[]','車馬無聲客到稀，荷鋤終日在園扉。',64,'全唐诗/poet.song.135000.json','["車馬無聲客到稀，荷鋤終日在園扉。", "斷殘地脈疏泉過，穿透天心得句歸。", "對鏡每悲鸞獨舞，繞枝誰見鵲南飛。", "悠然自適君無怪，文史如山暫解圍。"]'),
('966d5c9f-b8b1-416a-8569-02b1dfb7fbcc','秋夜','陸游','宋','宋诗','song-poetry','','[]','局促人間每鮮歡，秋來病骨愈酸寒。',64,'全唐诗/poet.song.135000.json','["局促人間每鮮歡，秋來病骨愈酸寒。", "夾衣尚典雁聲過，斷簡未收鷄唱殘。", "退士鬢毛紛似雪，老臣心事炳如丹。", "燈前握臂無交舊，聊喚清尊少自寬。"]'),
('351ba8f8-e44f-4ce9-bfcd-42ff8c136abd','驛壁偶題三首  其一','陸游','宋','宋诗','song-poetry','','[]','纍纍驛門堠，杳杳寺樓鐘。',48,'全唐诗/poet.song.135000.json','["纍纍驛門堠，杳杳寺樓鐘。", "葉落樹陰薄，雲生山崦重。", "交親窮未棄，父子老相從。", "惟待新粳熟，高眠聽夜舂。"]'),
('089c9581-c4bb-4c25-9862-888df86c9566','驛壁偶題三首  其二','陸游','宋','宋诗','song-poetry','','[]','去去投山驛，悠悠解橐裝。',48,'全唐诗/poet.song.135000.json','["去去投山驛，悠悠解橐裝。", "斜陽穿破廄，落葉滿空廊。", "舞簡村巫醉，塗朱野女粧。", "近行吾亦倦，假寢據胡床。"]'),
('e7cf58ce-39a9-4a3b-a275-cac9d466f305','驛壁偶題三首  其三','陸游','宋','宋诗','song-poetry','','[]','過市未十里，入山知幾重。',48,'全唐诗/poet.song.135000.json','["過市未十里，入山知幾重。", "幽林聞格磔，淺瀨見噞喁。", "小甕家家酒，衡門世世農。", "班生定癡絕，辛苦覓侯封。"]'),
('1a524903-ad81-4199-adcf-a48cb691d9c2','夜起思子虡','陸游','宋','宋诗','song-poetry','','[]','我久依耕壟，兒方吊戰場。',48,'全唐诗/poet.song.135000.json','["我久依耕壟，兒方吊戰場。", "卧聞風浩蕩，起視月蒼茫。", "老境綈袍暖，貧家菜粥香。", "惟愁殺風景，無酒作重陽。"]'),
('18ae0030-86b2-41ea-a9c3-80c57a9918c0','秋日次前輩新年韵五首  其一','陸游','宋','宋诗','song-poetry','','[]','孤生雖永棄，要亦是黎元。',48,'全唐诗/poet.song.135000.json','["孤生雖永棄，要亦是黎元。", "渺渺烟中路，冥冥海上村。", "小灘看鷺立，平野送鴉翻。", "即欲掩關卧，南山猶未昏。"]'),
('f6355763-6304-4032-bd96-e290d906549f','秋日次前輩新年韵五首  其二','陸游','宋','宋诗','song-poetry','','[]','舊交多雋傑，離散各何之。',48,'全唐诗/poet.song.135000.json','["舊交多雋傑，離散各何之。", "騏驥志千里，鷦鷯巢一枝。", "青雲迷故步，白首負明時。", "幸有殘書卷，猶堪付小兒。"]'),
('92f3a069-2c5b-4c8c-ae82-4a064104f8c6','秋日次前輩新年韵五首  其三','陸游','宋','宋诗','song-poetry','','[]','老人常獨處，一笑比河清。',48,'全唐诗/poet.song.135000.json','["老人常獨處，一笑比河清。", "終日無來客，三年不入城。", "高眠聽酒滴，危坐對雲生。", "矯首羲皇世，吾其享大羹。"]'),
('6105c620-b476-41c9-9fb8-524fccb8b82d','秋日次前輩新年韵五首  其四','陸游','宋','宋诗','song-poetry','','[]','浮家久居蜀，下峽晚還東。',48,'全唐诗/poet.song.135000.json','["浮家久居蜀，下峽晚還東。", "天際孤帆遠，花前百榼空。", "旅遊渾似夢，年運遂成翁。", "欲話峨眉月，無人可與同。"]'),
('3b6dfbf8-ca0a-48d6-a67c-4474b9afd5e6','秋日次前輩新年韵五首  其五','陸游','宋','宋诗','song-poetry','','[]','殘年垂九十，雪鬢不勝繁。',48,'全唐诗/poet.song.135000.json','["殘年垂九十，雪鬢不勝繁。", "賣屨糴炊米，典衣租廢園。", "山深雲滿屋，夜靜月當門。", "鄰曲時相過，扶行頼稚孫。"]'),
('d8f8d183-f231-4ccf-a39d-755606f7f5c7','仲秋書事十首  其一','陸游','宋','宋诗','song-poetry','','[]','秋風社散日平西，餘胙殘壺手自提。',32,'全唐诗/poet.song.135000.json','["秋風社散日平西，餘胙殘壺手自提。", "賜食敢思烹細項，家庖仍禁擘團臍。"]'),
('db2c6545-f76b-4a33-a83f-121f06ae6b3f','仲秋書事十首  其二','陸游','宋','宋诗','song-poetry','','[]','天心那得與人同，牲社家家禱歲豐。',32,'全唐诗/poet.song.135000.json','["天心那得與人同，牲社家家禱歲豐。", "料理蝗餘猶十五，殘年亦未委溝中。"]'),
('058f0659-cac2-4e02-af69-45faba32bb83','仲秋書事十首  其三','陸游','宋','宋诗','song-poetry','','[]','斷雲歸岫雨初收，茅舍蕭條古渡頭。',32,'全唐诗/poet.song.135000.json','["斷雲歸岫雨初收，茅舍蕭條古渡頭。", "短褐老人垂九十，松枯石瘦不禁秋。"]'),
('073f17bc-35ce-4ae4-bedd-9c0d57116c58','仲秋書事十首  其四','陸游','宋','宋诗','song-poetry','','[]','客來深愧里閭情，近爲衰殘罷送迎。',32,'全唐诗/poet.song.135000.json','["客來深愧里閭情，近爲衰殘罷送迎。", "旋置風爐煎顧渚，劇談猶得慰平生。"]'),
('71028d79-21e3-4017-b113-52bac674a4c3','仲秋書事十首  其五','陸游','宋','宋诗','song-poetry','','[]','舉家食粥顔平原，坐客無氈鄭廣文。',32,'全唐诗/poet.song.135000.json','["舉家食粥顔平原，坐客無氈鄭廣文。", "不是有心輕富貴，偶然看破是浮雲。"]'),
('cfdd1de4-36ab-4322-a300-c8d7a81dddb5','仲秋書事十首  其六','陸游','宋','宋诗','song-poetry','','[]','書生習氣盡驅除，酒興詩情亦已無。',32,'全唐诗/poet.song.135000.json','["書生習氣盡驅除，酒興詩情亦已無。", "底怪今朝親筆硯，村鄉來請辟蝗符。"]'),
('e7c30276-dbdf-46ca-8209-b81cff416baa','仲秋書事十首  其七','陸游','宋','宋诗','song-poetry','','[]','靈府不搖神泰定，病根已去脈和平。',32,'全唐诗/poet.song.135000.json','["靈府不搖神泰定，病根已去脈和平。", "金丹妙處無多子，只要先生兩眼明。"]'),
('5e22e186-21db-4dd5-bdc8-b993d317244a','仲秋書事十首  其八','陸游','宋','宋诗','song-poetry','','[]','省身要似晨通髮，止殺先從暮拍蚊。',32,'全唐诗/poet.song.135000.json','["省身要似晨通髮，止殺先從暮拍蚊。", "老負明時無補報，惟將忠敬事心君。"]'),
('477f243e-254d-4501-8a07-400ca8852682','仲秋書事十首  其九','陸游','宋','宋诗','song-poetry','','[]','杖得輕堅餘可略，酒能醇勁更何求。',32,'全唐诗/poet.song.135000.json','["杖得輕堅餘可略，酒能醇勁更何求。", "二君最是平生舊，白首相從萬事休。"]'),
('aaa6b0fd-4828-46bb-a516-4aefd22b464f','仲秋書事十首  其一○','陸游','宋','宋诗','song-poetry','','[]','心明始信元無佛，氣住何曾別有仙。',32,'全唐诗/poet.song.135000.json','["心明始信元無佛，氣住何曾別有仙。", "領取三山安樂法，蒲團紙帳過年年。"]'),
('a698e820-37ae-4d1d-bbbd-6ff9cd7fed98','步屧','陸游','宋','宋诗','song-poetry','','[]','名山有志未能酬，步屧東岡當出遊。',64,'全唐诗/poet.song.135000.json','["名山有志未能酬，步屧東岡當出遊。", "小閣捲簾驚鷺起，清池投餌看魚浮。", "西風吹葉空多感，落日銜山尚小留。", "兒老戍邊歸未得，淮南新雁又經秋。"]'),
('e65e3abb-2708-46dd-91ac-774f2e12a5f3','後死','陸游','宋','宋诗','song-poetry','','[]','後死非初望，餘生只自悲。',48,'全唐诗/poet.song.135000.json','["後死非初望，餘生只自悲。", "舊交孤劍在，壯志短檠知。", "行步雖依杖，光陰未付棋。", "爲農自當力，不爲學豳詩。"]'),
('12dfcee0-c167-4c42-870f-c10532433f05','思剡','陸游','宋','宋诗','song-poetry','','[]','羸疾無休日，清秋適此時。',48,'全唐诗/poet.song.135000.json','["羸疾無休日，清秋適此時。", "節存旄盡落，带剩眼頻移。", "吾興復不淺，俗人那得知。", "會當遊剡去，支許有深期。"]'),
('90aee1d5-1d31-4feb-be01-54a6fb94f889','故里','陸游','宋','宋诗','song-poetry','','[]','漏盡鐘鳴有夜行，幾人故里得歸耕。',64,'全唐诗/poet.song.135000.json','["漏盡鐘鳴有夜行，幾人故里得歸耕。", "摧傷自喜消前業，疾恙天教學養生。", "鄰曲新傳秧馬式，房櫳靜聽緯車聲。", "芋魁菰首君無笑，老子看來是大烹。"]'),
('921e2f84-917f-400d-a348-02f009f666a1','野意','陸游','宋','宋诗','song-poetry','','[]','久忝明恩返故鄉，全家衣食出耕桑。',64,'全唐诗/poet.song.135000.json','["久忝明恩返故鄉，全家衣食出耕桑。", "詩纔適意寧求好，醉即成眠不暇狂。", "小雨荷鉏分藥品，乍凉扶杖看優場。", "此身已作農夫死，却愧時賢獨未忘。"]'),
('bf9d4c7a-1c25-47cd-babd-d69c3caaa100','意行至神祠酒坊而歸','陸游','宋','宋诗','song-poetry','','[]','雨收霽色滿川原，獨曳枯藤出里門。',64,'全唐诗/poet.song.135000.json','["雨收霽色滿川原，獨曳枯藤出里門。", "陌上微風搖稗穟，溝中殘水出籬根。", "繫牲廟柱悲刀几，釃酒村場滿盎盆。", "興盡還家殊不遠，漁燈績火閙黄昏。"]'),
('4e67aa9d-31fc-4dd2-a5e0-87cb169b7555','訪村老','陸游','宋','宋诗','song-poetry','','[]','强健如翁舉世稀，夜深容我叩門扉。',64,'全唐诗/poet.song.135000.json','["强健如翁舉世稀，夜深容我叩門扉。", "大兒叱犢戴星出，稚子捕魚乘月歸。", "骨肉團欒無遠別，比鄰假貸不相違。", "人間可羨惟農畝，又見秋燈照搗衣。"]'),
('54b498c2-a7cd-4497-8f40-fe70dd893e03','戲題僧庵','陸游','宋','宋诗','song-poetry','','[]','致虛守靜氣常全，家付兒孫命委天。',64,'全唐诗/poet.song.135000.json','["致虛守靜氣常全，家付兒孫命委天。", "夢事只堪高卧看，危途誰較疾行先。", "獨轅短棹聊乘興，野草幽花自鬭妍。", "數字漫留僧壁去，與身閑作後身緣。"]'),
('f7d3cc23-06cb-4add-9fd9-ed0a6bb1d1cb','書意二首  其一','陸游','宋','宋诗','song-poetry','','[]','秋江菰菜喜新嘗，鹽酪親調匕箸香。',64,'全唐诗/poet.song.135000.json','["秋江菰菜喜新嘗，鹽酪親調匕箸香。", "但有長腰吳下米，豈須細肋大官羊。", "青衫昔悔塵中老，白髮今宜靜處藏。", "一事尚須深自咎，街頭兒女識韓康。"]'),
('b4ba2159-46e4-4865-8b4d-0ea23c6f4de1','書意二首  其二','陸游','宋','宋诗','song-poetry','','[]','物我年來已兩忘，蕭然湖曲一茆堂。',64,'全唐诗/poet.song.135000.json','["物我年來已兩忘，蕭然湖曲一茆堂。", "身閑自與俗子遠，睡美不知秋夜長。", "餘祿正應齏甕在，宿酲時卧酒壚傍。", "老人肘後長生藥，檢盡千金無此方。"]'),
('05e8c82d-a94f-4b43-af7d-ea4cd4db1231','南塘晚步記鄰里語','陸游','宋','宋诗','song-poetry','','[]','喚舟欲泛湖，出門日已暮。',144,'全唐诗/poet.song.135000.json','["喚舟欲泛湖，出門日已暮。", "顧景遂輟行，老病畏風露。", "不如上南塘，蕭然散予步。", "季子挾書卷，仲孫奉杖屨。", "夏秋多杜門，一出驚行路。", "鄰里相與言，穡事凜可懼。", "群蝗飛蔽日，殘嚙到竹樹。", "惟茲數里間，若有神物護。", "天菑幸獨薄，豈以此老故。", "老人亦自笑，病骨日欲仆。", "鬼神彼何爲，與世殊好惡。", "相期勤自修，此幸豈可屢。"]'),
('6e499cb4-c681-473a-862c-1b7a327bbdbf','稽山道中二首  其一','陸游','宋','宋诗','song-poetry','','[]','文章事業初何有，鐘鼎山林本自同。',32,'全唐诗/poet.song.135000.json','["文章事業初何有，鐘鼎山林本自同。", "昨暮釣魚天鏡北，今朝采藥石帆東。"]'),
('0dfa7165-8a84-4431-bcc1-dc72b8476312','稽山道中二首  其二','陸游','宋','宋诗','song-poetry','','[]','禹陵草木初霑露，謝墅人家已閉門。',32,'全唐诗/poet.song.135000.json','["禹陵草木初霑露，謝墅人家已閉門。", "八十年間幾來往，癡頑不料至今存。"]'),
('dedc39e3-18eb-41f4-93c6-5a4c03b65abd','讀近人詩','陸游','宋','宋诗','song-poetry','','[]','琢琱自是文章病，奇險尤傷氣骨多。',32,'全唐诗/poet.song.135000.json','["琢琱自是文章病，奇險尤傷氣骨多。", "君看大羹玄酒味，蟹螯蛤柱豈同科。"]'),
('4fbb4c72-cdc4-4c36-bc86-874f8c0c5b42','琴劍','陸游','宋','宋诗','song-poetry','','[]','流塵冉冉琴誰鼓，漬血斑斑劍不磨。',32,'全唐诗/poet.song.135000.json','["流塵冉冉琴誰鼓，漬血斑斑劍不磨。", "俱是人間感懷事，豈無壯士爲悲歌。"]'),
('e4ef8404-07d9-4e16-8f55-e62e4a43066e','戲題','陸游','宋','宋诗','song-poetry','','[]','莫輕凡骨未飛騰，要勝人間粥飯僧。',32,'全唐诗/poet.song.135000.json','["莫輕凡骨未飛騰，要勝人間粥飯僧。", "山路近行猶百里，酒杯一舉必三升。"]'),
('46ba8b4a-b8ce-43d3-9f62-2faf21f486e7','溪上小雨','陸游','宋','宋诗','song-poetry','','[]','我是人間自在人，江湖處處可垂綸。',32,'全唐诗/poet.song.135000.json','["我是人間自在人，江湖處處可垂綸。", "掃空紫陌紅塵夢，收得烟蓑雨笠身。"]'),
('524f06bc-e003-40ff-aba6-95109488c6c1','晚聞庭樹鴉鳴有感','陸游','宋','宋诗','song-poetry','','[]','烏鵲棲我庭，將旦輒散去。',144,'全唐诗/poet.song.135000.json','["烏鵲棲我庭，將旦輒散去。", "此豈厭所棲，亦以飲啄故。", "一饑能驅人，擾擾無晨暮。", "不然亦已矣，豈樂塵土污。", "我有茆三間，自少鮮外慕。", "力耕自足食，鷄豚亦可具。", "晚雖誤收召，疾走如脫兔。", "六年楓林下，不知歲月度。", "殘骸幸强健，沽酒遍山步。", "醉歸每自笑，不負此芒屨。", "平生愛方外，雖老冀有遇。", "秋風送片帆，更上剡溪路。"]'),
('73165543-96dc-4b5d-9753-9772f606ec4a','秋夜齋中二首  其一','陸游','宋','宋诗','song-poetry','','[]','木落烟深江上村，暮秋蕭瑟不堪論。',64,'全唐诗/poet.song.135000.json','["木落烟深江上村，暮秋蕭瑟不堪論。", "雁如著意頻驚枕，月似知愁故入門。", "營道數峰新石友，廣陵一曲古桐孫。", "亦知長物終安取，聊與兒曹洗睡昏。"]'),
('a21ed8c3-7519-495c-a1e1-e4e70785e762','秋夜齋中二首  其二','陸游','宋','宋诗','song-poetry','','[]','殘年冉冉返丘園，敗屋蕭蕭長子孫。',64,'全唐诗/poet.song.135000.json','["殘年冉冉返丘園，敗屋蕭蕭長子孫。", "久悔文辭妨大學，偶因憂患得玄門。", "扶持後死知天幸，容養無能荷國恩。", "急雨打窗秋又晚，旋挑野菜助盤飧。"]'),
('98b03e87-173b-478d-85c2-52bfc83e5329','識愧','陸游','宋','宋诗','song-poetry','','[]','幾年羸疾卧家山，牧豎樵夫日往還。',64,'全唐诗/poet.song.135000.json','["幾年羸疾卧家山，牧豎樵夫日往還。", "至論本求編簡上，忠言乃在里閭間。", "私憂驕虜心常折，念報明時涕每潸。", "寸祿不沾能及此，細聽只益厚吾顔。"]'),
('e4d36886-88ef-48e2-b4ee-33ba9b21c07e','秋雨','陸游','宋','宋诗','song-poetry','','[]','暮秋木葉已微丹，小雨蕭蕭又作寒。',64,'全唐诗/poet.song.135000.json','["暮秋木葉已微丹，小雨蕭蕭又作寒。", "目送斷雲歸谷口，身隨新雁寄江干。", "濁醪易負尋常債，退士難叨本分官。", "謝盡浮名更無事，燈前兒女話團欒。"]'),
('3a749799-b5b6-476c-953b-ca69b7a482cd','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其一','陸游','宋','宋诗','song-poetry','','[]','旬日雨頻作，一年秋又殘。',48,'全唐诗/poet.song.135000.json','["旬日雨頻作，一年秋又殘。", "光陰不少貸，懷抱若爲寬。", "小甕聊尋醉，疏砧已戒寒。", "定知清夜夢，又過石闌干。"]'),
('d9b72332-74fe-4860-86d5-d7184637092f','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其二','陸游','宋','宋诗','song-poetry','','[]','何許是吾廬，南臨古鏡湖。',48,'全唐诗/poet.song.135000.json','["何許是吾廬，南臨古鏡湖。", "園林垂橘柚，門巷落楸梧。", "床穩龜無息，巢新鶴有雛。", "鄰翁殊耐久，有酒即相呼。"]'),
('154701e8-6956-43e7-aa1e-769998aaae0e','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其三','陸游','宋','宋诗','song-poetry','','[]','原野無閑土，鄉閭有老人。',48,'全唐诗/poet.song.135000.json','["原野無閑土，鄉閭有老人。", "疾平行已健，秋晚醉差頻。", "啄黍黄鷄嫩，迎霜紫蟹新。", "百年元任運，一笑却關身。"]'),
('01466834-20ee-48be-a30f-380390da4452','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其四','陸游','宋','宋诗','song-poetry','','[]','藿食筋骸憊，林廬歲月侵。',48,'全唐诗/poet.song.135000.json','["藿食筋骸憊，林廬歲月侵。", "道窮思故友，力盡悔初心。", "浩浩天知我，悠悠後視今。", "飄零君勿嘆，古瑟有遺音。"]'),
('4ba49731-0ec1-4701-a32a-bae8107fddd6','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其五','陸游','宋','宋诗','song-poetry','','[]','輕裝兩衣笈，假寢一胡床。',48,'全唐诗/poet.song.135000.json','["輕裝兩衣笈，假寢一胡床。", "喚渡江樓下，逢僧縣驛傍。", "橫林生夕靄，孤蝶弄秋光。", "老慣人間事，無詩寄斷腸。"]'),
('3e65878a-d55d-45e9-941c-652a9184ab8d','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其六','陸游','宋','宋诗','song-poetry','','[]','渡水得魚舍，乞漿敲竹扉。',48,'全唐诗/poet.song.136000.json','["渡水得魚舍，乞漿敲竹扉。", "地偏花带恨，林暖鳥忘歸。", "獨往非違世，幽居自息機。", "晚來清興極，更喜雨霏霏。"]'),
('64cf4a73-ece6-4111-a586-8d20dabbbdbf','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其七','陸游','宋','宋诗','song-poetry','','[]','窮阨非由命，從來作計疏。',48,'全唐诗/poet.song.136000.json','["窮阨非由命，從來作計疏。", "妄營資鬼笑，多愛奪狐書。", "何事能陶寫，惟當盡破除。", "霜晴宜著屐，不敢笑無馿。"]'),
('ba11832a-11ac-4f8d-aab4-b0a6a5994744','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其八','陸游','宋','宋诗','song-poetry','','[]','寓世年雖往，安心疾已平。',48,'全唐诗/poet.song.136000.json','["寓世年雖往，安心疾已平。", "每思丹竈冷，宜覺世緣輕。", "布被鷄催曉，蓬窗鵲噪晴。", "呼兒凈洗硯，書帖寄青城。"]'),
('aaa085b3-1343-4b5d-aacc-50e4a09d2438','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其九','陸游','宋','宋诗','song-poetry','','[]','萬古無窮夢，餘年欲散雲。',48,'全唐诗/poet.song.136000.json','["萬古無窮夢，餘年欲散雲。", "身雖迫衰謝，學未廢鉏耘。", "開卷多新得，逢人有舊聞。", "伏生雖九十，猶冀與斯文。"]'),
('65010aa7-dd45-4c9e-8e33-ea9d21fd837a','秋來益覺頑健時一出遊意中甚適雜賦五字十首  其一○','陸游','宋','宋诗','song-poetry','','[]','斯世本無事，古人誰與歸。',48,'全唐诗/poet.song.136000.json','["斯世本無事，古人誰與歸。", "屏除閑麈尾，收拾舊蓑衣。", "浩浩觀空劫，拳拳訟昨非。", "雲開天萬里，遼鶴正孤飛。"]'),
('f9cc73d4-830d-471b-88aa-59a35447913a','遊近山僧庵','陸游','宋','宋诗','song-poetry','','[]','卧看香穗嘆吾衰，起著芒鞋信所之。',64,'全唐诗/poet.song.136000.json','["卧看香穗嘆吾衰，起著芒鞋信所之。", "十里溪山最佳處，一年寒暖適中時。", "眼明竹院如曾到，心許沙鷗卜後期。", "不是詩人託高興，日長真付一枰棋。"]'),
('89e9c5ed-6ac4-4779-98f9-7b2a6d7d184e','喜晴','陸游','宋','宋诗','song-poetry','','[]','三日雨不止，意謂無復晴。',96,'全唐诗/poet.song.136000.json','["三日雨不止，意謂無復晴。", "泥深不可出，卧聽空階聲。", "事有未易料，南風起三更。", "陣陣浮雲歸，杲杲初日明。", "穡事既竭作，機杼比屋鳴。", "天公真老手，談笑功皆成。", "家家有新釀，歡言相送迎。", "蝗孽幸掃空，努力謀春耕。"]'),
('357c6060-8eb2-4e46-8ddc-0d114c8a242e','阿通自閩中歸甫九歲頗有老成之風作此詩示之','陸游','宋','宋诗','song-poetry','','[]','通子還家已九齡，從師衿佩兩青青。',32,'全唐诗/poet.song.136000.json','["通子還家已九齡，從師衿佩兩青青。", "長成勉作功名計，勿學衰翁老一經。"]'),
('84f9aacb-01f6-4dfd-97f4-0072c48eae68','農家六首  其一','陸游','宋','宋诗','song-poetry','','[]','大布縫袍穩，乾薪起火紅。',48,'全唐诗/poet.song.136000.json','["大布縫袍穩，乾薪起火紅。", "薄才施畎畝，朴學教兒童。", "羊要高爲棧，鷄當細織籠。", "農家自堪樂，不是傲王公。"]'),
('3105e8b7-3e5e-413e-897b-5c5bccfe1fe5','農家六首  其二','陸游','宋','宋诗','song-poetry','','[]','盜息無排甲，兵消不取丁。',48,'全唐诗/poet.song.136000.json','["盜息無排甲，兵消不取丁。", "頻過鬭鷄舍，閑學相牛經。", "江浦漁歌遠，人家績火青。", "遨遊無定處，隨意宿丘亭。"]'),
('b5a990c9-1c46-4ca0-9e08-54f7efa08a5b','農家六首  其三','陸游','宋','宋诗','song-poetry','','[]','東舍女乘龍，西家婦夢熊。',48,'全唐诗/poet.song.136000.json','["東舍女乘龍，西家婦夢熊。", "翁誇酒重碧，孫愛果初紅。", "栗烈三冬近，團欒一笑同。", "營生無繆巧，百事仰天公。"]'),
('23bd30f8-2cfe-4089-aa73-dc9be0505d9f','農家六首  其四','陸游','宋','宋诗','song-poetry','','[]','租犢耕蕎地，呼船取荻薪。',48,'全唐诗/poet.song.136000.json','["租犢耕蕎地，呼船取荻薪。", "蒼頭供井臼，赤脚解縫紉。", "僧乞銘師塔，巫邀賽土神。", "心常厭多事，謝病又經旬。"]'),
('95e070a0-0045-418d-b967-ec8fc654c348','農家六首  其五','陸游','宋','宋诗','song-poetry','','[]','新作地爐成，蓬窗亦自明。',48,'全唐诗/poet.song.136000.json','["新作地爐成，蓬窗亦自明。", "油香蕎餌脆，人靜布機鳴。", "縣吏催科簡，豪家督債輕。", "小康何敢望，生計且支撐。"]'),
('eadcc4e4-16f7-44c1-950d-585eeb77c20c','農家六首  其六','陸游','宋','宋诗','song-poetry','','[]','諸孫晚下學，髻脫繞園行。',48,'全唐诗/poet.song.136000.json','["諸孫晚下學，髻脫繞園行。", "互笑藏鈎拙，爭言鬭草贏。", "爺嚴責程課，翁愛哺飴餳。", "富貴寧期汝，它年且力耕。"]'),
('951c6fc1-d86e-4b8a-a608-63e971dff2ba','讀老子有感','陸游','宋','宋诗','song-poetry','','[]','左史倚相讀皇墳，學者尚得窺全渾。',64,'全唐诗/poet.song.136000.json','["左史倚相讀皇墳，學者尚得窺全渾。", "孰爲武成二三策，寧取道德五千言。", "巢居結繩事益遠，澆淳散朴忍復論。", "安得深山老不死，坐待古俗還羲軒。"]'),
('e6ffc951-c456-4b26-8d0e-ac8b1049b973','鄰人送菰菜','陸游','宋','宋诗','song-poetry','','[]','張蒼飲乳元難學，綺季餐芝未免饑。',32,'全唐诗/poet.song.136000.json','["張蒼飲乳元難學，綺季餐芝未免饑。", "稻飯似珠菰似玉，老農此味有誰知。"]'),
('66bfd108-d4ad-4d77-b07e-85045a6e9b1c','書喜','陸游','宋','宋诗','song-poetry','','[]','莫謂家貧厭舊醅，一尊聊對桂花開。',64,'全唐诗/poet.song.136000.json','["莫謂家貧厭舊醅，一尊聊對桂花開。", "天菑已過無蝗孽，海舶初通有藥材。", "剩借凉風吹醉頰，况逢急雨洗浮埃。", "入秋腰脚增强健，山麓從今日日來。"]'),
('2eff9458-88c2-4e2d-8925-c244e6c02c41','秋日徙倚門外久之','陸游','宋','宋诗','song-poetry','','[]','舍前烟水似瀟湘，白首歸來愛故鄉。',64,'全唐诗/poet.song.136000.json','["舍前烟水似瀟湘，白首歸來愛故鄉。", "五畝山園鬰桑柘，數椽茅屋映菰蔣。", "翻翻小繖船歸郭，渺渺長歌月滿塘。", "却掩柴荆了無事，篆盤重點已殘香。"]'),
('92d7f173-a277-419d-8b59-637cb2d690b1','雙蝶','陸游','宋','宋诗','song-poetry','','[]','庭草何離離，清晨露猶溼。',72,'全唐诗/poet.song.136000.json','["庭草何離離，清晨露猶溼。", "草頭兩黄蝶，爲我小佇立。", "秋光亦已晚，行見霜霰集。", "方春不盡狂，汝悔尚何及。", "吾生更堪笑，去日如電急。", "功名竟何在，惆悵劍鋒澀。"]'),
('82a07c9f-5d80-4c82-b10f-df6b68d58015','法雲孚上座求詩','陸游','宋','宋诗','song-poetry','','[]','老人癡鈍避嫌猜，終日柴門閉不開。',32,'全唐诗/poet.song.136000.json','["老人癡鈍避嫌猜，終日柴門閉不開。", "堪笑山僧能好事，乞碑纔去覓詩來。"]'),
('57fffd5e-718d-4f61-bb6c-fba5412f2250','詹仲信出示卜居詩佳甚作二絕句謝之  其一','陸游','宋','宋诗','song-poetry','','[]','十里相望亦未遥，何由頻得慰無聊。',32,'全唐诗/poet.song.136000.json','["十里相望亦未遥，何由頻得慰無聊。", "老來萬事慵開眼，獨喜詩盟不寂寥。"]'),
('74e6a15e-a14a-4192-8313-9873e64cb10b','詹仲信出示卜居詩佳甚作二絕句謝之  其二','陸游','宋','宋诗','song-poetry','','[]','年來阻闊動經時，忽見新篇乃爾奇。',32,'全唐诗/poet.song.136000.json','["年來阻闊動經時，忽見新篇乃爾奇。", "安得齊紈翦團扇，爲君小草卜居詩。"]'),
('163c8217-07f3-403b-9bcc-1a17360c2422','夜雨','陸游','宋','宋诗','song-poetry','','[]','夜雨有殘滴，秋碪無絕聲。',48,'全唐诗/poet.song.136000.json','["夜雨有殘滴，秋碪無絕聲。", "得詩旋已忘，覓睡固難成。", "壯志悲垂老，歸耕願太平。", "發春纔屬爾，歲事又崢嶸。"]'),
('8da9e5d2-a429-45f8-931f-054ea2f3d963','晚秋出門戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','病叟倘徉古澤邊，橫林搖落暮秋天。',64,'全唐诗/poet.song.136000.json','["病叟倘徉古澤邊，橫林搖落暮秋天。", "鳴鳩雨後却呼婦，飛雀霜前先著綿。", "抱被每投僧榻宿，卷書時當酒家錢。", "秋風想像芝房熟，北望商山一悵然。"]'),
('5c7eede5-aedb-4e40-b49b-1774b22f40d9','晚秋出門戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','閑愁那到野人邊，萬事元知合付天。',64,'全唐诗/poet.song.136000.json','["閑愁那到野人邊，萬事元知合付天。", "盡醉僅能三龠酒，新寒未辦一銖綿。", "鄰僧每欲分齋鉢，廟史猶來索社錢。", "無地置錐真細事，不妨胸次日超然。"]'),
('cd3b8257-c186-4515-9a44-ba7453f90239','消搖','陸游','宋','宋诗','song-poetry','','[]','莫笑茆簷陋，消搖遂野情。',48,'全唐诗/poet.song.136000.json','["莫笑茆簷陋，消搖遂野情。", "遇魔增道力，因病悟浮生。", "謀食憑長鑱，論交得短檠。", "不知從此去，幾見雁南征。"]'),
('761e672d-3a49-4f7a-b9de-d50e13fd7315','堅頑','陸游','宋','宋诗','song-poetry','','[]','小市朝行藥，明燈夜讀書。',48,'全唐诗/poet.song.136000.json','["小市朝行藥，明燈夜讀書。", "雖殊带箭鶴，要是脫鈎魚。", "有飯已多矣，無衣亦晏如。", "堅頑君勿怪，豈失遂吾初。"]'),
('7c82d060-280c-4aea-b3ab-8d58450f21d4','遣懷四首  其一','陸游','宋','宋诗','song-poetry','','[]','息倦登耕隴，乘閑弄釣舟。',48,'全唐诗/poet.song.136000.json','["息倦登耕隴，乘閑弄釣舟。", "安能書咄咄，且復送悠悠。", "窮巷誰來往，村醪自獻酬。", "何妨晏平仲，歲晚一狐裘。"]'),
('e0ffdd62-979c-4b78-b35b-09e473d8c9a2','遣懷四首  其二','陸游','宋','宋诗','song-poetry','','[]','窮每占周易，閑惟讀楚騷。',48,'全唐诗/poet.song.136000.json','["窮每占周易，閑惟讀楚騷。", "病隨災漸退，懶與拙相遭。", "投枕燈初上，披衣日已高。", "清愁亦可剪，無處買并刀。"]'),
('f5e067df-9d4b-4134-a932-6118b9a26014','遣懷四首  其三','陸游','宋','宋诗','song-poetry','','[]','有志師千載，無方起九原。',48,'全唐诗/poet.song.136000.json','["有志師千載，無方起九原。", "山園菜常瘦，村店酒多渾。", "衰疾形詩句，窮愁入夢魂。", "傍觀任嘲笑，吾道始應尊。"]'),
('3e231b06-4182-451a-ae5f-6cb6194b0b55','遣懷四首  其四','陸游','宋','宋诗','song-poetry','','[]','雲族初疑雨，風生忽快晴。',48,'全唐诗/poet.song.136000.json','["雲族初疑雨，風生忽快晴。", "半窗松竹影，繞舍鳥烏聲。", "看劍心猶壯，開書眼漸明。", "餘年真已矣，不復問君平。"]'),
('83190c9b-ee64-4e03-8894-926cf89d537b','初寒','陸游','宋','宋诗','song-poetry','','[]','日月誰能駐，風霜忽已高。',48,'全唐诗/poet.song.136000.json','["日月誰能駐，風霜忽已高。", "公孫分布被，范叔共綈袍。", "䆉䅉炊香甑，蒲萄壓小槽。", "所慚才已盡，孤詠不能豪。"]'),
('ab719902-74a0-484f-ba8c-b498bf25e231','閑行至西山民家','陸游','宋','宋诗','song-poetry','','[]','秋林半丹葉，秋草多碧花。',72,'全唐诗/poet.song.136000.json','["秋林半丹葉，秋草多碧花。", "隔山五六里，臨水兩三家。", "罾魚與伐荻，各自有生涯。", "平池散雁鶩，繞舍栽桑麻。", "客至但舉手，土釜煎秋茶。", "城中不如汝，切莫慕浮夸。"]'),
('ba034eda-de89-4454-b7fc-162073842fb7','夜與子遹說蜀道因作長句示之','陸游','宋','宋诗','song-poetry','','[]','憶自梁州入劍門，關山無處不消魂。',64,'全唐诗/poet.song.136000.json','["憶自梁州入劍門，關山無處不消魂。", "亞松託宿逢秋雨，小柏經行聽曉猿。", "當日只知悲客路，歸來終亦老江村。", "吾兒生晚那知此，聊對青燈與細論。"]'),
('32cb4a0b-6bcd-439b-8a19-0cbd6ca68570','村舍七首  其一','陸游','宋','宋诗','song-poetry','','[]','無懷葛天古遺民，種畬歸來束澗薪。',32,'全唐诗/poet.song.136000.json','["無懷葛天古遺民，種畬歸來束澗薪。", "亭長聞名不識面，豈知明府是何人。"]'),
('51a2aff2-dacd-47f8-a6ae-0c71ee029416','村舍七首  其二','陸游','宋','宋诗','song-poetry','','[]','鷄鳴犬吠相聞地，穴處巢居上古風。',32,'全唐诗/poet.song.136000.json','["鷄鳴犬吠相聞地，穴處巢居上古風。", "飽飯不爲明日慮，酣歌便過百年中。"]'),
('a91abd03-3459-4949-8ac0-dd4cc6e2f22e','村舍七首  其三','陸游','宋','宋诗','song-poetry','','[]','露草乾時兒牧羊，朝日出時女采桑。',32,'全唐诗/poet.song.136000.json','["露草乾時兒牧羊，朝日出時女采桑。", "一床絮被千萬足，不解城中有許忙。"]'),
('83975a54-67f8-454e-a43c-953331214ac0','村舍七首  其四','陸游','宋','宋诗','song-poetry','','[]','山高正對燒畬火，溪近時聞戽水聲。',32,'全唐诗/poet.song.136000.json','["山高正對燒畬火，溪近時聞戽水聲。", "破屋已斜猶可住，老牛雖瘠尚能耕。"]'),
('94de5e6b-d950-49a7-b453-8818cac34f08','村舍七首  其五','陸游','宋','宋诗','song-poetry','','[]','莫笑山家拙治生，正緣亦足得身輕。',32,'全唐诗/poet.song.136000.json','["莫笑山家拙治生，正緣亦足得身輕。", "滿爐葑火渾家暖，一碗松肪徹夜明。"]'),
('f7a4f7f4-0f43-412d-912e-f4818d95c347','村舍七首  其六','陸游','宋','宋诗','song-poetry','','[]','故絮五更偏覺冷，薄糜未午已先饑。',32,'全唐诗/poet.song.136000.json','["故絮五更偏覺冷，薄糜未午已先饑。", "誰知人不堪憂處，正是降魔奏凱時。"]'),
('dc624772-b6c9-4e7d-90d2-24a6b3528a67','村舍七首  其七','陸游','宋','宋诗','song-poetry','','[]','氣全自可忘憂患，心動安能敵死生。',32,'全唐诗/poet.song.136000.json','["氣全自可忘憂患，心動安能敵死生。", "若論老人真受用，已多稗飯與藜羹。"]'),
('8740eae8-24d5-4569-a7d1-f8b27c9a36dc','登山西望有懷季長','陸游','宋','宋诗','song-poetry','','[]','行年垂九十，舉世少輩行。',168,'全唐诗/poet.song.136000.json','["行年垂九十，舉世少輩行。", "敢言貧非病，要是老益壯。", "平時懶書疏，有答未始倡。", "張卿獨所敬，夙昔推直諒。", "迹雖隔吳蜀，相憶每慘愴。", "使者交道中，萬里問亡恙。", "忽焉奉赴告，斯文豈將喪。", "腰絰不撫棺，執紼不會葬。", "送子岷山下，想見車百兩。", "我徒哭寢門，泪盡氣塞吭。", "年雖不耄期，仕誰不將相。", "神明司禍福，于職豈亦曠。", "霜風九月初，憑高極西望。", "江原在何許，安得鏟疊嶂。"]'),
('57cee3b8-42a2-4666-9018-483b320624e6','山行','陸游','宋','宋诗','song-poetry','','[]','五尺桄榔杖，二寸栟櫚冠。',72,'全唐诗/poet.song.136000.json','["五尺桄榔杖，二寸栟櫚冠。", "往來山谷中，髮白面渥丹。", "初非乳石力，所得懷抱寬。", "入寺不尋僧，自愛松風寒。", "松風晚少靜，我意殊未闌。", "却尋歸村路，白石明青灘。"]'),
('21554815-e7ad-40bf-b150-826985ba3e05','二樂','陸游','宋','宋诗','song-poetry','','[]','遊山恨不遠，讀書恨不博。',72,'全唐诗/poet.song.136000.json','["遊山恨不遠，讀書恨不博。", "天下多名山，何處無芒屩。", "束書飽蠹魚，於汝寧不怍。", "日月如過燒，老病將何若。", "眼猶急開卷，足尚供尋壑。", "少勞君勿辭，是中有真樂。"]'),
('b2ccff5d-3040-4a12-b4df-8ac0cf3d04a0','村女','陸游','宋','宋诗','song-poetry','','[]','白襦女兒繫青裙，東家西家世通婚。',32,'全唐诗/poet.song.136000.json','["白襦女兒繫青裙，東家西家世通婚。", "采桑餉飯無百步，至老何曾識別村。"]'),
('56c57325-59c0-4a37-920b-ad27020f2b8a','示子遹','陸游','宋','宋诗','song-poetry','','[]','我初學詩日，但欲工藻繪。',96,'全唐诗/poet.song.136000.json','["我初學詩日，但欲工藻繪。", "中年始少悟，漸若窺宏大。", "怪奇亦間出，如石漱湍瀨。", "數仞李杜牆，常恨欠領會。", "元白纔倚門，溫李真自鄶。", "正令筆扛鼎，亦未造三昧。", "詩爲六藝一，豈用資狡獪。", "汝果欲學詩，工夫在詩外。"]'),
('18febca3-7c3b-42ea-b1b5-e44bbfbcab42','聞新雁有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','才本無多老更疏，功名已負此心初。',32,'全唐诗/poet.song.136000.json','["才本無多老更疏，功名已負此心初。", "鏡湖夜半聞新雁，自起吹燈讀漢書。"]'),
('6b2fca45-8c84-4cce-943a-0ade36252594','聞新雁有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','新雁南來片影孤，冷雲深處宿菰蘆。',32,'全唐诗/poet.song.136000.json','["新雁南來片影孤，冷雲深處宿菰蘆。", "不知湘水巴陵路，曾記漁陽上谷無。"]'),
('8b544781-a26f-4f39-903a-9102e9b3b850','山村獨酌','陸游','宋','宋诗','song-poetry','','[]','腰劍如今不換牛，固應萬事一時休。',64,'全唐诗/poet.song.136000.json','["腰劍如今不換牛，固應萬事一時休。", "孤舟慣作瀟湘夢，駿馬寧思鄠杜遊。", "毀譽要須千載定，功名已向隔生求。", "石帆山下秋風晚，買酒看雲自獻酬。"]'),
('94e1e725-ef51-4b34-80d6-1457be076285','小園獨酌','陸游','宋','宋诗','song-poetry','','[]','橫林搖落弄微丹，深院蕭條作小寒。',64,'全唐诗/poet.song.136000.json','["橫林搖落弄微丹，深院蕭條作小寒。", "秋氣已高殊可喜，老懷多感自無歡。", "鹿初離母斑猶淺，橘乍經霜味尚酸。", "小酌一卮幽興足，豈須落佩與頹冠。"]'),
('a0510a95-5306-4832-897e-b1016b0ab7dc','秋思四首  其一','陸游','宋','宋诗','song-poetry','','[]','湖邊一夜霜，庭樹無秋聲。',48,'全唐诗/poet.song.136000.json','["湖邊一夜霜，庭樹無秋聲。", "懶不近筆硯，何以紓幽情。", "但有一睡耳，展轉無由成。", "起擁地爐暖，坐待天窗明。"]'),
('638e4767-9fb8-4981-80c0-e32ce05df138','秋思四首  其二','陸游','宋','宋诗','song-poetry','','[]','弊衣但故絮，糲食惟黄齏。',48,'全唐诗/poet.song.136000.json','["弊衣但故絮，糲食惟黄齏。", "餘年如登山，步步勤攀躋。", "從子念寂寞，千里致鹿麑。", "秋風石帆下，伴我扶青藜。"]'),
('19f5a92b-0c7c-4a83-900b-e1b36aca7a36','秋思四首  其三','陸游','宋','宋诗','song-poetry','','[]','稽山九十翁，病起無氣力。',48,'全唐诗/poet.song.136000.json','["稽山九十翁，病起無氣力。", "擁杖牧鷄豚，乃是老人職。", "一杯芋糝羹，孫子喚翁食。", "既飽負朝陽，自愧爾何德。"]'),
('6bff337e-e58d-4010-8847-453f540beeb5','秋思四首  其四','陸游','宋','宋诗','song-poetry','','[]','今日鵲噪簷，邢趙別我西。',48,'全唐诗/poet.song.136000.json','["今日鵲噪簷，邢趙別我西。", "老懷易感慨，近別亦慘凄。", "自我卧孤村，海內無輪蹄。", "垂虹秋愈佳，不得同裝賫。"]'),
('c82f6429-8b05-4195-a30d-4e12a905c704','覽鏡','陸游','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','鏡中老翁誰，非復少年我。',120,'全唐诗/poet.song.136000.json','["鏡中老翁誰，非復少年我。", "誦書如布穀，拈出無一可。", "又非富貴逼，棄去自不果。", "無功博一飽，有罪當萬坐。", "老境最堪笑，作計日益左。", "正似鳩拙巢，不及蠶自裹。", "霜寒衣未贖，瑟縮附殘火。", "作詩數十年，所得良瑣瑣。", "弱松困蔓纏，何日見磊砢。", "洞庭可遠遊，秋風思捩柁。"]'),
('fa4ec627-d2e9-4f70-be2e-006745cf31f8','雨晴','陸游','宋','宋诗','song-poetry','','[]','小雨初增氣慘凄，新晴差解病沉迷。',64,'全唐诗/poet.song.136000.json','["小雨初增氣慘凄，新晴差解病沉迷。", "虛廊靜院聽松籟，細草甘泉養鹿麛。", "寒靄細分山遠近，野歌相應路高低。", "孰知倦客蕭然意，水品茶經手自携。"]'),
('3d8e3625-b668-4378-97ed-f44322970889','秋盡自遣二首  其一','陸游','宋','宋诗','song-poetry','','[]','息駕江湖上，推移歲又殘。',48,'全唐诗/poet.song.136000.json','["息駕江湖上，推移歲又殘。", "雨添苔暈紫，霜染桕林丹。", "貧嘆耕疇薄，狂依禁網寬。", "遊山携一鉢，到寺即開單。"]'),
('094b687d-c05e-4656-aabc-18d86b93a2e4','秋盡自遣二首  其二','陸游','宋','宋诗','song-poetry','','[]','老健非頤攝，羈窮爲折除。',48,'全唐诗/poet.song.136000.json','["老健非頤攝，羈窮爲折除。", "人情看已慣，身在不論餘。", "席下錢雖盡，瓶中粟有儲。", "行歌混樵牧，吾計未全疏。"]'),
('e692a95f-166d-4ffb-bf4e-8717a3d122de','晝卧','陸游','宋','宋诗','song-poetry','','[]','我意殊昏然，一日三就枕。',96,'全唐诗/poet.song.136000.json','["我意殊昏然，一日三就枕。", "目前幸未病，病勢亦凜凜。", "偶拈一卷讀，美若鳩食葚。", "雖云嗜好篤，自計亦已審。", "聖門未能窺，詎敢希在寢。", "所求養根原，常恐躐階品。", "死期誠已迫，尚可支數稔。", "藨蔉不廢功，吾其享高廩。"]'),
('f10ce24c-6225-4fcb-9f19-5c588f4e125c','獨坐','陸游','宋','宋诗','song-poetry','','[]','博山香霧散馡馡，袖手何妨靜掩扉。',64,'全唐诗/poet.song.136000.json','["博山香霧散馡馡，袖手何妨靜掩扉。", "六十年前故人盡，八千里外寄書稀。", "昨朝送客桐江去，今日逢僧剡縣歸。", "欲作小詩還復懶，海鷗與我兩忘機。"]'),
('e5101f29-c583-493d-9a1c-6f289b09586c','書感','陸游','宋','宋诗','song-poetry','','[]','衰顔非復昔年朱，幾過黄公舊酒壚。',64,'全唐诗/poet.song.136000.json','["衰顔非復昔年朱，幾過黄公舊酒壚。", "成敗只堪三太息，是非終付一胡盧。", "連天烟草迷歸夢，動地風波歷畏途。", "辛苦一生成底事，躬耕猶得補東隅。"]'),
('cce9a471-cb5a-4650-b1cd-51f8986a6baa','舟中夜賦','陸游','宋','宋诗','song-poetry','','[]','問天乞得不貲身，常作東阡北陌人。',64,'全唐诗/poet.song.136000.json','["問天乞得不貲身，常作東阡北陌人。", "買酒不澆胸礌磈，憂時空覺膽輪囷。", "寓居尚復能栽竹，羈宦懸知正憶蓴。", "那似石帆山下客，釣船載月泊烟津。"]'),
('1ab534c3-420b-4800-b79e-685f27cab358','舍傍晚步二首  其一','陸游','宋','宋诗','song-poetry','','[]','蒲團初起定，藤杖偶閑行。',48,'全唐诗/poet.song.136000.json','["蒲團初起定，藤杖偶閑行。", "鳥語如相命，魚浮忽自驚。", "麥苗經雨綠，楓葉得霜頳。", "野老淳風在，悠然不送迎。"]'),
('d8a626d1-acda-43b3-8dfe-baee09b77e4c','舍傍晚步二首  其二','陸游','宋','宋诗','song-poetry','','[]','養疾便居僻，尋幽喜雨晴。',48,'全唐诗/poet.song.136000.json','["養疾便居僻，尋幽喜雨晴。", "偶因將鹿出，遂作放魚行。", "木落塔初見，潦收灘自生。", "霜清念遊衍，漸擬問山程。"]'),
('f0792583-ef6a-4e2d-93b6-5f074dec2c72','自詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','紛紛世態但堪悲，一念蕭然我亦奇。',64,'全唐诗/poet.song.136000.json','["紛紛世態但堪悲，一念蕭然我亦奇。", "醉裏猖狂醒自笑，夢中虛幻覺方知。", "江湖重複風波惡，齒髮凋零歲月馳。", "安得中原路如砥，渭川釣伴待多時。"]'),
('25b2fec8-e7f0-42a1-a9f0-94fb87c049f6','自詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','茅舍蕭條似寶坊，老人終日對爐香。',64,'全唐诗/poet.song.136000.json','["茅舍蕭條似寶坊，老人終日對爐香。", "學荒自笑身空在，祿盡誰知壽更長。", "陂水蘸堤常灧灧，麥苗覆塊已蒼蒼。", "經行更有欣然處，四野鉏耰滿夕陽。"]'),
('aee7b7d1-7a4c-45b3-9312-80428168ecdf','初冬','陸游','宋','宋诗','song-poetry','','[]','初冬常憶宴梁州，百炬如椽滿畫樓。',32,'全唐诗/poet.song.136000.json','["初冬常憶宴梁州，百炬如椽滿畫樓。", "三十七年猶未死，茅簷霜冷一燈幽。"]'),
('9b219350-5ce6-47c1-b12e-a4b48640f957','霜晴','陸游','宋','宋诗','song-poetry','','[]','萬瓦新霜白，一窗朝日晴。',48,'全唐诗/poet.song.136000.json','["萬瓦新霜白，一窗朝日晴。", "破裘身亦暖，細字眼猶明。", "耄喜譫諄語，衰常踸踔行。", "登封書不草，力穡報時平。"]'),
('eeda8ce8-411d-4a3c-8320-31ae04dfcf43','初寒','陸游','宋','宋诗','song-poetry','','[]','新雁來時歲又殘，丹楓數樹照江干。',64,'全唐诗/poet.song.136000.json','["新雁來時歲又殘，丹楓數樹照江干。", "前山雲起忽成暝，陋屋雨來初變寒。", "身退已收清禁夢，里居終出上恩寬。", "作詩老恨無奇思，時取囊中斷稿看。"]'),
('1680cf7b-675f-473f-8cda-e1857033c653','題傳神','陸游','宋','宋诗','song-poetry','','[]','溼雲生兩屨，細雨暗孤篷。',24,'全唐诗/poet.song.136000.json','["溼雲生兩屨，細雨暗孤篷。", "悔不桐江上，從初作釣翁。"]'),
('88d401b1-3624-4645-805b-c0a8171be532','書感','陸游','宋','宋诗','song-poetry','','[]','伐性戕生豈一端，暮年贏得是衰殘。',64,'全唐诗/poet.song.136000.json','["伐性戕生豈一端，暮年贏得是衰殘。", "齒牙零落畏大胾，毛髮蕭疏便小冠。", "惜日每驚新曆換，怯寒尚覺弊廬寬。", "華山阻絕岷山遠，安得冥鴻借羽翰。"]'),
('c4587c5d-b4be-4e9a-a095-6a4ed4e6acfe','宋都曹屢寄詩且督和答作此示之','陸游','宋','宋诗','song-poetry','','[]','古詩三千篇，刪取財十一。',120,'全唐诗/poet.song.136000.json','["古詩三千篇，刪取財十一。", "每讀先再拜，若聽清廟瑟。", "詩降爲楚騷，猶足中六律。", "天未喪斯文，杜老乃獨出。", "陵遲至元白，固已可憤疾。", "及觀晚唐作，令人欲焚筆。", "此風近復熾，隙穴始難窒。", "淫哇解移人，往往喪妙質。", "苦言告學者，切勿爲所怵。", "杭川必至海，爲道當擇術。"]'),
('2eea7e60-54f1-495d-b848-8c6602bad244','獨飲','陸游','宋','宋诗','song-poetry','','[]','肅肅霜風勁，蕭蕭木葉聲。',48,'全唐诗/poet.song.136000.json','["肅肅霜風勁，蕭蕭木葉聲。", "殘年如寄爾，冷坐太憎生。", "就市沽新釀，呼兒洗破觥。", "獨斟還獨醉，無月配長庚。"]'),
('382aa1d6-946d-4ac6-aaff-a1d66e88f202','簡湖中隠者','陸游','宋','宋诗','song-poetry','','[]','十里隔天鏡，一庵依翠屏。',48,'全唐诗/poet.song.136000.json','["十里隔天鏡，一庵依翠屏。", "甘泉勝牛乳，靈藥似人形。", "處處筇枝健，年年鬢色青。", "客星猶不作，肯應少微星。"]'),
('10c968db-4ab4-42d3-99a0-46e613863901','初冬雜詠八首  其一','陸游','宋','宋诗','song-poetry','','[]','重陽已過二十日，殘菊纔存三四枝。',32,'全唐诗/poet.song.136000.json','["重陽已過二十日，殘菊纔存三四枝。", "對酒插花君勿笑，從來不解入時宜。"]'),
('8ae91a6e-5196-48d0-8aac-a2e91afb8229','初冬雜詠八首  其二','陸游','宋','宋诗','song-poetry','','[]','古壽書來言得婿，東陽人到報生孫。',32,'全唐诗/poet.song.136000.json','["古壽書來言得婿，東陽人到報生孫。", "一家三處俱强健，且撥閑愁近酒尊。"]'),
('60f30b13-9e97-4f92-be80-e33ac4f980a7','初冬雜詠八首  其三','陸游','宋','宋诗','song-poetry','','[]','兒時愛書百事廢，飯冷胾乾呼不來。',32,'全唐诗/poet.song.136000.json','["兒時愛書百事廢，飯冷胾乾呼不來。", "一生被誤終未醒，老作蠹魚吁可哀。"]'),
('e16cf0ab-2105-40b1-beae-40baacfb6865','初冬雜詠八首  其四','陸游','宋','宋诗','song-poetry','','[]','微風蹙水靴文浪，薄日烘雲卵色天。',32,'全唐诗/poet.song.136000.json','["微風蹙水靴文浪，薄日烘雲卵色天。", "但恨世間閑客少，江湖底處欠漁船。"]'),
('db221157-94fe-4421-a2c3-8f816e443f3c','初冬雜詠八首  其五','陸游','宋','宋诗','song-poetry','','[]','書生本欲輩莘渭，蹭蹬乃去爲詩人。',32,'全唐诗/poet.song.136000.json','["書生本欲輩莘渭，蹭蹬乃去爲詩人。", "囊中略有七千首，不負百年風月身。"]'),
('ba4fa6cd-2927-4e95-a850-e82eb0f9751e','初冬雜詠八首  其六','陸游','宋','宋诗','song-poetry','','[]','俗緣已斷寧容續，幽事雖多不厭增。',32,'全唐诗/poet.song.136000.json','["俗緣已斷寧容續，幽事雖多不厭增。", "折簡迎醫看病鹿，舂粳炊飯供遊僧。"]'),
('8a2567b5-5a66-4acc-99a6-65f9ce9cbdcc','初冬雜詠八首  其七','陸游','宋','宋诗','song-poetry','','[]','夜窗父子共煎茶，一點青燈冷結花。',32,'全唐诗/poet.song.136000.json','["夜窗父子共煎茶，一點青燈冷結花。", "村落盜清無犬吠，園林月上有啼鴉。"]'),
('5c4c46c8-76bd-4dac-90c3-1b769407052b','初冬雜詠八首  其八','陸游','宋','宋诗','song-poetry','','[]','老去胸中百事真，同遊無復白頭新。',32,'全唐诗/poet.song.136000.json','["老去胸中百事真，同遊無復白頭新。", "鵲從熟後頻分食，鹿漸馴來不避人。"]'),
('7f396eec-1ec2-4e7a-b300-6622132374a6','老嘆','陸游','宋','宋诗','song-poetry','','[]','齒髮衰殘久退休，衡茅荒寂更禁秋。',64,'全唐诗/poet.song.136000.json','["齒髮衰殘久退休，衡茅荒寂更禁秋。", "一無用力身猶倦，百不關心夢亦愁。", "遠浦卧看鳬泛泛，深林時聽鹿呦呦。", "天台日有遊僧過，白朮黄精不待求。"]'),
('000a709d-802d-49c4-b773-007fa1ab8f93','小園','陸游','宋','宋诗','song-poetry','','[]','誰爲閑愁撥不開，小園也復有池臺。',64,'全唐诗/poet.song.136000.json','["誰爲閑愁撥不開，小園也復有池臺。", "清泉白石皆吾友，綠李黄梅盡手栽。", "衝雨茭鷄時上下，近人栗鼠不驚猜。", "自憐兩屨猶輕捷，不待兒扶日日來。"]'),
('40911280-f2b2-43af-98af-9832486ac90a','冬夜思里中多不濟者愴然有感','陸游','宋','宋诗','song-poetry','','[]','大耋年光病日侵，久辭微祿卧山林。',64,'全唐诗/poet.song.136000.json','["大耋年光病日侵，久辭微祿卧山林。", "雖無嘆老嗟卑語，猶有哀窮悼屈心。", "力薄不能推一飯，義深常願散千金。", "夜闌感慨殘燈下，皎皎孤懷帝所臨。"]'),
('274e252f-8d4e-4612-a079-cb807ea0336e','宿近村','陸游','宋','宋诗','song-poetry','','[]','病齒漂浮短髮稀，此身猶墮亂書圍。',64,'全唐诗/poet.song.136000.json','["病齒漂浮短髮稀，此身猶墮亂書圍。", "邯鄲倦枕晨炊熟，昌谷空囊晚醉歸。", "久困厭從人乞貸，力耕頻遇歲凶饑。", "行年九十窮彌甚，旅舍燈前自綻衣。"]'),
('8ee796a2-5154-44bc-bdbb-8817d0acebd5','梅村野人家小憩','陸游','宋','宋诗','song-poetry','','[]','正遣清詩覓菊栽，穿雲涉水又尋梅。',64,'全唐诗/poet.song.136000.json','["正遣清詩覓菊栽，穿雲涉水又尋梅。", "萬牛不挽新愁去，一鳥還驚午夢回。", "老愧逢人說幽憤，窮能隨事學低摧。", "江邊漂母何爲者，無食王孫未易哀。"]'),
('5833c57b-438f-4044-b948-bd88fe6eb7dd','寄陳伯予主簿','陸游','宋','宋诗','song-poetry','','[]','今年閏餘時令早，十月霜風吹客倒。',128,'全唐诗/poet.song.136000.json','["今年閏餘時令早，十月霜風吹客倒。", "老夫畏寒不出門，數步鄰家迹如掃。", "此時陳子獨何勇，饑僮瘦馬長安道。", "絕知涵養與人別，吐氣如虹失衰老。", "孟軻浩然正應爾，豈比區區養梨棗。", "萬鍾于子本何加，一官未免從人討。", "世誰不達子獨窮，熟念令人惡懷抱。", "石渠天祿正須才，往乞揚雄太玄草。"]'),
('f0dc1737-42b4-46f2-9a33-56b953f9338f','夜坐憶剡溪','陸游','宋','宋诗','song-poetry','','[]','早睡苦夜長，晚睡意復倦。',72,'全唐诗/poet.song.136000.json','["早睡苦夜長，晚睡意復倦。", "斂膝傍殘燈，拭眥展書卷。", "時時搔短髮，稍稍磨凍硯。", "更闌月入戶，皎若舒白練。", "便思泛樵風，次第入剡縣。", "名山如高人，豈可久不見。"]'),
('bcbccc42-9ae1-4387-b2f6-c6f9c53913f9','道上見村民聚飲','陸游','宋','宋诗','song-poetry','','[]','霜風利如割，霜葉凈如掃。',96,'全唐诗/poet.song.136000.json','["霜風利如割，霜葉凈如掃。", "正當十月時，我行山陰道。", "場功俱已畢，歡樂無壯老。", "野歌相和答，村鼓更擊考。", "市壚酒雖薄，群飲必醉倒。", "鷄豚治羹胾，魚鱉雜鮮薧。", "但願時太平，鄰里常相保。", "家家了租稅，春酒壽翁媼。"]'),
('8740ec8b-d869-4f0d-96ca-6b7376079e13','小江','陸游','宋','宋诗','song-poetry','','[]','出郭四十里，孟冬天尚和。',48,'全唐诗/poet.song.136000.json','["出郭四十里，孟冬天尚和。", "風生帆力健，木落月明多。", "小市人聲散，長橋炬火過。", "吾生幾來往，撫枕獨悲歌。"]'),
('5d467861-aff6-4efc-ad97-b8bdfd52d5f5','短歌行','陸游','宋','宋诗','song-poetry','','[]','富貴得意如登天，自計一跌理不全。',131,'全唐诗/poet.song.136000.json','["富貴得意如登天，自計一跌理不全。", "晝食忘味夜費眠，渠過一日如一年。", "春蠶得衣耕得食，農功初成各休息。", "賣酒壚邊紛鼓笛，我過一年如一日。", "二者求兼勢安可，與我周旋寧作我。", "春城桃李豈不妍，雪澗未妨松磊砢。", "人生禍福難遽論，廟犧烏得爲孤豚。", "君不見獵徒父子牽黄犬，歲歲秋風下蔡門。"]'),
('cd217a6c-1230-4f15-86d5-bb57de440f3f','初寒','陸游','宋','宋诗','song-poetry','','[]','重雲蔽白日，陂港日夜涸。',72,'全唐诗/poet.song.136000.json','["重雲蔽白日，陂港日夜涸。", "秋風纔幾時，已見霜雪作。", "人生各有分，豈必衣狐狢。", "吳中冬蔬茂，盤筯不寂寞。", "摶泥治牆屋，伐篠補籬落。", "薄酒亦醉人，問子胡不樂。"]'),
('ee18ca7b-0405-4907-88fc-1e08ef1427ef','對鏡','陸游','宋','宋诗','song-poetry','','[]','鏡中衰顔失敷腴，綠鬢已作霜蓬枯。',96,'全唐诗/poet.song.136000.json','["鏡中衰顔失敷腴，綠鬢已作霜蓬枯。", "兩肩聳聳似山字，曳杖更有蠻童扶。", "自驚何以致此老，亟欲修敬問起居。", "徐徐熟視乃大笑，但記昔我忘今吾。", "今吾雖憊頗神王，飛仙正可折簡呼。", "遠遊縱未從谿父，醉眼猶能隘具區。"]'),
('7841c512-9575-4c02-afee-fca4e14454ed','書劍','陸游','宋','宋诗','song-poetry','','[]','書劍當年遍兩川，歸來垂釣鏡湖邊。',64,'全唐诗/poet.song.136000.json','["書劍當年遍兩川，歸來垂釣鏡湖邊。", "老皆有死豈獨我，士固多貧寧怨天。", "物外勝遊携鶴去，琴中絕譜就僧傳。", "莫言白首詩才盡，讀罷猶能意爽然。"]'),
('ae859d56-ed87-4bfa-a31e-55cbf82bddc2','城南道中有感','陸游','宋','宋诗','song-poetry','','[]','行李蕭然一束書，城南觸目更愁予。',64,'全唐诗/poet.song.136000.json','["行李蕭然一束書，城南觸目更愁予。", "市門乞食僧持鉢，關路哦詩客跨馿。", "殘髮無多真已矣，名山未去獨何歟。", "芒鞋可買身猶健，紅樹青霜十月初。"]'),
('1d1a6c75-a3fd-42ef-aa91-8955430e8447','寄子虡兼示子遹','陸游','宋','宋诗','song-poetry','','[]','書生賦命艱，舉步得憂患。',180,'全唐诗/poet.song.136000.json','["書生賦命艱，舉步得憂患。", "敢論得意事，一笑亦有限。", "南征度閩嶺，西戍歷蜀棧。", "吳江聽唳鶴，淮浦送歸雁。", "歸來耕故山，暮雨泥沒骭。", "群鴉下空陂，黄犢鳴絕岸。", "索飯閔兒啼，乞墦虞妾覸。", "一裘三十年，破裂不受綻。", "欲添一把茅，百計亦未辦。", "大兒急親養，辛苦就遠宦。", "間出冒虜塵，短甲中夜擐。", "小兒奉親歡，野果采溪澗。", "勉使就微祿，未對涕先潸。", "觀汝兄弟意，豈復厭藜莧。", "兄歸弟不出，定省同夜旦。"]'),
('e4fcf3af-480d-406d-91dc-2c4880adaf24','一年老一年','陸游','宋','宋诗','song-poetry','','[]','一年老一年，一日衰一日。',88,'全唐诗/poet.song.136000.json','["一年老一年，一日衰一日。", "譬如東周亡，豈復須大疾。", "懶惰已廢書冊久，病來亦復疏杯酒。", "軔車小住固自佳，拂袖便行亦何有。", "下床擁火暖有餘，鹹豆數粒粥一盂。", "平生常笑愚公愚，欲栽墮齒染白鬚。"]'),
('faad69cc-7c07-4bcb-bd93-132c9139386b','自東岡繚出舍北','陸游','宋','宋诗','song-poetry','','[]','年光豈不好，老境獨無歡。',48,'全唐诗/poet.song.136000.json','["年光豈不好，老境獨無歡。", "百步未爲遠，一尊聊自寬。", "澤枯波尚綠，霜薄葉初丹。", "矯首問來雁，中原應苦寒。"]'),
('6e7ea653-ee36-4564-8833-e2d876da060e','有客','陸游','宋','宋诗','song-poetry','','[]','有客南山至，相携飯野亭。',48,'全唐诗/poet.song.136000.json','["有客南山至，相携飯野亭。", "傾籃魚白白，出籠菜青青。", "米滑溪舂碓，醅渾草塞瓶。", "從今同保社，日醉不須醒。"]'),
('920f163a-39fa-488c-bce7-30bace55d66c','陳伯予見過喜予强健戲作','陸游','宋','宋诗','song-poetry','','[]','寒無氈坐甑生塵，此老年來乃爾貧。',32,'全唐诗/poet.song.136000.json','["寒無氈坐甑生塵，此老年來乃爾貧。", "兩頰如丹君會否，胸中原自有陽春。"]'),
('ea7cb290-f220-4ece-b533-7ab023d42324','東陽郭希呂呂子益送酒','陸游','宋','宋诗','song-poetry','','[]','山崦尋香得早梅，園丁又報水仙開。',32,'全唐诗/poet.song.136000.json','["山崦尋香得早梅，園丁又報水仙開。", "獨醒坐看兒孫醉，虛負東陽酒擔來。"]'),
('a6c38983-bb17-49ab-8251-4e8021b75791','夜坐','陸游','宋','宋诗','song-poetry','','[]','家家績火夜深明，處處新畬雨後耕。',32,'全唐诗/poet.song.136000.json','["家家績火夜深明，處處新畬雨後耕。", "常愧老身無一事，地爐堅坐聽風聲。"]'),
('f04d0da8-29e3-4e9d-8410-9a6a6249c02c','兩日意殊不懌作短歌自遣','陸游','宋','宋诗','song-poetry','','[]','一月得笑纔四五，十事敗意常八九。',128,'全唐诗/poet.song.136000.json','["一月得笑纔四五，十事敗意常八九。", "國中謾說無雙士，天下元無第一手。", "平生愛酒恨小戶，半世爲文真弊帚。", "劫灰處處吊興亡，宿草年年哭交友。", "君看丈夫得意時，大冠如箕印如斗。", "一朝棄去豈復論，衣破何妨露雙肘。", "有時采藥二室間，亦或釣魚五湖口。", "死來萬古一熟眠，安用虛名傳不朽。"]'),
('d1747524-e3d8-46ca-982e-40efc095fe59','戲書日用事','陸游','宋','宋诗','song-poetry','','[]','衰病時時作，閑愁日日生。',48,'全唐诗/poet.song.136000.json','["衰病時時作，閑愁日日生。", "寒添沽酒興，困喜磑茶聲。", "琴廢還重理，詩成更細評。", "殘年那望進，且復暢幽情。"]'),
('2f01b7b1-bad1-4005-baf0-fb583960d57e','獨立','陸游','宋','宋诗','song-poetry','','[]','上書不上登封書，乘車但乘下澤車。',32,'全唐诗/poet.song.136000.json','["上書不上登封書，乘車但乘下澤車。", "夕陽獨立衡門外，閑看村童學釣魚。"]'),
('a9b08897-97c9-4fc2-8037-a9106857438e','夢中江行過鄉豪家賦詩二首既覺猶歷歷能記也  其一','陸游','宋','宋诗','song-poetry','','[]','築屋傍江皋，牆垣締結牢。',48,'全唐诗/poet.song.136000.json','["築屋傍江皋，牆垣締結牢。", "深門蔭楊柳，高架引蒲萄。", "黍酒歡迎客，麻衫旋束絳。", "兒孫勿遊惰，常念起家勞。"]'),
('9fc0851a-3a7d-499e-876f-3d676e9b8032','夢中江行過鄉豪家賦詩二首既覺猶歷歷能記也  其二','陸游','宋','宋诗','song-poetry','','[]','蒲席乘風健，江潮带雨渾。',48,'全唐诗/poet.song.136000.json','["蒲席乘風健，江潮带雨渾。", "樹餘梢纜迹，崖有刺篙痕。", "酒酹湘君廟，歌招屈子魂。", "客途嗟草草，無處采芳蓀。"]'),
('a8b397de-3f50-482a-b092-56acd973e29e','病中夜思','陸游','宋','宋诗','song-poetry','','[]','一病輒兼旬，百憂集雙鬢。',72,'全唐诗/poet.song.136000.json','["一病輒兼旬，百憂集雙鬢。", "藥裹堆床滿，生意垂欲盡。", "時聞雀翻更，頻看燈落燼。", "平生學六經，白首頗自信。", "拳拳服仁義，念念去驕吝。", "所覬未死間，猶有分寸進。"]'),
('66225903-adc5-4a45-a0a7-6da34b5a5e85','得子虡書言明春可歸','陸游','宋','宋诗','song-poetry','','[]','白首相依飽蕨薇，吾家父子古來稀。',32,'全唐诗/poet.song.136000.json','["白首相依飽蕨薇，吾家父子古來稀。", "春秧出水柔桑綠，正是農時望汝歸。"]'),
('a0734c40-afbe-46f8-a6e4-9ce17f81c5c7','雜賦十二首  其一','陸游','宋','宋诗','song-poetry','','[]','地爐夜熱麻䕸暖，瓦鬴晨烹豆粥香。',32,'全唐诗/poet.song.136000.json','["地爐夜熱麻䕸暖，瓦鬴晨烹豆粥香。", "不是有心輕富貴，從來吾亦愛吾鄉。"]'),
('3a0e1bef-1a34-41c8-9bfe-c9b932554a71','雜賦十二首  其二','陸游','宋','宋诗','song-poetry','','[]','病叟胸中一物無，夢遊信脚到華胥。',32,'全唐诗/poet.song.136000.json','["病叟胸中一物無，夢遊信脚到華胥。", "覺來忽見天窗白，短髮蕭蕭起自梳。"]'),
('608d59f2-55d8-494c-9606-1bb03c9080c2','雜賦十二首  其三','陸游','宋','宋诗','song-poetry','','[]','終日纔堪米一升，生涯略似草庵僧。',32,'全唐诗/poet.song.136000.json','["終日纔堪米一升，生涯略似草庵僧。", "溼薪不管晨炊晚，留得松肪代夜燈。"]'),
('b2a51d4f-8232-45e9-a5c8-cd6a2aa07957','雜賦十二首  其四','陸游','宋','宋诗','song-poetry','','[]','出門信步作閑遊，野廟村坊到處留。',32,'全唐诗/poet.song.136000.json','["出門信步作閑遊，野廟村坊到處留。", "每伴樵夫嘗半舍，更隨牧豎采沿溝。"]'),
('737c05e6-37d5-4b9c-8221-983822d0a259','雜賦十二首  其五','陸游','宋','宋诗','song-poetry','','[]','體不佳時看周易，酒痛飲後讀離騷。',32,'全唐诗/poet.song.136000.json','["體不佳時看周易，酒痛飲後讀離騷。", "騎馿太華三峰雪，鼓棹錢塘八月濤。"]'),
('f68e9235-5a2a-4cf5-a82d-7097a05971df','雜賦十二首  其六','陸游','宋','宋诗','song-poetry','','[]','昔人莽莽荒丘裏，陳迹紛紛朽簡中。',32,'全唐诗/poet.song.136000.json','["昔人莽莽荒丘裏，陳迹紛紛朽簡中。", "畢竟是非誰辨得，舉杯吾欲問虛空。"]'),
('f324c889-768b-4e63-9105-101aa5618671','雜賦十二首  其七','陸游','宋','宋诗','song-poetry','','[]','百億須彌理固有，八九雲夢何足吞。',32,'全唐诗/poet.song.136000.json','["百億須彌理固有，八九雲夢何足吞。", "天下廣居君識否，一間茆屋寄孤村。"]'),
('617c7102-0166-463b-94fc-2aafc7a588aa','雜賦十二首  其八','陸游','宋','宋诗','song-poetry','','[]','夢裏曾作南柯守，少時元是東陵侯。',32,'全唐诗/poet.song.136000.json','["夢裏曾作南柯守，少時元是東陵侯。", "今朝半醉歸草市，指點青帘上酒樓。"]'),
('231e1b54-47c0-4207-a267-56c8f096a1b0','雜賦十二首  其九','陸游','宋','宋诗','song-poetry','','[]','七十八十古來稀，行年九十固應衰。',32,'全唐诗/poet.song.136000.json','["七十八十古來稀，行年九十固應衰。", "已興工部耳聾嘆，更和文公齒落詩。"]'),
('dbbc522b-c46f-4b1d-b893-b4ecf405e686','雜賦十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','中年畏病杯行淺，晚歲修真食禁多。',32,'全唐诗/poet.song.136000.json','["中年畏病杯行淺，晚歲修真食禁多。", "謝客杜門殊省事，一盂香飯養天和。"]'),
('426e9a37-f9a6-4a8a-9cd8-ed5f1a05b64a','雜賦十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','齊民讓畔不爭桑，和氣橫流歲自穰。',32,'全唐诗/poet.song.136000.json','["齊民讓畔不爭桑，和氣橫流歲自穰。", "君看三山百家聚，更無一壟有遺蝗。"]'),
('a0e84f47-68b0-4111-a622-51e397e1239a','雜賦十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','得雨郊原已遍耕，東家西舍多逢迎。',32,'全唐诗/poet.song.136000.json','["得雨郊原已遍耕，東家西舍多逢迎。", "前山雲起樹無影，別浦潮生船有聲。"]'),
('87d465a3-1c33-4c5c-9e02-de70bcf2f901','散懷','陸游','宋','宋诗','song-poetry','','[]','小疾便幽翳，孤懷抱鬰陶。',48,'全唐诗/poet.song.136000.json','["小疾便幽翳，孤懷抱鬰陶。", "遺文誦史漢，奇思探莊騷。", "談笑寬吟苦，經行慰作勞。", "東岡聊一往，突兀古臺高。"]'),
('be002450-2a55-4f86-9eba-1e9a1f8734ba','書壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','稻草高茨屋，繩樞窄作門。',48,'全唐诗/poet.song.136000.json','["稻草高茨屋，繩樞窄作門。", "漁樵皆結友，鄰曲自通婚。", "留客秋茶苦，醺人社酒渾。", "餘年尚有嘆，一飯亦君恩。"]'),
('95c6b21f-3334-4a19-9c05-89d23c89e05e','書壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','故里還初服，明恩念老農。',48,'全唐诗/poet.song.136000.json','["故里還初服，明恩念老農。", "方蒙鏡湖賜，又忝渭川封。", "炊粟猶支日，藏蔬可御冬。", "霜天病益減，高枕聽鄰鐘。"]'),
('e97c674d-13c0-40fc-8132-e057b215a31c','冬日齋中即事六首  其一','陸游','宋','宋诗','song-poetry','','[]','讀書雖所樂，置之固亦佳。',48,'全唐诗/poet.song.136000.json','["讀書雖所樂，置之固亦佳。", "燒香袖手坐，自足紓幽懷。", "我生本從人，豈願終不諧。", "其如定命何，生死一茆齋。"]'),
('6b75418f-de94-40d6-b030-b217d58b1df4','冬日齋中即事六首  其二','陸游','宋','宋诗','song-poetry','','[]','一帚常在傍，有暇即掃地。',48,'全唐诗/poet.song.136000.json','["一帚常在傍，有暇即掃地。", "既省課童奴，亦以平血氣。", "按摩與導引，雖善亦多事。", "不如掃地法，延年直差易。"]'),
('2e135f84-0d86-4d35-b9f8-93e70c897af5','冬日齋中即事六首  其三','陸游','宋','宋诗','song-poetry','','[]','夙興人尚默，衆鳥相語言。',48,'全唐诗/poet.song.136000.json','["夙興人尚默，衆鳥相語言。", "小語豈不可，何至爾啾喧。", "吾獨擁燎爐，宿火有餘溫。", "澹然以自適，喧寂何足論。"]'),
('9ea233ed-bd1f-4907-a0cc-3a99484757a1','冬日齋中即事六首  其四','陸游','宋','宋诗','song-poetry','','[]','詰朝澹無營，百事付童子。',48,'全唐诗/poet.song.136000.json','["詰朝澹無營，百事付童子。", "拂我架上書，注我硯中水。", "覓睡不復成，取衣乃徐起。", "卒歲如一朝，底處著慍喜。"]'),
('66af50f9-045b-4909-b736-aa35d3c0a5fc','冬日齋中即事六首  其五','陸游','宋','宋诗','song-poetry','','[]','我老苦寂寥，誰與娛晨暮。',48,'全唐诗/poet.song.136000.json','["我老苦寂寥，誰與娛晨暮。", "狸奴共茵席，鹿麑隨杖屨。", "歲薄食無餘，恨使鳥雀去。", "安得粟滿囷，作粥餽行路。"]'),
('cc5ac5d4-fde2-42dc-b3d9-8ea43d5cfaea','冬日齋中即事六首  其六','陸游','宋','宋诗','song-poetry','','[]','東園二畝地，重重作藩籬。',48,'全唐诗/poet.song.136000.json','["東園二畝地，重重作藩籬。", "我豈婦女哉，避客門不窺。", "要當盡徹去，來往無它歧。", "飯罷忌久坐，時須曳筇枝。"]'),
('d48d7352-1a48-481d-b3e5-8bd9c78c7899','冬日排悶二首  其一','陸游','宋','宋诗','song-poetry','','[]','老欲躬耕力弗强，但應賣藥似韓康。',64,'全唐诗/poet.song.136000.json','["老欲躬耕力弗强，但應賣藥似韓康。", "陳編時見古成敗，舊友不知今在亡。", "已返山林遺世事，尚憑詩酒答年光。", "此身自笑如稊米，加損寧能繫太倉。"]'),
('60702b69-0be2-4255-aea6-c9a53cdcd228','冬日排悶二首  其二','陸游','宋','宋诗','song-poetry','','[]','地爐微火伴寒灰，垂野江雲暝不開。',64,'全唐诗/poet.song.136000.json','["地爐微火伴寒灰，垂野江雲暝不開。", "欲睡手中書自墮，半酣窗外雪初來。", "渡頭照影聞征雁，籬角吹香得早梅。", "佛粥春盤俱不遠，離離斗柄欲東回。"]'),
('b57acbce-213e-41f0-9854-805d47590a43','法雲寺','陸游','宋','宋诗','song-poetry','','[]','勾踐舊國古會稽，南山擁郭分東西。',128,'全唐诗/poet.song.136000.json','["勾踐舊國古會稽，南山擁郭分東西。", "城門大路引繩直，西走百里皆平堤。", "客行欲曉到梅市，喔喔尚聽城中鷄。", "法雲古寺臨大澤，風皺百頃青玻璃。", "迎來送往此其地，素壁時見前人題。", "乖離會合浩莫計，歷觀名氏空含凄。", "山僧慣見爲客嘆，榮悴從來如夜旦。", "明年吾樓插天半，世事君須倚闌看。"]'),
('0a3e4862-1071-4083-86c0-668e41632cf9','自法雲歸','陸游','宋','宋诗','song-poetry','','[]','落日疏林數點鴉，青山闕處是吾家。',32,'全唐诗/poet.song.136000.json','["落日疏林數點鴉，青山闕處是吾家。", "歸來何事添幽致，小竈燈前自煮茶。"]'),
('41e4c4b6-5a00-4d15-a21f-9a2e2b4034f9','枯菊','陸游','宋','宋诗','song-poetry','','[]','龍山落帽未多時，陳迹依然使我悲。',32,'全唐诗/poet.song.136000.json','["龍山落帽未多時，陳迹依然使我悲。", "粲粲菊花何似好，階前惟見束枯枝。"]'),
('147836d8-ea4e-4426-94eb-e479b7048263','聞吳中米價甚貴二十韵','陸游','宋','宋诗','song-poetry','','[]','千錢得斗米，一斛當萬錢。',240,'全唐诗/poet.song.136000.json','["千錢得斗米，一斛當萬錢。", "嗟汝蚩蚩民，何恃以自全。", "我欲告父老，食爲汝之天。", "勿結迎神社，勿飾杭湖船。", "築室勿斲削，但取垣屋堅。", "婦女省釵澤，野粧何用妍。", "趨利常處薄，衆役常在前。", "歲時相勞苦，盛饌一豚肩。", "近市可致酒，雖薄亦醺然。", "切勿慕公卿，早朝妨熟眠。", "亦勿謀高貲，貪吏不汝憐。", "有負固吹毛，無罪亦株連。", "豈暇論曲直，梃繫如登僊。", "短褐與飯豆，溫飽可終年。", "草廬挂葦箔，乃可數世傳。", "朱門雖赫赫，變化如飛烟。", "爲農最得策，本無祿與權。", "時平自逸樂，奉牲祭其先。", "不幸有散徙，均爲寓民編。", "吾詩不足徵，請讀七月篇。"]'),
('b36fe9c6-db2d-41e9-8f22-c56b8d3c3191','寒夜偶懷壯遊書感','陸游','宋','宋诗','song-poetry','','[]','疇昔西遊萬里還，狂吟散落滿人間。',64,'全唐诗/poet.song.136000.json','["疇昔西遊萬里還，狂吟散落滿人間。", "買空綠水橋邊酒，看徧青城縣裏山。", "梅蕊疏疏春欲動，川雲漠漠雪猶慳。", "偶思五十年來事，顧影燈前自笑頑。"]'),
('123f458b-d48a-4c81-8393-7e9c32ae9072','夢曾文清公','陸游','宋','宋诗','song-poetry','','[]','有道真爲萬物宗，巉然使我嘆猶龍。',32,'全唐诗/poet.song.136000.json','["有道真爲萬物宗，巉然使我嘆猶龍。", "晨鷄底事驚殘夢，一夕清談恨未終。"]'),
('eb0a6c3b-6d2c-4d6a-9470-e867dc22d61d','睡覺','陸游','宋','宋诗','song-poetry','','[]','白日悠悠喜意平，夢中歷歷覺魂清。',32,'全唐诗/poet.song.136000.json','["白日悠悠喜意平，夢中歷歷覺魂清。", "覺時不落晨鷄後，靜待天窗一點明。"]'),
('7cc119ad-2149-4c92-8a0e-79827e19c862','湖邊小聚','陸游','宋','宋诗','song-poetry','','[]','小聚遠塵囂，淳風獨未澆。',48,'全唐诗/poet.song.136000.json','["小聚遠塵囂，淳風獨未澆。", "鳴機燈煜煜，飲犢雨蕭蕭。", "異味常交致，新醪亦苦邀。", "人間交道絕，令我慕漁樵。"]'),
('c645a2aa-055a-46ed-a51d-306462698c96','雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','秋冬久不雨，氣濁喜雲生。',48,'全唐诗/poet.song.136000.json','["秋冬久不雨，氣濁喜雲生。", "麥壟崇朝潤，茆簷徹夜聲。", "初來斷幽徑，漸密雜疏更。", "頼有牆陰薺，離離已可烹。"]'),
('e9dc48a6-85f9-4a64-a894-d1c660eb7751','雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','薄晚初沾灑，清晨更慘凄。',48,'全唐诗/poet.song.136000.json','["薄晚初沾灑，清晨更慘凄。", "魚寒拋餌去，鴉溼就簷栖。", "幽澗濺濺溜，長堤淺淺泥。", "一杯持自賀，吾事在鋤犁。"]'),
('2e2e340a-c6ae-45e5-8301-f23b64ca9401','雨後快晴步至湖塘','陸游','宋','宋诗','song-poetry','','[]','齒豁從教道字訛，負薪陌上且行歌。',64,'全唐诗/poet.song.136000.json','["齒豁從教道字訛，負薪陌上且行歌。", "古人亦自逢時少，吾輩何疑忤俗多。", "山掃黛痕如尚溼，湖開鏡面似新磨。", "亦知大有掀髯處，無奈西流白日何。"]'),
('15b4e2eb-bcca-4da5-b4fa-91232c6fc516','兩日寒雨作雪不成夜忽大雨遂晴','陸游','宋','宋诗','song-poetry','','[]','折木翻濤一夜風，浮雲吹盡日行空。',32,'全唐诗/poet.song.136000.json','["折木翻濤一夜風，浮雲吹盡日行空。", "天公豈是真慳雪，三白留來付臘中。"]'),
('b7a5cde2-6864-4d2c-be39-00538bb4e653','歲窮','陸游','宋','宋诗','song-poetry','','[]','困阨身如寄，推遷歲忽窮。',48,'全唐诗/poet.song.136000.json','["困阨身如寄，推遷歲忽窮。", "百年均昨夢，萬古一飛鴻。", "夜甕鳴春酒，晨畦擷晚菘。", "屬饜童子笑，便腹負吾翁。"]'),
('3bef5b37-bb91-4a81-a585-b0070fd9e142','凍坐','陸游','宋','宋诗','song-poetry','','[]','湖海凄凉地，風霜慘淡天。',24,'全唐诗/poet.song.136000.json','["湖海凄凉地，風霜慘淡天。", "吾其去道近，無酒亦陶然。"]'),
('f4c2d90b-cb49-4ab9-be5d-9de08768b5a3','古意二首  其一','陸游','宋','宋诗','song-poetry','','[]','千金募戰士，萬里築長城。',24,'全唐诗/poet.song.136000.json','["千金募戰士，萬里築長城。", "何時青冢月，却照漢家營。"]'),
('67c8a83c-5717-4f55-9046-d71c03586e0e','古意二首  其二','陸游','宋','宋诗','song-poetry','','[]','夜泊武昌城，江流千丈清。',24,'全唐诗/poet.song.136000.json','["夜泊武昌城，江流千丈清。", "寧爲雁奴死，不作鶴謀生。"]'),
('5fed7492-49f8-4ccc-a98f-930ebcb132a0','雪意復作','陸游','宋','宋诗','song-poetry','','[]','前日作雪風敗之，今日濃雲雪復作。',98,'全唐诗/poet.song.136000.json','["前日作雪風敗之，今日濃雲雪復作。", "一寒未暇自爲計，宿麥懸知天已諾。", "灞橋策馿愁露手，新豐買酒聊軟脚。", "胸中正著九雲夢，廊廟何加一丘壑。", "上書陳事固可笑，服藥求仙亦成錯。", "不如醉踏一劍騰風雲，跨海東謁青童君。"]'),
('a8ae4077-8917-4747-9f08-95a099cf554c','醉書','陸游','宋','宋诗','song-poetry','','[]','天公賦與五湖秋，風月雲烟處處留。',32,'全唐诗/poet.song.136000.json','["天公賦與五湖秋，風月雲烟處處留。", "損食一年猶可健，無詩三日却堪憂。"]'),
('5111cbd0-d2f8-4b6d-9d3f-58fbfda72835','排悶','陸游','宋','宋诗','song-poetry','','[]','造物冥冥中，與我無一面。',264,'全唐诗/poet.song.136000.json','["造物冥冥中，與我無一面。", "不知獲罪由，動輒被訶譴。", "又若哀其愚，救以藥瞑眩。", "我亦揣此心，安受不敢怨。", "中間戍蜀漢，十載困郵傳。", "騎壒蒙隴干，陣雲暗秦甸。", "賫糧雜沙墋，掬水以三咽。", "傳烽東駱谷，倏忽若流電。", "歸吳獲小休，餘喘僅一綫。", "意言在故鄉，終勝客異縣。", "夫何命大謬，魔事每交戰。", "友讎同一波，平地肆蹈踐。", "么然性命微，日畏讒口煽。", "舊書不暇視，鼠迹上几硯。", "負疴不即死，遂作諸老殿。", "却觀所更歷，殆是金百鍊。", "人誰不愛身，悔作青紫楦。", "短筇入空翠，小艇破江練。", "漁歌隔浦聞，績火傍林見。", "苦貧雖至骨，未肯受客唁。", "君看投林猿，終異巢幕燕。", "有山皆可耕，焉往失貧賤。"]'),
('70035aa9-60c4-4dce-896f-3ff29dbe809b','湖山尋梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','鏡湖渺渺烟波白，不與人間通地脈。',64,'全唐诗/poet.song.136000.json','["鏡湖渺渺烟波白，不與人間通地脈。", "騎龍古仙絕火食，慣住空山嚙冰雪。", "東皇高之置度外，正似人中巢許輩。", "萬木僵死我獨存，本來長生非返魂。"]'),
('671bd737-d659-4c5a-a066-af31586871f2','湖山尋梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','小雪湖上尋梅時，短帽亂插皆繁枝。',64,'全唐诗/poet.song.136000.json','["小雪湖上尋梅時，短帽亂插皆繁枝。", "路人看者竊相語，此老胸中常有詩。", "歸來青燈耿窗扉，心鏡忽入造化機。", "墨池水淺筆鋒燥，笑拂吳箋作飛草。"]'),
('768b6ed6-3c1f-4f94-82f5-3517dbc8d8e0','作雪寒甚有賦','陸游','宋','宋诗','song-poetry','','[]','雲暝風號得我驚，硯池轉盼已生冰。',64,'全唐诗/poet.song.136000.json','["雲暝風號得我驚，硯池轉盼已生冰。", "窗間頓失疏梅影，枕上空聞斷雁聲。", "公子皂貂方痛飲，農家黄犢正深耕。", "老人別有超然處，一首清詩信筆成。"]'),
('57e5d1d5-f889-4ac3-8c80-a09678c6427c','書懶','陸游','宋','宋诗','song-poetry','','[]','我性本迂疏，養生又無術。',72,'全唐诗/poet.song.136000.json','["我性本迂疏，養生又無術。", "憂患自外至，疾病由中出。", "屏居絕造請，冀補東隅失。", "今觀世間事，如僧視沐櫛。", "閑身嶺上雲，睡味蜂房蜜。", "惟思茅簷下，一席卧朝日。"]'),
('e71925c4-cba2-4e36-a6f8-de22a1b577c3','讀唐人愁詩戲作五首  其一','陸游','宋','宋诗','song-poetry','','[]','少時喚愁作底物，老境方知世有愁。',32,'全唐诗/poet.song.136000.json','["少時喚愁作底物，老境方知世有愁。", "忘盡世間愁故在，和身忘却始應休。"]'),
('dc4a6876-6863-4d3d-ac06-1892e9fd7461','讀唐人愁詩戲作五首  其二','陸游','宋','宋诗','song-poetry','','[]','清愁自是詩中料，向使無愁可得詩。',32,'全唐诗/poet.song.136000.json','["清愁自是詩中料，向使無愁可得詩。", "不屬僧窗孤宿夜，即還山驛旅遊時。"]'),
('833b8d70-139f-48c9-8d4b-07d0a993eb02','讀唐人愁詩戲作五首  其三','陸游','宋','宋诗','song-poetry','','[]','天恐文人未盡才，常教零落在蒿萊。',32,'全唐诗/poet.song.136000.json','["天恐文人未盡才，常教零落在蒿萊。", "不爲千載離騷計，屈子何由澤畔來。"]'),
('332287e3-3043-4afc-aaf4-ec773f585730','讀唐人愁詩戲作五首  其四','陸游','宋','宋诗','song-poetry','','[]','我輩情鍾不自由，等閑白却九分頭。',32,'全唐诗/poet.song.136000.json','["我輩情鍾不自由，等閑白却九分頭。", "此懷豈獨騷人事，三百篇中半是愁。"]'),
('cb71b219-be82-4d6e-a383-367f0807abed','讀唐人愁詩戲作五首  其五','陸游','宋','宋诗','song-poetry','','[]','飛雪安能住酒中，閑愁見酒亦消融。',32,'全唐诗/poet.song.136000.json','["飛雪安能住酒中，閑愁見酒亦消融。", "山家有力參天地，不放清尊一日空。"]'),
('df98abf1-e953-4c6c-82c9-571171deb110','讀書至夜分感嘆有賦','陸游','宋','宋诗','song-poetry','','[]','老人世間百念衰，惟好古書心未移。',128,'全唐诗/poet.song.136000.json','["老人世間百念衰，惟好古書心未移。", "斷碑殘刻亦在櫝，時時取玩忘朝饑。", "推尋點畫到曲折，想見落筆縱橫時。", "豈惟鸞鳳九霄上，景鍾大鼎森陸離。", "雖然欲學則曷敢，駑馬仰看驊騮馳。", "正如志士才不稱，心慕伊傅終何施。", "爾來亦復强點染，手不隨意徒嗟咨。", "懸知明日天將雨，中夜雲蒸紫玉池。"]'),
('d1f65f87-3aad-4049-a418-8a59dfed959f','擁爐','陸游','宋','宋诗','song-poetry','','[]','急雨狂風暮不收，燎爐薪暖復何憂。',64,'全唐诗/poet.song.136000.json','["急雨狂風暮不收，燎爐薪暖復何憂。", "如傾瀲灧鵝黄酒，似擁蒙茸狐白裘。", "大澤羈鴻來萬里，高城傳漏過三籌。", "明朝會看稽山雪，莫爲衝寒怯上樓。"]'),
('2d068a1d-2d0d-4222-9ab5-cfb6d088d10b','隠趣','陸游','宋','宋诗','song-poetry','','[]','歸老家山一幅巾，俗間那可與知聞。',64,'全唐诗/poet.song.136000.json','["歸老家山一幅巾，俗間那可與知聞。", "舉杯每屬江頭月，贈客時緘谷口雲。", "行采菖蒲緣蘚磴，卧浮舴艋入鷗群。", "力營隠趣君無怪，作得閑人要十分。"]'),
('ffbd1ee3-4dcd-4e8a-a959-74c470bae9ce','冬夜舟中作','陸游','宋','宋诗','song-poetry','','[]','夜榜孤舟掠岸行，村墟頻過不知名。',64,'全唐诗/poet.song.136000.json','["夜榜孤舟掠岸行，村墟頻過不知名。", "繞枝倦鵲寒無影，脫網奔魚遠有聲。", "兩紙忽驚殘曆盡，一杯聊慰旅懷情。", "還家自笑身猶健，又付生涯與短檠。"]'),
('7bdc80ee-b79f-4710-a930-0ef2c6c90e2e','湖山九首  其一','陸游','宋','宋诗','song-poetry','','[]','逐鹿心雖壯，乘騅勢已窮。',24,'全唐诗/poet.song.136000.json','["逐鹿心雖壯，乘騅勢已窮。", "終全蓋世氣，絕意走江東。"]'),
('97ebeb3c-4e1c-4110-bdf9-5a604c9dcb5f','湖山九首  其二','陸游','宋','宋诗','song-poetry','','[]','湖上多甘井，磑泉尤得名。',24,'全唐诗/poet.song.136000.json','["湖上多甘井，磑泉尤得名。", "何時枕白石，靜聽轆轤聲。"]'),
('1eaffc4a-7b6e-4f40-bfcf-ecbee5a2b4f8','湖山九首  其三','陸游','宋','宋诗','song-poetry','','[]','山崦桑麻路，柴門鳥雀聲。',24,'全唐诗/poet.song.136000.json','["山崦桑麻路，柴門鳥雀聲。", "老巫祈社雨，小婦餉春耕。"]'),
('7aaca998-0340-4b3b-a295-e4d2c7961100','湖山九首  其四','陸游','宋','宋诗','song-poetry','','[]','坡陀度小嶺，軒豁見平湖。',24,'全唐诗/poet.song.136000.json','["坡陀度小嶺，軒豁見平湖。", "但醉梅花下，民家酒可沽。"]'),
('d8110e6e-dbe2-47c1-8189-dab02f258d29','湖山九首  其五','陸游','宋','宋诗','song-poetry','','[]','淺井供茶竈，分流浣布沙。',24,'全唐诗/poet.song.136000.json','["淺井供茶竈，分流浣布沙。", "此泉吾所愛，百用給山家。"]'),
('d5882d71-eebc-4277-832e-9503e2654b32','湖山九首  其六','陸游','宋','宋诗','song-poetry','','[]','故堞無遺迹，蕭然數十家。',24,'全唐诗/poet.song.136000.json','["故堞無遺迹，蕭然數十家。", "茶烟映山起，酒帘傍堤斜。"]'),
('e19e1de2-792b-43b9-8715-7344a40e12c7','湖山九首  其七','陸游','宋','宋诗','song-poetry','','[]','汀月生眉黛，溪梅試額妝。',24,'全唐诗/poet.song.136000.json','["汀月生眉黛，溪梅試額妝。", "幽閨元不出，莫道嫁彭郎。"]'),
('ebfd3697-7b0c-4612-9f6d-913df340d857','湖山九首  其八','陸游','宋','宋诗','song-poetry','','[]','城邊小市聚，烟水淡秋容。',24,'全唐诗/poet.song.136000.json','["城邊小市聚，烟水淡秋容。", "南走蘭亭路，迢迢雲外鐘。"]'),
('399c5b56-965e-4356-8313-4690e15336da','湖山九首  其九','陸游','宋','宋诗','song-poetry','','[]','東西二十里，相望兩平橋。',24,'全唐诗/poet.song.136000.json','["東西二十里，相望兩平橋。", "傍水多投釣，穿雲有負樵。"]'),
('8d2a0254-3209-401b-a0ad-27d24e7283a0','齒髮','陸游','宋','宋诗','song-poetry','','[]','暮境侵尋歲月遒，齒搖髮脫又經秋。',64,'全唐诗/poet.song.136000.json','["暮境侵尋歲月遒，齒搖髮脫又經秋。", "此身要是歸衰謝，外物何須更固留。", "皂白從來憎了了，登臨且復送悠悠。", "嗣宗痛飲圖南睡，萬事輸君此一籌。"]'),
('4bc95527-e1b2-41b1-9da9-f80e1d74cc6b','古謂不如意事十常八九雖出于好功名者之言閑中亦未免此嘆戲作七字一首','陸游','宋','宋诗','song-poetry','','[]','歸志初諧老遽催，良辰常與病俱來。',64,'全唐诗/poet.song.136000.json','["歸志初諧老遽催，良辰常與病俱來。", "酒雖已熟恨無菊，雪苦不成空見梅。", "朋舊乖離心每折，山川悠邈首頻回。", "人生敗意無窮達，莫厭相逢笑口開。"]'),
('fdc8b51a-7c4b-4e93-b8ee-5fe36a688821','幽居歲暮五首  其一','陸游','宋','宋诗','song-poetry','','[]','冉冉忘年往，紛紛厭事來。',48,'全唐诗/poet.song.136000.json','["冉冉忘年往，紛紛厭事來。", "庭除多草莽，几硯亦塵埃。", "園爲畦蔬到，門因汲水開。", "偶聞林鳥語，太息又春回。"]'),
('a7285eb0-88ef-4ae5-a3fc-fdfbf7b9e95b','幽居歲暮五首  其二','陸游','宋','宋诗','song-poetry','','[]','却醫翻少疾，辭祿不加貧。',48,'全唐诗/poet.song.136000.json','["却醫翻少疾，辭祿不加貧。", "嘉木移俱活，村醪釀輒醇。", "悠悠還過日，盎盎又逢春。", "狂舞君毋笑，梅花插滿巾。"]'),
('0ab4ff78-6476-44e8-85a8-03bbad9febaa','幽居歲暮五首  其三','陸游','宋','宋诗','song-poetry','','[]','老去轉無事，室空惟一床。',48,'全唐诗/poet.song.136000.json','["老去轉無事，室空惟一床。", "卧時幽鳥語，行處野花香。", "巷北觀神社，村東看戲場。", "誰知屏居意，不獨爲耕桑。"]'),
('fd6f229e-d798-4250-9932-c3be3899d2bd','幽居歲暮五首  其四','陸游','宋','宋诗','song-poetry','','[]','燃薪代秉燭，煮茗當傳杯。',48,'全唐诗/poet.song.136000.json','["燃薪代秉燭，煮茗當傳杯。", "但恨朋儕少，那知日月催。", "衣裳任穿穴，芋栗且燔煨。", "不爲殘年迫，吾心久矣灰。"]'),
('5b3fda66-ebea-4665-aef8-9d589fa75b9b','幽居歲暮五首  其五','陸游','宋','宋诗','song-poetry','','[]','古井年年浚，荒疇日日犁。',48,'全唐诗/poet.song.136000.json','["古井年年浚，荒疇日日犁。", "刈茅苫鹿屋，插棘護鷄栖。", "閑頼書遮眼，愁須酒到臍。", "斜陽有常課，緩步上湖堤。"]'),
('b88f1fe8-8ef9-4b7d-8977-5c1db31fc523','過湖上僧庵','陸游','宋','宋诗','song-poetry','','[]','西庵每過未嘗開，邂逅清言始此回。',64,'全唐诗/poet.song.136000.json','["西庵每過未嘗開，邂逅清言始此回。", "陶令巾車尋壑去，巳公茅屋賦詩來。", "奇香炷罷雲生岫，瑞茗分成乳泛杯。", "便恐從今往還熟，入門猿鳥不驚猜。"]'),
('f56d0c3c-5841-4b77-a8bb-e2b125a54e66','夜坐戲作短歌','陸游','宋','宋诗','song-poetry','','[]','畏事如畏虎，避人如避寇。',108,'全唐诗/poet.song.136000.json','["畏事如畏虎，避人如避寇。", "結廬三家村，百事喜寒陋。", "身閑自爲貴，飯足豈非富。", "素心憎狐妖，老愈惡銅臭。", "視之若寒氣，可使客膚腠。", "即今知免矣，終歲塞門竇。", "始知松倒壑，殊勝雲出岫。", "聊持不動心，更養未盡壽。", "夜讀南華篇，欣然發吾覆。"]'),
('23c557b6-9fe7-4b7d-bb43-01a642e2b6a1','書嘆二首  其一','陸游','宋','宋诗','song-poetry','','[]','世事紛紜汝所知，欣然領略尚何疑。',64,'全唐诗/poet.song.136000.json','["世事紛紜汝所知，欣然領略尚何疑。", "窮居自是長年術，魔境常爲定力資。", "人但與遊無德怨，酒皆可醉略醇醨。", "蘭亭賓主今何在，修竹依然似曩時。"]'),
('e0ce01d5-4e87-4632-96a7-2a47659ea8d5','書嘆二首  其二','陸游','宋','宋诗','song-poetry','','[]','尺椽不改結茅初，薄粥猶艱卒歲儲。',64,'全唐诗/poet.song.136000.json','["尺椽不改結茅初，薄粥猶艱卒歲儲。", "猧子解迎門外客，狸奴知護案間書。", "深林閑數新添筍，小沼時觀舊放魚。", "自笑從來徒步慣，歸休枉道是懸車。"]'),
('3725c879-c3b5-4a06-810c-13d209bf2a34','日暮自湖上歸','陸游','宋','宋诗','song-poetry','','[]','我生本亦與人同，緣薄才疏剩得窮。',64,'全唐诗/poet.song.136000.json','["我生本亦與人同，緣薄才疏剩得窮。", "細水自鳴沙渚外，亂山時出雪雲中。", "僧歸獨趁殘鐘去，人散遥憐晚渡空。", "造物陳詩信奇絕，匆匆摹寫不能工。"]'),
('de789b6b-e439-4c46-b27f-e6660e4a7875','晚步湖堤','陸游','宋','宋诗','song-poetry','','[]','絁裘桐帽野人裝，又上湖堤步夕陽。',64,'全唐诗/poet.song.136000.json','["絁裘桐帽野人裝，又上湖堤步夕陽。", "貧甚不爲明日計，興來猶作少年狂。", "殘樽倒酒無餘瀝，幽圃尋梅認暗香。", "時有行人嘆頑健，黑絲點破頷間霜。"]'),
('d561505f-8c2d-4f5b-827f-e01408de71cc','夜寒','陸游','宋','宋诗','song-poetry','','[]','江雲作雪暗郊原，竟夜風聲萬馬奔。',64,'全唐诗/poet.song.136000.json','["江雲作雪暗郊原，竟夜風聲萬馬奔。", "槁面暫朱知酒釅，曲身成直頼爐溫。", "幼輿正復宜巖石，倚相猶能讀典墳。", "米貴僅供糜粥用，自傷無力濟元元。"]'),
('11f1c7f8-e694-4e1e-a55d-a39d767c91fe','感舊','陸游','宋','宋诗','song-poetry','','[]','早參太史筆，晚典石渠書。',48,'全唐诗/poet.song.136000.json','["早參太史筆，晚典石渠書。", "孤立如羈雁，微生等蠹魚。", "虛名真忝竊，定理有乘除。", "九十稽山下，荒畦日荷鋤。"]'),
('6dfd9a3f-9dd6-4bcf-a0e8-903b80451f5a','小雪','陸游','宋','宋诗','song-poetry','','[]','夜卧風號野，晨興雪擁籬。',48,'全唐诗/poet.song.136000.json','["夜卧風號野，晨興雪擁籬。", "未言能壓瘴，要是欲催詩。", "跨蹇雖堪喜，呼舟似更奇。", "元知剡溪路，不減灞橋時。"]'),
('ee23be89-0656-4911-9679-bcb8eae3c771','十二月十日暮小雪即止二首  其一','陸游','宋','宋诗','song-poetry','','[]','夜來急雪打船窗，今夜推窗月滿江。',32,'全唐诗/poet.song.136000.json','["夜來急雪打船窗，今夜推窗月滿江。", "堪恨無情一枝櫓，水禽驚起不成雙。"]'),
('77a6c8a5-2b0a-47c7-8add-33b2284e2085','十二月十日暮小雪即止二首  其二','陸游','宋','宋诗','song-poetry','','[]','夜來一雪苦匆匆，千里濃雲忽掃空。',32,'全唐诗/poet.song.136000.json','["夜來一雪苦匆匆，千里濃雲忽掃空。", "換得月明良不惡，未須過計慮蝗蟲。"]'),
('4949e3f1-1197-432a-8a0b-e6ae3b8f3130','遣興','陸游','宋','宋诗','song-poetry','','[]','翳翳魚鹽市，迢迢桑麥村。',48,'全唐诗/poet.song.136000.json','["翳翳魚鹽市，迢迢桑麥村。", "山家薪炭足，野叟袴襦溫。", "罝兔殘蕪盡，叉魚積水渾。", "詩書老無效，猶擬付兒孫。"]'),
('5078ad49-001b-4249-87bc-23dbc6c4686e','貧居時一肉食爾戲作','陸游','宋','宋诗','song-poetry','','[]','身老便居僻，山寒喜屋低。',48,'全唐诗/poet.song.136000.json','["身老便居僻，山寒喜屋低。", "時猶頼僧米，那惜貸鄰醯。", "湯餠挑春薺，盤餐設凍齏。", "怪來食指動，異味得豚蹄。"]'),
('6b4fe095-7f25-4012-892d-2af857802935','臘月十四日雨','陸游','宋','宋诗','song-poetry','','[]','歲晚深居懶出遊，小窗終日寄悠悠。',64,'全唐诗/poet.song.136000.json','["歲晚深居懶出遊，小窗終日寄悠悠。", "雨聲到枕助詩律，花氣襲衣生客愁。", "殘齒不堪添臲卼，瘦肩轉復覺颼飀。", "春前一雪猶關念，安得瓊瑶積瓦溝。"]'),
('97df755b-e182-4229-af4c-0753e5d2e362','節物','陸游','宋','宋诗','song-poetry','','[]','節物猶關老病身，鄉儺佛粥一年新。',32,'全唐诗/poet.song.136000.json','["節物猶關老病身，鄉儺佛粥一年新。", "簷間百舌還多事，探借園林十日春。"]'),
('bb98f2c3-6f6a-405b-9d6c-67ad1daca6ab','讀書','陸游','宋','宋诗','song-poetry','','[]','力不扶微學，心猶守舊聞。',24,'全唐诗/poet.song.136000.json','["力不扶微學，心猶守舊聞。", "壁間科斗字，秦火豈能焚。"]'),
('8702da22-5a45-4e11-b70d-02395b59e757','春近','陸游','宋','宋诗','song-poetry','','[]','曆授人時後，天回斗柄初。',48,'全唐诗/poet.song.136000.json','["曆授人時後，天回斗柄初。", "農疇興耒耜，家塾盛詩書。", "縹緲雙鳬舄，咿啞一鹿車。", "山翁喜春近，隨處狎樵漁。"]'),
('4cca5803-a691-4828-a986-a131d2a97341','讀陶詩','陸游','宋','宋诗','song-poetry','','[]','陶謝文章造化侔，篇成能使鬼神愁。',32,'全唐诗/poet.song.136000.json','["陶謝文章造化侔，篇成能使鬼神愁。", "君看夏木扶疏句，還許詩家更道不。"]'),
('adc6f1c2-e832-4a05-b43d-404bbacbac26','夜雨寒甚','陸游','宋','宋诗','song-poetry','','[]','萬籟號風如戰鼓，雪意垂垂先作雨。',96,'全唐诗/poet.song.136000.json','["萬籟號風如戰鼓，雪意垂垂先作雨。", "庭中栖鳥驚屢起，窗下殘燈翳還吐。", "老翁聳膊高過頂，童子觸屏低不語。", "時聞鄰舍起飯牛，亦有歸樵說逢虎。", "去年雪薄蝗害稼，今年望雪如望赦。", "行當三白兆豐年，牲酒如山作秋社。"]'),
('5fac534e-db93-4eff-896b-49b6144e3c8d','寄趙昌甫','陸游','宋','宋诗','song-poetry','','[]','杳杳雙鵲鳴庭除，東陽吏傳昌甫書。',128,'全唐诗/poet.song.136000.json','["杳杳雙鵲鳴庭除，東陽吏傳昌甫書。", "紙窮乃復得傑作，字字如刮造化爐。", "爾來此道苦寂寞，千里一士如鄰居。", "小兒得祿在傍邑，我貧初辦一鹿車。", "過門剝啄亦奇事，拜起幸未須人扶。", "君看幼安氣如虎，一病遽已歸荒墟。", "吾曹雖健固難恃，相覓寧待折簡呼。", "餘寒更祝勤自愛，時寄新詩來起予。"]'),
('b4a09f03-dcda-436d-8a44-93fa8a21f762','稽山雪','陸游','宋','宋诗','song-poetry','','[]','高人采藥來禹穴，骨瘦巉然鬢眉白。',128,'全唐诗/poet.song.136000.json','["高人采藥來禹穴，骨瘦巉然鬢眉白。", "結茅分得野鹿場，一夜北風三尺雪。", "明朝過午勢愈惡，虎兕交迹人聲絕。", "虛窗縱橫叢竹入，幽磵荒寂孤松折。", "凍吟孰窺袁安戶，僵卧禿盡蘇武節。", "人生饑寒固亦有，養氣不動真豪傑。", "希名後世吾所耻，姓字寧與身俱滅。", "班馬復生無自書，我作此歌空激烈。"]'),
('6a3ff33b-13ec-4ed3-84e3-33fcf12fd2e6','招鄰父啜菜羹','陸游','宋','宋诗','song-poetry','','[]','老境遺人事，窮居砭世肓。',48,'全唐诗/poet.song.136000.json','["老境遺人事，窮居砭世肓。", "茅簷聽雲滴，瓦鼎爇松肪。", "不願封侯印，惟求煮菜方。", "杯羹須及熱，剩欲喚君嘗。"]'),
('5a1f7f62-560c-457b-abbf-e6889e7dfe1b','讀論語','陸游','宋','宋诗','song-poetry','','[]','壯歲貪求未見書，歸常充棟出連車。',32,'全唐诗/poet.song.136000.json','["壯歲貪求未見書，歸常充棟出連車。", "晚窺闕里親傳妙，數簡方知已有餘。"]'),
('6d692acb-20e2-449d-880a-780e12daebd9','晨起','陸游','宋','宋诗','song-poetry','','[]','殘夢悠颺不復成，鎗然已有百禽鳴。',32,'全唐诗/poet.song.136000.json','["殘夢悠颺不復成，鎗然已有百禽鳴。", "山童來報溪流長，幽事從今日日生。"]'),
('e79caf6b-5e21-4fa9-b854-d618fafaf2a9','雪後','陸游','宋','宋诗','song-poetry','','[]','雪消已斷虛簷溜，日暖初催百草生。',32,'全唐诗/poet.song.136000.json','["雪消已斷虛簷溜，日暖初催百草生。", "射的山前春水綠，笙歌又滿會稽城。"]'),
('3d1257d5-6d27-4810-94fb-705c4a558c78','示福孫并示喜曾','陸游','宋','宋诗','song-poetry','','[]','北商久不通，梨棗罕登盤。',96,'全唐诗/poet.song.136000.json','["北商久不通，梨棗罕登盤。", "山舍惟有橘，瑣細如彈丸。", "此外則柿栗，收拾猿鳥殘。", "雖無龐翁話，兒孫亦團欒。", "今歲雨雪晚，歲暮始大寒。", "二稚乃可憐，不訴衣襦單。", "地爐有微火，誦書到更闌。", "我老多感慨，頼汝差自寬。"]'),
('a763b4de-c235-4235-b864-59b5afb8fbbb','微疾','陸游','宋','宋诗','song-poetry','','[]','微疾經旬近藥囊，往來巷陌未全妨。',64,'全唐诗/poet.song.136000.json','["微疾經旬近藥囊，往來巷陌未全妨。", "時時小雨知春近，處處閑身覺日長。", "林外鼓歌聞賽廟，懷中茶餠議租桑。", "兩京梅發今何似，送老流年只自傷。"]'),
('26d417db-599d-40af-a4d7-81427e0ded88','簡僧求秦望山拄杖','陸游','宋','宋诗','song-poetry','','[]','老病龍鍾不自持，飽知藤杖可扶衰。',32,'全唐诗/poet.song.136000.json','["老病龍鍾不自持，飽知藤杖可扶衰。", "明朝欲入天台去，試就高人乞一枝。"]'),
('a4509e3f-1ad0-4cff-b52b-3dc32adf8d4c','遊山步二首  其一','陸游','宋','宋诗','song-poetry','','[]','蹇馿渺渺過雲邊，旋了三生物外緣。',64,'全唐诗/poet.song.136000.json','["蹇馿渺渺過雲邊，旋了三生物外緣。", "平日視家真逆旅，此行出戶若登仙。", "饑從野店烹葵飯，困就僧床借枕眠。", "所恨暮年交舊盡，佳時無與共聯翩。"]'),
('8d7b5d08-2a83-4e02-bda5-aafdaf76df65','遊山步二首  其二','陸游','宋','宋诗','song-poetry','','[]','南出平橋十里餘，湖山處處可成圖。',64,'全唐诗/poet.song.136000.json','["南出平橋十里餘，湖山處處可成圖。", "水邊更覺梅花瘦，雲外誰憐雁影孤。", "時喚行僧同煮茗，亦逢樵叟問迷途。", "破裘不怕春寒峭，小市疏燈有酒壚。"]'),
('a808ac8d-ba97-4ef4-bf4f-92387b34809d','雪晴欲出而路濘未通戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','欲覓溪頭路，春泥不可行。',24,'全唐诗/poet.song.136000.json','["欲覓溪頭路，春泥不可行。", "歸來小窗下，袖手看新晴。"]'),
('bb468daf-0a97-4515-bf62-e9bc51a5fb90','雪晴欲出而路濘未通戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','雪消重作雨，冰釋又成泥。',24,'全唐诗/poet.song.136000.json','["雪消重作雨，冰釋又成泥。", "已敗筇枝興，高眠聽午鷄。"]'),
('8f28647f-8a22-496f-9c98-a5f40c25f991','春日','陸游','宋','宋诗','song-poetry','','[]','冷餠細生菜，老翁殊未衰。',24,'全唐诗/poet.song.136000.json','["冷餠細生菜，老翁殊未衰。", "仍尋舊旛勝，一笑伴諸兒。"]'),
('291aa2ee-340e-4047-a2f3-d23a2f1384a2','示兒輩','陸游','宋','宋诗','song-poetry','','[]','窮居懷抱久無歡，猶頼吾兒得少寬。',64,'全唐诗/poet.song.136000.json','["窮居懷抱久無歡，猶頼吾兒得少寬。", "謹視鷄豚供老疾，力營薪炭備春寒。", "舊書綴緝編無絕，小甕調停味不酸。", "坐使乃翁無一事，高眠常到日三竿。"]'),
('606ca5d2-93fa-4626-b500-1341d405794c','雪後煎茶','陸游','宋','宋诗','song-poetry','','[]','雪液清甘漲井泉，自携茶竈就烹煎。',32,'全唐诗/poet.song.136000.json','["雪液清甘漲井泉，自携茶竈就烹煎。", "一毫無復關心事，不枉人間住百年。"]'),
('bed3af52-bd31-47cb-97a5-cc4cf999cf43','夢中作','陸游','宋','宋诗','song-poetry','','[]','久向人間隠姓名，看花幾到武昌城。',64,'全唐诗/poet.song.136000.json','["久向人間隠姓名，看花幾到武昌城。", "一壺春色常供醉，萬里烟波懶問程。", "斜日挂帆堤外影，便風擊鼓驛前聲。", "丈夫入手皆勛業，廊廟江湖未易評。"]'),
('177cd0bf-d6e4-4ce8-9cf0-a74392ac3598','破屋嘆','陸游','宋','宋诗','song-poetry','','[]','我年四十時，築舍受一廛。',120,'全唐诗/poet.song.136000.json','["我年四十時，築舍受一廛。", "歲月不貸人，殆將五十年。", "初非楩柟材，既久理豈全。", "慘淡窘風雨，亦復補破穿。", "竹椽與繩樞，豈敢求牢堅。", "今朝忽自顧，衰疾方沉綿。", "不知此殘軀，與屋誰先顛。", "粥藥幸粗給，兒稚滿目前。", "斂藏雖甚薄，猶勝死道邊。", "一笑推枕起，無酒亦陶然。"]'),
('0a57b91c-1eb7-4fef-b7e8-890e0a7a124f','戊辰歲除前五日作新歲八十有五矣','陸游','宋','宋诗','song-poetry','','[]','灰深火可宿，炷小燈耐久。',84,'全唐诗/poet.song.136000.json','["灰深火可宿，炷小燈耐久。", "長流故不腐，易成必速朽。", "我昔遊青城，聞道巢居叟。", "躬行雖不力，年少過九九。", "固知適天幸，自養亦差厚。", "傳家六兒子，其四今皓首。", "寧聞澗底松，鬰鬰慕蒲柳。"]'),
('2fa01eee-8b20-4435-81b7-ca70d745aab3','晨起復睡','陸游','宋','宋诗','song-poetry','','[]','衰翁卯飲易上面，澤國春寒偏著人。',32,'全唐诗/poet.song.136000.json','["衰翁卯飲易上面，澤國春寒偏著人。", "下榻一杯還就枕，不嫌鼾睡聒比鄰。"]'),
('9c6e09a0-9687-41a0-8c64-4b4b3f416cf9','梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','三十三年舉眼非，錦江樂事祇成悲。',32,'全唐诗/poet.song.136000.json','["三十三年舉眼非，錦江樂事祇成悲。", "溪頭忽見梅花發，恰是青羊宮裏時。"]'),
('ea26ab0c-cfb8-4ba5-a62b-3d8f9b742c41','梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','俗事常妨把一杯，等閑開過小園梅。',32,'全唐诗/poet.song.136000.json','["俗事常妨把一杯，等閑開過小園梅。", "自傷惟有尋春夢，百舌無情又喚回。"]'),
('6861bf54-12df-4892-b2c0-e9255f1e59fb','小疾治藥偶書二首  其一','陸游','宋','宋诗','song-poetry','','[]','禦戎虛上策，治疾闕全功。',24,'全唐诗/poet.song.136000.json','["禦戎虛上策，治疾闕全功。", "安得如神禹，常行無事中。"]'),
('122e343a-fa29-46b5-ac14-2baf953e6366','小疾治藥偶書二首  其二','陸游','宋','宋诗','song-poetry','','[]','揠苗農害稼，過劑藥傷人。',24,'全唐诗/poet.song.136000.json','["揠苗農害稼，過劑藥傷人。", "此理君能造，無爲萬物春。"]'),
('7bf1faf6-13b0-427e-b600-cd69fbecf34a','子遹讀書常至夜分作此示之','陸游','宋','宋诗','song-poetry','','[]','我爲無才老把鉏，汝窮亦復坐迂疏。',64,'全唐诗/poet.song.136000.json','["我爲無才老把鉏，汝窮亦復坐迂疏。", "夜燈詠史蟲吟草，朝几陳書獺祭魚。", "未至苦饑依馬磨，不妨相守卧蝸廬。", "業成自有能知賞，家世從來典石渠。"]'),
('c5f3eb0d-db9f-4bbf-aa4e-9c151895fd8f','歲暮作','陸游','宋','宋诗','song-poetry','','[]','魚貫長條兔卧盤，往來聊續里閭歡。',64,'全唐诗/poet.song.136000.json','["魚貫長條兔卧盤，往來聊續里閭歡。", "舊符又擬新年換，殘曆都無半紙看。", "梅影橫斜春尚淺，角聲悲壯夜將闌。", "堅頑敢望今如許，戲說期頤强自寬。"]'),
('137b3196-adba-4afe-b82b-6a3172952d12','除夕','陸游','宋','宋诗','song-poetry','','[]','熾炭爐中百藥香，屠蘇煎酒代椒觴。',32,'全唐诗/poet.song.136000.json','["熾炭爐中百藥香，屠蘇煎酒代椒觴。", "明朝頼是無來客，雪後泥深一尺强。"]'),
('20afc9fa-291a-408d-ae58-a6e3b804ec9d','己巳元日','陸游','宋','宋诗','song-poetry','','[]','曾孫新長奉椒觴，兒女冠笄各綴行。',32,'全唐诗/poet.song.136000.json','["曾孫新長奉椒觴，兒女冠笄各綴行。", "身作太翁垂九十，醉來堪喜亦堪傷。"]'),
('b12ce6b9-70a4-442d-98a2-86ea4ba5949a','初春','陸游','宋','宋诗','song-poetry','','[]','裝罷桃符又剪燈，新年光景捷飛騰。',32,'全唐诗/poet.song.136000.json','["裝罷桃符又剪燈，新年光景捷飛騰。", "老翁掃盡兒童事，却學禪床入定僧。"]'),
('cc895eb6-1e2c-48c2-bf00-26336c7b89ca','新年書感','陸游','宋','宋诗','song-poetry','','[]','早歲西遊賦子虛，暮年負耒返鄉閭。',64,'全唐诗/poet.song.136000.json','["早歲西遊賦子虛，暮年負耒返鄉閭。", "殘軀未死敢忘國，病眼欲盲猶愛書。", "朋舊何勞記車笠，子孫幸不廢菑畬。", "新年冷落如常日，白髮蕭蕭悶自梳。"]'),
('8d0270c1-1287-4fe3-ba7e-c37b3d35a044','開歲連日大雪','陸游','宋','宋诗','song-poetry','','[]','開歲大雪如飛鷗，轉盼已見平簷溝。',96,'全唐诗/poet.song.136000.json','["開歲大雪如飛鷗，轉盼已見平簷溝。", "村深出門風裂面，况復取醉湖邊樓。", "從來春雪不耐久，卧聽點滴無時休。", "去年久旱綿千里，犁不入土蝗蟲稠。", "今年冬春足膏澤，天意似欲滋農疇。", "豈惟養豬大作社，更賣寶劍添耕牛。"]'),
('ce4dcf2d-1d72-4d1b-9f94-a3e44bba56a0','飲酒','陸游','宋','宋诗','song-poetry','','[]','我酒本小戶，痛飲乃有時。',72,'全唐诗/poet.song.136000.json','["我酒本小戶，痛飲乃有時。", "意氣不相值，終日持空卮。", "醉或能齋莊，不醉或狂逸。", "乃知老子狂，非自麴糵出。", "今日雪始晴，行歌官道傍。", "超然醒醉間，非莊亦非狂。"]'),
('22a2b1fd-36aa-40c4-88bb-ec64fe8ddae2','詩酒','陸游','宋','宋诗','song-poetry','','[]','我生寓詩酒，本以全吾真。',96,'全唐诗/poet.song.136000.json','["我生寓詩酒，本以全吾真。", "酒既工作病，詩亦能窮人。", "每欲兩忘之，永爲耕樵民。", "周旋日已久，棄去終無因。", "齒髮益衰謝，肝膽猶輪囷。", "吟哦撼四壁，嵬峨頹烏巾。", "江上處處好，風月年年新。", "正爾豈不樂，浩歌終此身。"]'),
('a9beccdc-b20f-48c1-961c-18f92f902448','人日雪','陸游','宋','宋诗','song-poetry','','[]','病卧江村不厭深，貂裘無奈曉寒侵。',64,'全唐诗/poet.song.136000.json','["病卧江村不厭深，貂裘無奈曉寒侵。", "非賢那畏蛇年至，多難却愁人日陰。", "嫋嫋孤雲生翠壁，霏霏急雪灑青林。", "一盂飯罷無餘事，坐看生臺下凍禽。"]'),
('e827e258-faf5-47f9-9ede-1cb875e20163','春寒二首  其一','陸游','宋','宋诗','song-poetry','','[]','滔天來洚水，震瓦戰昆陽。',24,'全唐诗/poet.song.136000.json','["滔天來洚水，震瓦戰昆陽。", "此敵猶能禦，春寒不可當。"]'),
('ec275ade-d72b-4887-8817-00d65520beab','春寒二首  其二','陸游','宋','宋诗','song-poetry','','[]','高樓墜綠珠，惡客醉珊瑚。',24,'全唐诗/poet.song.136000.json','["高樓墜綠珠，惡客醉珊瑚。", "未抵春寒夜，貧翁喪故襦。"]'),
('fac686b0-d1a8-419e-b57c-cea210a77b0a','雨雪久無來客亦不能出作長句排悶','陸游','宋','宋诗','song-poetry','','[]','造物無情豈我私，從來不使墮危機。',64,'全唐诗/poet.song.136000.json','["造物無情豈我私，從來不使墮危機。", "青雲路近常排去，白浪堆高亦脫歸。", "殘稿尚存空自許，故人略盡欲誰依。", "新春雪暗山村路，且復焚香獨掩扉。"]'),
('9d5d1a9d-c4fe-4d01-bf6b-7f31b7ebc1ca','書耄','陸游','宋','宋诗','song-poetry','','[]','我老耄已及，終日惟冥行。',72,'全唐诗/poet.song.136000.json','["我老耄已及，終日惟冥行。", "鄰里少間闊，便若昧平生。", "家人每過前，亦或忘其名。", "昏昏等作夢，兀兀如病酲。", "不知張睢陽，何以記一城。", "愚知各自適，得失未易評。"]'),
('a77e328e-23df-4f0d-801e-9683779e5c2f','初春遣興','陸游','宋','宋诗','song-poetry','','[]','閑愁長與病相依，晨起梳頭感髮稀。',64,'全唐诗/poet.song.136000.json','["閑愁長與病相依，晨起梳頭感髮稀。", "春事鼎來風更惡，晨光已滿雪猶飛。", "江梅有恨論年別，旅雁無情計日歸。", "剩欲湖邊踏青去，憑誰爲解亂書圍。"]'),
('92982d50-490a-4a46-bd46-a4bc36ba523f','讀書','陸游','宋','宋诗','song-poetry','','[]','少從師友講唐虞，白首襟懷不少舒。',64,'全唐诗/poet.song.136000.json','["少從師友講唐虞，白首襟懷不少舒。", "舊謂皆當付之酒，今知莫若信吾書。", "朱黄參錯鷄鳴後，籤帙從橫月墮初。", "撫几欣然時有得，此翁作計未全疏。"]'),
('478f77db-ccb2-418c-92bc-e7f95a4bee24','雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','灰中火如螢，燎原從此始。',24,'全唐诗/poet.song.136000.json','["灰中火如螢，燎原從此始。", "元氣一點存，危疾亦不死。"]'),
('3a6e569a-6e7a-4591-9f85-f03907cc48a2','雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','炷香火要深，作墨手當緩。',24,'全唐诗/poet.song.136000.json','["炷香火要深，作墨手當緩。", "淺士務成速，所以多後患。"]'),
('5bb2c4b2-5b45-41c9-8423-11e7f4ae158e','雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','庖丁悟養生，輪扁議讀書。',24,'全唐诗/poet.song.136000.json','["庖丁悟養生，輪扁議讀書。", "彼特一技爾，聖智有不如。"]'),
('e97d1517-40f2-4e9d-9689-762ce6dfcdb4','雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','鏗爾捨瑟作，嚗然放杖笑。',24,'全唐诗/poet.song.136000.json','["鏗爾捨瑟作，嚗然放杖笑。", "浩浩太古音，與俗不同調。"]'),
('39f76a79-185f-42d4-a8fd-0de863c29fa7','後雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','臘雪瑞我麥，春雨嘉我穀。',24,'全唐诗/poet.song.136000.json','["臘雪瑞我麥，春雨嘉我穀。", "老農無他求，一飽萬事足。"]'),
('b9404885-5bb2-4941-b08b-c23b121069ea','後雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','日上明我窗，月出縞我庭。',24,'全唐诗/poet.song.136000.json','["日上明我窗，月出縞我庭。", "朝暮得嘉時，一榼醉復醒。"]'),
('91e8b41c-9cba-4747-a25d-3823c5f5c673','後雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','會合惜日短，別離愁夜長。',24,'全唐诗/poet.song.136000.json','["會合惜日短，別離愁夜長。", "人老愛吾廬，客歸悲故鄉。"]'),
('991eccae-4b87-4f72-b4b4-4a309e33051f','後雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','俚醫刀匕藥，老巫半榼酒。',24,'全唐诗/poet.song.136000.json','["俚醫刀匕藥，老巫半榼酒。", "拜况不敢忘，淡薄最耐久。"]'),
('bbf7745b-fc79-4226-a3e9-349428f7f816','自詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','道本治吾身，緒餘方及人。',48,'全唐诗/poet.song.136000.json','["道本治吾身，緒餘方及人。", "神清緣食少，事簡爲家貧。", "薄酒如重醖，寒蔬抵八珍。", "村村花柳動，且復岸綸巾。"]'),
('f25cd04c-c35a-47c9-9d66-f212b1de5210','自詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','謝事客誰過，閑遊吏不訶。',48,'全唐诗/poet.song.136000.json','["謝事客誰過，閑遊吏不訶。", "家人爭稗粥，鄰叟和畬歌。", "靜夜詩成祟，新春睡有魔。", "年光本無盡，未用嘆蹉跎。"]'),
('68e399d1-488c-4bda-89e1-af9952dd5fe2','晚窗','陸游','宋','宋诗','song-poetry','','[]','一塢梅花已盡空，數瓴春雪未全融。',32,'全唐诗/poet.song.136000.json','["一塢梅花已盡空，數瓴春雪未全融。", "晚窗忽有題詩興，落筆縱橫半醉中。"]'),
('1e9eab23-8e3c-44c7-83a6-79658d37f0b6','遠遊二十韵','陸游','宋','宋诗','song-poetry','','[]','早歲志遠遊，萬里携孤劍。',240,'全唐诗/poet.song.136000.json','["早歲志遠遊，萬里携孤劍。", "所至必吊古，如疾得針砭。", "荒寒過吳宮，摧剝觀禹窆。", "及仕揚潤間，挂席度天塹。", "梁宋不可遊，北望每懷歉。", "會有蜀漢役，奇嶮日窺覘。", "築壇訪遺址，燒棧想烈焰。", "轅門俯清渭，徹底綠可染。", "舊史所登載，一一嘗考驗。", "胡羊美無敵，黍酒實醇釅。", "枕戈南山下，馳獵久不厭。", "比參劍南幕，壯志就收斂。", "卜鄰揚雄宅，遂欲老鉛槧。", "但愛古柏青，肯顧海棠艷。", "人生不易料，白首東歸剡。", "稽山秋峨峨，鏡水春瀲瀲。", "餘俸買扁舟，月下采菱芡。", "湖山最奇處，容我釣石占。", "婚嫁幸已畢，百事不關念。", "但當勤醉歌，一死不汝欠。"]'),
('717f2a2f-d376-4477-a387-00dcd8b566e3','對酒','陸游','宋','宋诗','song-poetry','','[]','社醅又借醉顔酡，手挽鄰翁作浩歌。',64,'全唐诗/poet.song.136000.json','["社醅又借醉顔酡，手挽鄰翁作浩歌。", "江月偏能照蓬戶，京塵終不汙漁蓑。", "苦吟且復欹吾帽，對弈真當爛汝柯。", "回首紛紛俱夢耳，人間何處有天魔。"]'),
('df423a53-2f2a-48b8-9678-f9b96c831aa0','夜雨','陸游','宋','宋诗','song-poetry','','[]','正看飛雪暗江天，不覺新春已粲然。',64,'全唐诗/poet.song.136000.json','["正看飛雪暗江天，不覺新春已粲然。", "花氣襲人娛獨夜，雨聲繞舍送豐年。", "樵風未改山川舊，禊事空悲歲月遷。", "一榼可營身尚健，故應先治下湖船。"]'),
('aae8463c-f06d-4844-bed3-db561e98f87a','己巳正月十八九間雪復大作不止','陸游','宋','宋诗','song-poetry','','[]','早衰常畏雪，况復在江干。',48,'全唐诗/poet.song.136000.json','["早衰常畏雪，况復在江干。", "三日不能出，數年無此寒。", "捲簾驚滉漾，下榻覺蹣跚。", "稚子應憐我，孤吟興未闌。"]'),
('032dfdf0-7335-46bd-84c0-099e01cb6441','寄子虡','陸游','宋','宋诗','song-poetry','','[]','汝官南壽春，我居東會稽。',72,'全唐诗/poet.song.136000.json','["汝官南壽春，我居東會稽。", "疋馬護秋塞，兩犢翻春泥。", "淮天沙雁過，江村雪雲低。", "書來動半年，相望常愴凄。", "父子不共耕，此悔真噬臍。", "明年城西社，爛醉相扶携。"]'),
('b46edce1-ed0e-4918-af11-67527bf3dc0d','書夢','陸游','宋','宋诗','song-poetry','','[]','我夢舉有司，鷄唱起裹飯。',72,'全唐诗/poet.song.136000.json','["我夢舉有司，鷄唱起裹飯。", "又夢趁早朝，漏舍坐待旦。", "既寤兩無有，撫枕徒浩嘆。", "今雖去爲農，飯牛亦夜半。", "何曾得放慵，美睡到日旰。", "一笑俱置之，浮生固多難。"]'),
('362e8197-bb49-443a-8e66-39cf3cce685c','示子遹','陸游','宋','宋诗','song-poetry','','[]','家貧不學儉，物理有固然。',72,'全唐诗/poet.song.136000.json','["家貧不學儉，物理有固然。", "要是善用短，足以終其年。", "我家稽山下，稟賦良奇偏。", "敢言中人産，日或無炊烟。", "有兒更耐窮，伴翁理遺編。", "短檠幸能繼，竟夜可忘眠。"]'),
('2660dc5d-4457-477c-b891-11382f122e10','對食有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','杯酌以助氣，匕筯以充腹。',72,'全唐诗/poet.song.136000.json','["杯酌以助氣，匕筯以充腹。", "沾醉與屬饜，其害等嗜慾。", "啜醨有餘歡，食淡百味足。", "養生所甚惡，旨酒及大肉。", "老翁雖無能，更事嗟已熟。", "勿嘆茆三間，養汝山林福。"]'),
('f31243fc-1d1a-4d18-85dd-8a8e375b7ab0','對食有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','我老雖無家，其實如客耳。',72,'全唐诗/poet.song.136000.json','["我老雖無家，其實如客耳。", "食至舉匕箸，飽則捨而起。", "厨人有勤惰，我豈形慍喜。", "園畦摘青蔬，地碓舂赤米。", "勞人固已多，坐享顙常泚。", "作詩本自規，亦以告閭里。"]'),
('f0efa4c5-85ea-479b-9472-bbcbbdcce882','雪夜三首  其一','陸游','宋','宋诗','song-poetry','','[]','荒郊貿貿行，斷壟俋俋耕。',48,'全唐诗/poet.song.136000.json','["荒郊貿貿行，斷壟俋俋耕。", "常情所藉躪，豈復懷不平。", "歸來卧破屋，中惟一床橫。", "且燒生柴火，靜聽溼雪聲。"]'),
('88e6ce0a-8e9b-454a-8985-9be897acc437','雪夜三首  其二','陸游','宋','宋诗','song-poetry','','[]','今年春苦寒，風雪塞戶牖。',48,'全唐诗/poet.song.136000.json','["今年春苦寒，風雪塞戶牖。", "况我窮閻士，袴敝衣見肘。", "正須小忍之，此事豈得久。", "努力辦一壺，西村看花柳。"]'),
('22255aaa-f7ef-47e5-98c0-94d43cf77f07','雪夜三首  其三','陸游','宋','宋诗','song-poetry','','[]','瓦疏雪墮簷，窗破風吹燭。',48,'全唐诗/poet.song.136000.json','["瓦疏雪墮簷，窗破風吹燭。", "短裘不及骭，手脚盡皸瘃。", "猶勝南鄰叟，一褐竟未贖。", "薄酒城中來，清夜聊相屬。"]'),
('352f2e12-1abc-447d-af53-dc347f38005f','初春','陸游','宋','宋诗','song-poetry','','[]','柳拂朱橋湖水生，園林處處聽新鶑。',64,'全唐诗/poet.song.136000.json','["柳拂朱橋湖水生，園林處處聽新鶑。", "亦知人世當行樂，無奈春陰不肯晴。", "走馬章臺身縱老，看花杜曲眼猶明。", "只應詩思年來減，預怯同遊議罰觥。"]'),
('ed2d8201-833c-49bb-b79d-57bde7d6d3d7','春日雜興十二首  其一','陸游','宋','宋诗','song-poetry','','[]','方塘盎盎带泥渾，遠草青青沒燒痕。',32,'全唐诗/poet.song.136000.json','["方塘盎盎带泥渾，遠草青青沒燒痕。", "只道雨晴春晝永，歸時不覺已黄昏。"]'),
('ecddb225-1944-4d05-a09a-e6cf2ca64235','春日雜興十二首  其二','陸游','宋','宋诗','song-poetry','','[]','南村北村鼓鼕鼕，刲羊刺豕祭潭龍。',32,'全唐诗/poet.song.136000.json','["南村北村鼓鼕鼕，刲羊刺豕祭潭龍。", "一生衣食財取足，百世何妨常作農。"]'),
('8a39eec7-67bb-4f6c-b08f-b772d087d13a','春日雜興十二首  其三','陸游','宋','宋诗','song-poetry','','[]','小甔有米可續炊，紙鳶竹馬看兒嬉。',32,'全唐诗/poet.song.136000.json','["小甔有米可續炊，紙鳶竹馬看兒嬉。", "但得官清吏不橫，即是村中歌舞時。"]'),
('387fe712-2ff3-4c51-92cb-43a096d274d4','春日雜興十二首  其四','陸游','宋','宋诗','song-poetry','','[]','夜夜燃薪暖絮衾，禺中一飯直千金。',32,'全唐诗/poet.song.136000.json','["夜夜燃薪暖絮衾，禺中一飯直千金。", "身爲野老已無責，路有流民終動心。"]'),
('dfeac57f-e85b-4486-8541-c8e044b9d3ab','春日雜興十二首  其五','陸游','宋','宋诗','song-poetry','','[]','出仕常騎禿尾馿，歸休自駕折轅車。',32,'全唐诗/poet.song.136000.json','["出仕常騎禿尾馿，歸休自駕折轅車。", "今朝偶遇林夫子，借得齊民一卷書。"]'),
('f1c23377-b3a7-4405-95cb-d2e497dabf11','春日雜興十二首  其六','陸游','宋','宋诗','song-poetry','','[]','更事多來見物情，世間常恨太忙生。',32,'全唐诗/poet.song.136000.json','["更事多來見物情，世間常恨太忙生。", "花開款款寧爲晚，日出遲遲却是晴。"]'),
('0cc07bdd-bfbc-4398-ba65-19abdd7e1840','春日雜興十二首  其七','陸游','宋','宋诗','song-poetry','','[]','一枝筇杖一山童，買酒行歌小市中。',32,'全唐诗/poet.song.136000.json','["一枝筇杖一山童，買酒行歌小市中。", "莫笑摧頹今至此，當年萬里看春風。"]'),
('1689570f-3918-4207-a518-d164cc8d5faf','春日雜興十二首  其八','陸游','宋','宋诗','song-poetry','','[]','四十餘年學養生，誰知所得亦平平。',32,'全唐诗/poet.song.136000.json','["四十餘年學養生，誰知所得亦平平。", "體孱不犯寒時出，路溼常尋乾處行。"]'),
('f71c5df2-c51b-4c98-99ca-48da426a51d3','春日雜興十二首  其九','陸游','宋','宋诗','song-poetry','','[]','攪睡禽聲曉傍簷，泥人花氣午穿簾。',32,'全唐诗/poet.song.136000.json','["攪睡禽聲曉傍簷，泥人花氣午穿簾。", "歡情老去年年薄，困思春來日日添。"]'),
('1e8e5abc-6061-42b7-985c-5f5099ff48ba','春日雜興十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','陰晴不定春猶淺，困健相兼病未蘇。',32,'全唐诗/poet.song.136000.json','["陰晴不定春猶淺，困健相兼病未蘇。", "見說市樓新酒美，杖頭今日一錢無。"]'),
('0f1c32a4-0133-4847-85ee-20fdaf2f6fac','春日雜興十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','乍晴乍雨忽經旬，半醉半醒還過春。',32,'全唐诗/poet.song.136000.json','["乍晴乍雨忽經旬，半醉半醒還過春。", "春卧不知庵外事，閑吟聊適夢中身。"]'),
('8c8d4983-5d17-4d9b-99ef-50e8f9e23d28','春日雜興十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','行人陌上思悠悠，十里斜陽古渡頭。',32,'全唐诗/poet.song.136000.json','["行人陌上思悠悠，十里斜陽古渡頭。", "一片落花無覓處，只教芳草管閑愁。"]'),
('6238fb92-50ba-40d6-b690-a1d250cc6d15','小霽乘竹輿至柳姑廟而歸','陸游','宋','宋诗','song-poetry','','[]','殘雲斷處漏斜陽，草滿平堤柳著行。',64,'全唐诗/poet.song.136000.json','["殘雲斷處漏斜陽，草滿平堤柳著行。", "颭颭畫船來北港，翻翻青繖度南塘。", "行人相賀新年健，逃戶雖窮舊業荒。", "感物興懷空絕嘆，才衰無語付詩囊。"]'),
('fc2c4b4e-efdd-4e94-8b11-44b7681250d2','春曉','陸游','宋','宋诗','song-poetry','','[]','初見天窗一點明，旋看曉色到簷楹。',64,'全唐诗/poet.song.136000.json','["初見天窗一點明，旋看曉色到簷楹。", "衾裯溫暖留殘夢，鳥雀呼鳴報快晴。", "雖喜心隨年愈老，却愁事與日俱生。", "平川漫漫烟蕪綠，筋力猶堪給耦耕。"]'),
('6c43c44e-81f5-484a-ac82-b1152a018ee7','肩輿歷湖桑堰東西過陳灣至陳讓堰小市抵暮乃歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','堤遠沙平草色勻，新晴喜得自由身。',64,'全唐诗/poet.song.136000.json','["堤遠沙平草色勻，新晴喜得自由身。", "芋羹豆飯家家樂，桑眼榆條物物春。", "野店茶香迎倦客，市街犬熟傍行人。", "牆頭婦女更相語，認到先生折角巾。"]'),
('1523261c-0c6a-466c-b74b-1ddb54a204b5','肩輿歷湖桑堰東西過陳灣至陳讓堰小市抵暮乃歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','貪看西南一面山，不知信步到陳灣。',64,'全唐诗/poet.song.136000.json','["貪看西南一面山，不知信步到陳灣。", "未言散釋經旬病，且要消磨半日閑。", "蔬壟過寒常鬰鬰，鳥聲迎暖已關關。", "斜陽不爲行人駐，十里鐘來翠靄間。"]'),
('bd937cf1-6aad-4728-89df-1eb804d26531','書適','陸游','宋','宋诗','song-poetry','','[]','疇昔花前醉放顛，即今不飲亦陶然。',64,'全唐诗/poet.song.136000.json','["疇昔花前醉放顛，即今不飲亦陶然。", "太平固自多遺老，獨往何妨是斥仙。", "扶杖每觀南畝饁，解衣時作北窗眠。", "人間賢俊方雲集，我遇龍蛇豈厄年。"]'),
('d74a931d-6cf1-4d45-bc0b-e6cd13cfd4f2','陳讓堰市中遇吳氏老自言七十六歲與語久之及歸送予過市猶戀戀不忍去','陸游','宋','宋诗','song-poetry','','[]','就店煮茶古堰邊，偶逢父老便忘年。',64,'全唐诗/poet.song.136000.json','["就店煮茶古堰邊，偶逢父老便忘年。", "磋予空忝十年長，聞道慙無一日先。", "壯子當門能碌碌，諸孫承業亦翩翩。", "熟思遊宦終何得，悔不從公曝背眠。"]'),
('c3ea1d9a-3b61-47f6-82bf-7c034845fb0b','午炊','陸游','宋','宋诗','song-poetry','','[]','江路初晴日，烟蕪古廢城。',48,'全唐诗/poet.song.136000.json','["江路初晴日，烟蕪古廢城。", "青鍼秧稻出，黑螘稚蠶生。", "山際牛羊路，林間雞犬聲。", "午炊聊小憩，野老解逢迎。"]'),
('6ce93818-69c8-4b5a-a706-e1093af10884','古風二首  其一','陸游','宋','宋诗','song-poetry','','[]','犧象薦清廟，餘材棄溝中。',48,'全唐诗/poet.song.136000.json','["犧象薦清廟，餘材棄溝中。", "二者雖甚遠，殘生其實同。", "人當貴其身，豈復論窮通。", "寧爲原上草，一寸搖春風。"]'),
('3589085d-21ea-4f3a-8b25-0c127df90be3','古風二首  其二','陸游','宋','宋诗','song-poetry','','[]','木生雖拱把，鮮不困斧斤。',48,'全唐诗/poet.song.136000.json','["木生雖拱把，鮮不困斧斤。", "枯朽亦可全，又以薌故焚。", "嘉禾終銍艾，豈獨草見耘。", "此理講已熟，要當尊所聞。"]'),
('e2eed20c-d1b5-4f30-bd96-288987e8912e','肩輿至石堰村','陸游','宋','宋诗','song-poetry','','[]','偶上籃輿踏夕陽，醉魂困思兩倀倀。',64,'全唐诗/poet.song.136000.json','["偶上籃輿踏夕陽，醉魂困思兩倀倀。", "澗薪旋拾供茶竈，詩稿初成寄藥囊。", "村舍藝麻驅鳥雀，牧童隨草放牛羊。", "歸來徙倚衡門久，始覺中春已日長。"]'),
('b98d036d-b75b-41ee-b483-eec4acf7464b','睡起遣懷','陸游','宋','宋诗','song-poetry','','[]','百事不能能荷鋤，不鋤菜畦鋤芋區。',128,'全唐诗/poet.song.136000.json','["百事不能能荷鋤，不鋤菜畦鋤芋區。", "身存那用十年相，陂壞且爲凶歲儲。", "百事不學學作詩，不作白紵作竹枝。", "黄陵廟前風浪惡，青衣渡口行人悲。", "老病閉門常憒憒，芋不復鋤詩亦廢。", "客來剝啄喚不譍，一味人間占閑退。", "今朝一日三倒床，歎息春晝如年長。", "摩挲困睫喜湯熟，小瓶自拆山茶香。"]'),
('910888f2-7cc9-44e9-8f13-ea2908bc8814','春晴','陸游','宋','宋诗','song-poetry','','[]','柳未吹綿筍未抽，春郊風日正清柔。',64,'全唐诗/poet.song.136000.json','["柳未吹綿筍未抽，春郊風日正清柔。", "疏疏簾影供高卧，裊裊輿竿嬾出遊。", "無客共謀良夜醉，有花空動故年愁。", "雲生祇恐還成雨，自向園頭聽鵓鳩。"]'),
('ed8c042f-e025-49cd-badb-0528cdd076a8','書感','陸游','宋','宋诗','song-poetry','','[]','鴨子陂頭看水生，蜂兒園裏按歌聲。',32,'全唐诗/poet.song.136000.json','["鴨子陂頭看水生，蜂兒園裏按歌聲。", "天公用意誰能測，未許吾曹醉太平。"]'),
('f9c27e0a-69f5-48b0-9419-ef7b2b128f44','野興','陸游','宋','宋诗','song-poetry','','[]','莽莽寬野間，悠悠曠達身。',48,'全唐诗/poet.song.136000.json','["莽莽寬野間，悠悠曠達身。", "氣從林下吐，言向醉中真。", "社櫟元當壽，江鷗豈易馴。", "興來無遠近，隨處岸綸巾。"]'),
('ce1cf2de-3939-4cf5-94b6-c0b9312b901b','野步二首  其一','陸游','宋','宋诗','song-poetry','','[]','堤上淡黄柳，水中花白鵝。',24,'全唐诗/poet.song.136000.json','["堤上淡黄柳，水中花白鵝。", "詩情隨處有，此地得偏多。"]'),
('eae34571-9dcd-45a9-b866-d1955c2a785d','野步二首  其二','陸游','宋','宋诗','song-poetry','','[]','水生已抹堤，草長復侵路。',24,'全唐诗/poet.song.136000.json','["水生已抹堤，草長復侵路。", "小蝶仍可憐，欲下却飛去。"]'),
('93a11402-a2f5-4e64-ac16-de853fe84e9f','稽山','陸游','宋','宋诗','song-poetry','','[]','我識康廬面，亦撫終南背。',120,'全唐诗/poet.song.136000.json','["我識康廬面，亦撫終南背。", "平生愛山心，於此可無悔。", "晚歸古會稽，開門與山對。", "奇峰綰髻鬟，橫嶺掃眉黛。", "豈亦念孤愁，一日變萬態。", "風月娛朝夕，雲烟閲明晦。", "一洗故鄉悲，更益吾廬愛。", "東偏得山多，寢食鮮不在。", "寧無度世人，談笑見英概。", "御風倘可留，爲我傾玉瀣。"]'),
('78335557-0140-450d-981d-99cdaa5eab2f','緋桃開小酌','陸游','宋','宋诗','song-poetry','','[]','我廬城南村，家無十金産。',96,'全唐诗/poet.song.136000.json','["我廬城南村，家無十金産。", "種花雖歷歲，名品終有限。", "頗欲及暇時，著譜書之簡。", "今朝緋桃開，歡喜洗酒醆。", "鄰翁亦喜事，爲我一笑莞。", "但恨苜蓿盤，蔬薄欠佳饌。", "往來見已熟，勸揖忘愧赧。", "一事粗可言，似具識花眼。"]'),
('2d88568b-49f8-4975-9739-24cf26b97e92','夜中獨步','陸游','宋','宋诗','song-poetry','','[]','春半寒初退，更闌睡不成。',48,'全唐诗/poet.song.136000.json','["春半寒初退，更闌睡不成。", "褰裳偶獨起，曳履得徐行。", "月上鳥未宿，水深蛙亂鳴。", "踟躕忽已久，殘漏下高城。"]'),
('9410f86c-e8d6-4ec0-997e-4698e9b20f46','春寒復作','陸游','宋','宋诗','song-poetry','','[]','春寒已解忽復作，病思不堪當語誰。',64,'全唐诗/poet.song.136000.json','["春寒已解忽復作，病思不堪當語誰。", "青燈熒熒耿欲滅，殘雨滴滴休無期。", "故人已死夢中見，壯志未忘心自知。", "青絲玉井聲轣轆，又是窗白鴉鳴時。"]'),
('d9e53615-de8b-4083-9281-ed52235a0975','大雨排悶二首  其一','陸游','宋','宋诗','song-poetry','','[]','地潤礎流水，氣蒸人脫裘。',24,'全唐诗/poet.song.136000.json','["地潤礎流水，氣蒸人脫裘。", "前知暴雨至，孰解老農憂。"]'),
('58d14b2f-93e5-4c75-86c9-d78290ec6b8d','大雨排悶二首  其二','陸游','宋','宋诗','song-poetry','','[]','三日斷行路，束薪無處求。',24,'全唐诗/poet.song.136000.json','["三日斷行路，束薪無處求。", "床頭周易在，且復送悠悠。"]'),
('6a68a16d-074e-4ef5-b71c-51ceca2c985d','室中屏去長物戲作','陸游','宋','宋诗','song-poetry','','[]','久從昭代乞殘骸，荷鍤隨行偶未薶。',32,'全唐诗/poet.song.136000.json','["久從昭代乞殘骸，荷鍤隨行偶未薶。", "四壁盡空君勿怪，纔留一物即關懷。"]'),
('354095a3-b739-44d4-8191-dd93995aa9c0','對酒','陸游','宋','宋诗','song-poetry','','[]','酒非攻愁具，本頼以適意。',48,'全唐诗/poet.song.136000.json','["酒非攻愁具，本頼以適意。", "如接名勝遊，所挹在風味。", "庸子墮世紛，但欲蘄一醉。", "麴生絕俗人，笑汝非真契。"]'),
('835c909d-77eb-4582-9b3e-c0ae1af434e6','曝舊畫','陸游','宋','宋诗','song-poetry','','[]','故篋開緘一愴情，斷縑殘幅尚知名。',64,'全唐诗/poet.song.136000.json','["故篋開緘一愴情，斷縑殘幅尚知名。", "翩翩戲鵲如相語，洶洶驚濤覺有聲。", "柳暗正當烟未斂，花穠仍值雨初晴。", "百年手澤存無幾，蟲蠹塵侵祇涕橫。"]'),
('ffeeda24-2bf6-4ca4-8083-668a48792e27','予以淳熙戊戌歲自蜀歸時年五十四今三十有二年矣猶復强健得小詩自賀','陸游','宋','宋诗','song-poetry','','[]','入玉門關到酒泉，昔人想望若登天。',32,'全唐诗/poet.song.136000.json','["入玉門關到酒泉，昔人想望若登天。", "豈知萬里西征客，歸卧家山三十年。"]'),
('6d880756-1f3c-4fdd-8375-ce3335882ac7','花下小酌二首  其一','陸游','宋','宋诗','song-poetry','','[]','柳色初深燕子回，猩紅千點海棠開。',32,'全唐诗/poet.song.136000.json','["柳色初深燕子回，猩紅千點海棠開。", "鮆魚蒓菜隨宜具，也是花前一醉來。"]'),
('fbfb29fc-63b1-46c9-86be-bf0d40139cad','花下小酌二首  其二','陸游','宋','宋诗','song-poetry','','[]','雲開太華插遥空，我是山中採藥翁。',32,'全唐诗/poet.song.136000.json','["雲開太華插遥空，我是山中採藥翁。", "何日胡塵掃除盡，敷溪道上醉春風。"]'),
('d9f59c4f-3351-4fea-a5a2-c151cfdbf058','夜酌','陸游','宋','宋诗','song-poetry','','[]','我有一瓢酒，與君今夕同。',48,'全唐诗/poet.song.136000.json','["我有一瓢酒，與君今夕同。", "鳴簷社公雨，捲野沛歌風。", "閲世花開落，觀身劫壞空。", "北邙丘壠盡，太息幾英雄。"]'),
('8da9d2d4-bad2-4121-87b8-c0aa34f9b587','數日不作詩','陸游','宋','宋诗','song-poetry','','[]','吾詩鬰不發，孤寂奈愁何。',48,'全唐诗/poet.song.136000.json','["吾詩鬰不發，孤寂奈愁何。", "偶爾得一語，快如疏九河。", "黄流舞浩蕩，白雨助滂沱。", "門外無來客，花前自浩歌。"]'),
('ea6b6881-fec1-4bbd-8dbc-d312b496df9c','幽居示客二首  其一','陸游','宋','宋诗','song-poetry','','[]','嗜睡疏茶碗，逢春愛麴車。',48,'全唐诗/poet.song.136000.json','["嗜睡疏茶碗，逢春愛麴車。", "聊將枕流耳，靜聽屬私蛙。", "林下閑成癖，人間懶莫加。", "孫登欲長嘯，四座且無譁。"]'),
('cc9f0243-2117-4422-bacc-514107b26d30','幽居示客二首  其二','陸游','宋','宋诗','song-poetry','','[]','齒髮雖俱弊，神明尚有餘。',48,'全唐诗/poet.song.136000.json','["齒髮雖俱弊，神明尚有餘。", "幽扉鍊奇藥，細字錄仙書。", "野水鳴苔徑，長松蔭草廬。", "客來多謝病，深愧問何如。"]'),
('01c68538-2c4a-4e81-ac15-1587f372971f','春日登小臺西望','陸游','宋','宋诗','song-poetry','','[]','九十衰翁身尚健，流年過眼如奔電。',128,'全唐诗/poet.song.136000.json','["九十衰翁身尚健，流年過眼如奔電。", "憶昔初來對行在，衫鬢青青接英彥。", "中間亦嘗走梁益，萬里憑高望鄉縣。", "散關驛近柳迎馬，駱谷雪深風裂面。", "東歸却尋書生事，誤長諸儒集賢院。", "乞身七年罪未除，君恩尚許寬嚴譴。", "癡頑亦復病不死，春到故園家釀美。", "雨餘草長四野青，日落烟生半山紫。"]'),
('f08add10-e1c4-4170-ac43-58f5447293a4','醉賦','陸游','宋','宋诗','song-poetry','','[]','我疾多自愈，初非遇奇方。',72,'全唐诗/poet.song.136000.json','["我疾多自愈，初非遇奇方。", "我生固多難，欲慮忽已忘。", "頹然亂書中，不知歲月忙。", "有時或得意，炙冷不暇嘗。", "乃今又大悟，萬事付一觴。", "書中友王績，堂上祠杜康。"]'),
('25a65612-7a10-4f87-b3d9-a0b8d136a58d','即事','陸游','宋','宋诗','song-poetry','','[]','我本區中士，偶來湖上居。',48,'全唐诗/poet.song.136000.json','["我本區中士，偶來湖上居。", "時尋一枕夢，閑展數行書。", "得醉常歡甚，無炊亦晏如。", "今朝好天氣，一笑命柴車。"]'),
('271571b6-6b4c-4d71-9f42-6c2d77eb1330','落花','陸游','宋','宋诗','song-poetry','','[]','山杏溪桃次第開，狂風正用此時來。',32,'全唐诗/poet.song.136000.json','["山杏溪桃次第開，狂風正用此時來。", "未妨老子憑欄興，滿地殘紅點綠苔。"]'),
('184f36e2-8f36-41d7-99da-cdd8342f25e4','春日','陸游','宋','宋诗','song-poetry','','[]','春來日日困春酲，徂歲如馳得我驚。',64,'全唐诗/poet.song.136000.json','["春來日日困春酲，徂歲如馳得我驚。", "山寺饋茶知穀雨，人家插柳記清明。", "登階勃窣晨鷄老，侵路縱橫野草生。", "堪嘆筋骸猶健在，强隨丁壯事深耕。"]'),
('95bcd656-d0e1-4d27-9f9e-8a1ef114e70c','戲詠園中春草二首  其一','陸游','宋','宋诗','song-poetry','','[]','離離幽草自成叢，過眼兒童采擷空。',32,'全唐诗/poet.song.136000.json','["離離幽草自成叢，過眼兒童采擷空。", "不知馬蘭入晨俎，何似燕麥搖春風。"]'),
('e2d64d9f-3047-4266-a9a2-9c0b86f7bd7f','戲詠園中春草二首  其二','陸游','宋','宋诗','song-poetry','','[]','童子爭尋鵓鴿飯，醫翁日曝蝦蟆衣。',32,'全唐诗/poet.song.136000.json','["童子爭尋鵓鴿飯，醫翁日曝蝦蟆衣。", "欲賡楚客詠餐菊，却愧周人歌采薇。"]'),
('485752ec-78e3-472f-a935-a2ca54557a5a','二月二十四日夜大風異常','陸游','宋','宋诗','song-poetry','','[]','天青無雲星錯落，大風忽自西南作。',96,'全唐诗/poet.song.136000.json','["天青無雲星錯落，大風忽自西南作。", "壽藤老木不自全，門外豈容存略彴。", "翁媼驚呼兒女泣，屋瓦飛空吁可愕。", "巢傾共閔烏鵲死，空黑還疑鬼神惡。", "南鄰僅有瓜牛廬，轉盼卷去無遺餘。", "腐儒自笑獨耐事，一燈熒熒猶讀書。"]'),
('dacbc477-a35c-4b39-ab6d-899c88d8445d','雨夜與鄰翁飲用前輩韵','陸游','宋','宋诗','song-poetry','','[]','老人閲世真悠哉，八十已過九十來。',64,'全唐诗/poet.song.136000.json','["老人閲世真悠哉，八十已過九十來。", "茆簷參差映烟樹，蕭條鷄犬三家聚。", "一樽鄰翁迭賓主，醉語豈憂多謬誤。", "我作吳歌君起舞，夜雨莫辭泥沒屨。"]'),
('67cbd899-dca7-4d4f-9514-6f8c37a37512','雜感四首  其一','陸游','宋','宋诗','song-poetry','','[]','壯遊回首海茫茫，默數方驚歲月長。',32,'全唐诗/poet.song.136000.json','["壯遊回首海茫茫，默數方驚歲月長。", "舊事莫論齊柏寢，殘軀方似魯靈光。"]'),
('c70bf404-b30c-44c4-8e93-72e06b3a56c8','雜感四首  其二','陸游','宋','宋诗','song-poetry','','[]','天際晴雲舒復卷，庭中風絮去還來。',32,'全唐诗/poet.song.136000.json','["天際晴雲舒復卷，庭中風絮去還來。", "人生自在常如此，何事能妨笑口開。"]'),
('51718cb2-b5b3-4b94-816d-87d118218b48','雜感四首  其三','陸游','宋','宋诗','song-poetry','','[]','射的山前花柳新，典衣買酒過殘春。',32,'全唐诗/poet.song.136000.json','["射的山前花柳新，典衣買酒過殘春。", "但甘身作噲等伍，莫信人間髯絕倫。"]'),
('a235463a-3685-4246-a3b4-8dd0d0fc6dbc','雜感四首  其四','陸游','宋','宋诗','song-poetry','','[]','禍福雖云不可猜，人生要豈願爲才。',32,'全唐诗/poet.song.136000.json','["禍福雖云不可猜，人生要豈願爲才。", "髑髏正使非王樂，犧象何疑是木災。"]'),
('213bc7ea-3314-4f1c-8272-8e6f9212de8e','讀史二首  其一','陸游','宋','宋诗','song-poetry','','[]','蕭相守關成漢業，穆之一死宋班師。',32,'全唐诗/poet.song.136000.json','["蕭相守關成漢業，穆之一死宋班師。", "赫連拓跋非難取，天意從來未易知。"]'),
('8fa3da9e-dbf8-42fd-80cf-d3c7517e4ae2','讀史二首  其二','陸游','宋','宋诗','song-poetry','','[]','顔良文醜知何益，關羽張飛死可傷。',32,'全唐诗/poet.song.136000.json','["顔良文醜知何益，關羽張飛死可傷。", "等是人間號驍將，太山寧比一毫芒。"]'),
('c74d4780-9061-421f-9e3c-a9022ccedb95','出遊二首  其一','陸游','宋','宋诗','song-poetry','','[]','社近頻逢雨，春深却喜晴。',48,'全唐诗/poet.song.136000.json','["社近頻逢雨，春深却喜晴。", "畬烟傍山起，神鼓隔林鳴。", "客駐觀農饁，兒歸遺母羹。", "豐年多樂事，何以報時平。"]'),
('c87fb083-bec9-4ba8-9e20-e106cc40ba1e','出遊二首  其二','陸游','宋','宋诗','song-poetry','','[]','綠樹魚鹽市，青蕪雉兔場。',48,'全唐诗/poet.song.136000.json','["綠樹魚鹽市，青蕪雉兔場。", "采桑村女集，入學幼童忙。", "戶賽祈蠶願，家藏問孝章。", "村坊多美酒，爛醉答年光。"]'),
('03588f49-6bca-4cb7-9f4e-73984e8887e7','夜興戲作','陸游','宋','宋诗','song-poetry','','[]','遥夜寂無譁，江城鼓屢撾。',48,'全唐诗/poet.song.136000.json','["遥夜寂無譁，江城鼓屢撾。", "傍牆行踸踔，脫帽髮鬖髿。", "詩和玲瓏韵，燈開頃刻花。", "會心有佳處，不寐到啼鴉。"]'),
('9ebaf22d-6301-4406-90a9-8af9a0cc7fee','酒熟書喜','陸游','宋','宋诗','song-poetry','','[]','小槽春夜壓春醪，天與龜堂慰作勞。',64,'全唐诗/poet.song.136000.json','["小槽春夜壓春醪，天與龜堂慰作勞。", "喜似繫囚聞縱釋，快如苛癢得爬搔。", "未陳尊杓心先醉，傍睨江山氣已豪。", "久厭膻葷愁下筯，眼明湖上得雙螯。"]'),
('39f96a68-4efd-4bd4-9bdc-057e3deb43dc','湖上','陸游','宋','宋诗','song-poetry','','[]','寒食初過穀雨前，輕衫短帽影翩翩。',64,'全唐诗/poet.song.136000.json','["寒食初過穀雨前，輕衫短帽影翩翩。", "獨轅碾破新堤路，雙耜犁殘古廟壖。", "萬事不禁劉毅擲，諸人誰著祖生鞭。", "市壚處處誇新釀，且就花陰一醉眠。"]'),
('23341a5f-8675-4dea-b9fa-42b3b55a8aec','春晚','陸游','宋','宋诗','song-poetry','','[]','落絮飛花又滿城，年光大半付春酲。',64,'全唐诗/poet.song.136000.json','["落絮飛花又滿城，年光大半付春酲。", "蹇馿閑後詩情減，陣馬拋來髀肉生。", "少日雕蟲真小技，暮年畫餠更虛名。", "囊中幸有黄庭在，安得高人與細評。"]'),
('874db89d-5a31-4082-9b0c-f8d4a097cb15','食酪','陸游','宋','宋诗','song-poetry','','[]','南烹北饌妄相高，常笑紛紛兒女曹。',32,'全唐诗/poet.song.136000.json','["南烹北饌妄相高，常笑紛紛兒女曹。", "未必鱸魚芼菰菜，便勝羊酪薦櫻桃。"]'),
('b502b91f-06a9-4cbc-9b06-0f835c1641a9','六言六首  其一','陸游','宋','宋诗','song-poetry','','[]','愛馬能成一癖，結髦可忘百憂。',28,'全唐诗/poet.song.136000.json','["愛馬能成一癖，結髦可忘百憂。", "我亦時時自笑，開編萬事俱休。"]'),
('d230560e-cf61-492a-a6fc-8ed42357aa6c','六言六首  其二','陸游','宋','宋诗','song-poetry','','[]','遇合生封萬戶，阨窮不直一錢。',28,'全唐诗/poet.song.136000.json','["遇合生封萬戶，阨窮不直一錢。", "此是由來事爾，正須到處欣然。"]'),
('34352af3-d895-4936-a748-6b300c443323','六言六首  其三','陸游','宋','宋诗','song-poetry','','[]','豪士以妾換馬，耕農賣劍買牛。',28,'全唐诗/poet.song.136000.json','["豪士以妾換馬，耕農賣劍買牛。", "我看浮名似夢，却貪山水閑遊。"]'),
('d5884a06-fd8a-4027-b4c6-e3ecf9cc8e6b','六言六首  其四','陸游','宋','宋诗','song-poetry','','[]','風細飛花相逐，林深啼鳥移時。',28,'全唐诗/poet.song.136000.json','["風細飛花相逐，林深啼鳥移時。", "客至旋開新茗，僧歸未拾殘棋。"]'),
('65d4a61b-4a10-4748-b248-387e79498f65','六言六首  其五','陸游','宋','宋诗','song-poetry','','[]','覓飽如籌大事，擁書似墮重圍。',28,'全唐诗/poet.song.136000.json','["覓飽如籌大事，擁書似墮重圍。", "誤喜敲門客至，出看啄木驚飛。"]'),
('82e039f8-e80e-4816-8719-dcdf4394f710','六言六首  其六','陸游','宋','宋诗','song-poetry','','[]','香烟觸簾不散，燈焰無風自搖。',28,'全唐诗/poet.song.136000.json','["香烟觸簾不散，燈焰無風自搖。", "獨倚蒲團寂寂，忽聞山雨蕭蕭。"]'),
('6a6fd6d9-a4db-404b-ba76-b921eb296c6e','書意示子孫','陸游','宋','宋诗','song-poetry','','[]','我閲人間久，深知理惡盈。',48,'全唐诗/poet.song.136000.json','["我閲人間久，深知理惡盈。", "孳孳訓來裔，堇堇作儒生。", "仕勿卑曹掾，書纔記姓名。", "茆茨不啻足，此外盡浮榮。"]'),
('18138666-0a94-4d63-a9f7-6a543b66b5c8','暮春龜堂即事四首  其一','陸游','宋','宋诗','song-poetry','','[]','風日初和晝漏長，蕭然巾屨集茆堂。',64,'全唐诗/poet.song.136000.json','["風日初和晝漏長，蕭然巾屨集茆堂。", "雨餘千疊暮山綠，花落一溪春水香。", "斷簡櫝中塵委積，故人墓上草荒凉。", "爾來幸有寬懷處，病退床頭減藥囊。"]'),
('87460942-4a98-46dd-af27-baf501dbf93e','暮春龜堂即事四首  其二','陸游','宋','宋诗','song-poetry','','[]','躑躅花開照眼明，緩扶藤杖繞廊行。',64,'全唐诗/poet.song.136000.json','["躑躅花開照眼明，緩扶藤杖繞廊行。", "流年又見一春過，苦雨略無三日晴。", "覓句未應妨熟睡，漱泉聊足解餘酲。", "鹿麛稚子常追逐，誰識山翁及物情。"]'),
('e822852c-2f9a-4149-a7fe-6fb84242211e','暮春龜堂即事四首  其三','陸游','宋','宋诗','song-poetry','','[]','日月無根去若馳，故園又見落花時。',64,'全唐诗/poet.song.136000.json','["日月無根去若馳，故園又見落花時。", "杯中綠酒不肯飲，鏡裏蒼顔應自知。", "千丈新堤湖水滿，五更殘漏角聲悲。", "暮年父子難乖隔，淮浦書來苦覺遲。"]'),
('83b27112-eaa2-4475-b556-086b1ab42ff1','暮春龜堂即事四首  其四','陸游','宋','宋诗','song-poetry','','[]','東皇促駕又天涯，一片難尋墮地花。',64,'全唐诗/poet.song.136000.json','["東皇促駕又天涯，一片難尋墮地花。", "瘦策穿林數新筍，素屏圍枕聽鳴蛙。", "蠶房已裏清明種，茶戶初收穀雨芽。", "欲把一杯壺已罄，謾搜詩句答年華。"]'),
('47f1dad0-d65e-4f8e-9964-e74c7604a89f','莫辭酒','陸游','宋','宋诗','song-poetry','','[]','勸君莫辭酒，酒能解君愁。',72,'全唐诗/poet.song.136000.json','["勸君莫辭酒，酒能解君愁。", "勸君勤采藥，藥可使疾瘳。", "此外莫廢書，書亦豈君悞。", "古來敗人事，正以不學故。", "愁去疾亦平，便腹如瓠壺。", "努力貯萬卷，無此令君愚。"]'),
('1d21796a-5f1e-472d-98ce-e7cd3ad39dab','懷友','陸游','宋','宋诗','song-poetry','','[]','酒家旗下分携久，山驛燈前感慨頻。',32,'全唐诗/poet.song.136000.json','["酒家旗下分携久，山驛燈前感慨頻。", "人事已隨雙鬢改，柳條又見一年新。"]'),
('45cc25ed-dea3-4635-97c1-c0fb54e83b89','蘭亭道上四首  其一','陸游','宋','宋诗','song-poetry','','[]','湖上青山古會稽，斷雲漠漠雨凄凄。',32,'全唐诗/poet.song.136000.json','["湖上青山古會稽，斷雲漠漠雨凄凄。", "籃輿晚過偏門市，滿路春泥聞竹鷄。"]'),
('1aa6c645-3bfa-43db-ae0b-69129fe30d3b','蘭亭道上四首  其二','陸游','宋','宋诗','song-poetry','','[]','蘭亭步口水如天，茶市紛紛趁雨前。',32,'全唐诗/poet.song.136000.json','["蘭亭步口水如天，茶市紛紛趁雨前。", "烏笠遊僧雲際去，白衣醉叟道傍眠。"]'),
('5378f257-dc73-4a48-9039-329678ac0b7e','蘭亭道上四首  其三','陸游','宋','宋诗','song-poetry','','[]','陌上行歌日正長，吳蠶捉績麥登場。',32,'全唐诗/poet.song.136000.json','["陌上行歌日正長，吳蠶捉績麥登場。", "蘭亭酒美逢人醉，花塢茶新滿市香。"]'),
('41760e2d-c60e-40d7-8957-41f42a7b4c0f','蘭亭道上四首  其四','陸游','宋','宋诗','song-poetry','','[]','箭箙弓弢小獵回，壯心自笑未低摧。',32,'全唐诗/poet.song.136000.json','["箭箙弓弢小獵回，壯心自笑未低摧。", "前身家近盤閶路，曾看吳王射雉來。"]'),
('b511d04f-5938-49ff-b695-4a4e40135586','殘年','陸游','宋','宋诗','song-poetry','','[]','殘年光景易駸駸，屏迹江村不厭深。',64,'全唐诗/poet.song.136000.json','["殘年光景易駸駸，屏迹江村不厭深。", "新麥熟時蠶上簇，晚鶑啼處柳成陰。", "短檠已負觀書眼，孤劍空懷許國心。", "惟有雲山差可樂，杖藜誰與伴幽尋。"]'),
('23f8a24d-78b3-4a95-ae74-7399e234d94d','春老','陸游','宋','宋诗','song-poetry','','[]','春色垂垂老，山家處處忙。',48,'全唐诗/poet.song.136000.json','["春色垂垂老，山家處處忙。", "園丁賣菰白，蠶妾采桑黄。", "候雨占秧信，催兒築麥場。", "醉眠官道上，人爲護牛羊。"]'),
('bf05bce2-5ab8-4d46-9a5a-4b3cc8a64a5a','睡起','陸游','宋','宋诗','song-poetry','','[]','睡起披衣弄素琴，房櫳槐柳綠成陰。',64,'全唐诗/poet.song.136000.json','["睡起披衣弄素琴，房櫳槐柳綠成陰。", "春殘鵯鵊如多恨，雨惡酴醿欲不禁。", "羸病强行常踸踔，戇愚多慮每噫喑。", "行年九十猶賒死，誰測高高厚厚心。"]'),
('4c049bf6-fef0-4550-9e2c-f629841306f1','自規','陸游','宋','宋诗','song-poetry','','[]','立志當如塞决河，犀編鐵硯未爲過。',64,'全唐诗/poet.song.136000.json','["立志當如塞决河，犀編鐵硯未爲過。", "文難稱意古所恨，學不盡才今亦多。", "四海交朋常隔闊，一生光景易蹉跎。", "耄年尚欲鞭吾後，太息無人爲詆訶。"]'),
('23103b8b-4ae2-492a-86bb-f54b64e710f6','夜聞雷雨大作','陸游','宋','宋诗','song-poetry','','[]','暗空霧雨無時已，卷地風雷却是晴。',32,'全唐诗/poet.song.136000.json','["暗空霧雨無時已，卷地風雷却是晴。", "九十老翁更事久，寄言兒女不須驚。"]'),
('be67182b-f577-47d8-81c8-dbafe8d6b8c3','賞小園牡丹有感','陸游','宋','宋诗','song-poetry','','[]','雒陽牡丹面徑尺，鄜畤牡丹高丈餘。',64,'全唐诗/poet.song.136000.json','["雒陽牡丹面徑尺，鄜畤牡丹高丈餘。", "世間尤物有如此，恨我總角東吳居。", "俗人用意苦局促，目所未見輒謂無。", "周漢故都亦豈遠，安得尺箠驅群胡。"]'),
('7b7fc6ca-bdf7-4801-8ccf-adbc6d2fdbac','山居','陸游','宋','宋诗','song-poetry','','[]','平生絕愛山居樂，老去初心亦漸償。',64,'全唐诗/poet.song.136000.json','["平生絕愛山居樂，老去初心亦漸償。", "直道本知天可恃，曠懷真與世相忘。", "徑穿修竹衣巾爽，盤設靈苗匕箸香。", "但恨相逢無魯叟，浩歌小試接輿狂。"]'),
('576eb931-5e3a-4957-90a8-c148acaafb17','閑咏五首  其一','陸游','宋','宋诗','song-poetry','','[]','蕭蕭華髮映烏巾，五十年前故史臣。',64,'全唐诗/poet.song.136000.json','["蕭蕭華髮映烏巾，五十年前故史臣。", "正使老來無老伴，未妨閑處作閑人。", "按行池水知增耗，點檢庭花見故新。", "更有庵中策勛事，投床鼻息聒比鄰。"]'),
('d436464a-592f-4f33-8f59-7016d94f0bf9','閑咏五首  其二','陸游','宋','宋诗','song-poetry','','[]','事業無聞負聖時，滄波自照角巾欹。',64,'全唐诗/poet.song.136000.json','["事業無聞負聖時，滄波自照角巾欹。", "養成林下無窮懶，占盡人間徹底癡。", "小麥繞村苗鬰鬰，柔桑滿陌椹纍纍。", "醫翁筮叟真堪友，搜索殘尊與共持。"]'),
('e9affda2-27d8-473e-a252-96da448a81fa','閑咏五首  其三','陸游','宋','宋诗','song-poetry','','[]','謝事歸來一把茅，村深樵牧日論交。',64,'全唐诗/poet.song.136000.json','["謝事歸來一把茅，村深樵牧日論交。", "未言客路塵衣化，最恨書窗鐵硯凹。", "戀戀故袍誰復念，便便癡腹敢辭嘲。", "卜居雖僻吾猶悟，失却岷山理鶴巢。"]'),
('bc6ddb3f-09eb-4e76-83ef-718309768e70','閑咏五首  其四','陸游','宋','宋诗','song-poetry','','[]','白頭羈客更堪論，身寄城南桑竹村。',64,'全唐诗/poet.song.136000.json','["白頭羈客更堪論，身寄城南桑竹村。", "一榻琴書春寂寂，四山霧雨晝昏昏。", "常情共笑門庭冷，好事虛推輩行尊。", "燒筍炊粳真過足，兒曹不用致魚餐。"]'),
('8091fced-34f8-45cd-a65b-40caa0a88e2c','閑咏五首  其五','陸游','宋','宋诗','song-poetry','','[]','危途九折浩無津，晚幸收身作散人。',64,'全唐诗/poet.song.136000.json','["危途九折浩無津，晚幸收身作散人。", "俸祿既空憂患少，酒殽雖薄笑歌頻。", "多添布褐方知老，凈掃茆衡不覺貧。", "南陌東阡元在望，柴車懶駕動經旬。"]'),
('62d27970-7427-4849-a671-5a282e719249','讀樂天詩','陸游','宋','宋诗','song-poetry','','[]','放姬鬻駱初何有，常笑香山恨不攄。',32,'全唐诗/poet.song.136000.json','["放姬鬻駱初何有，常笑香山恨不攄。", "輸與此翁容易死，一身之外更無餘。"]'),
('854901fd-e1d7-4581-a62c-09daac57c7fc','讀許渾詩','陸游','宋','宋诗','song-poetry','','[]','裴相功名冠四朝，許渾身世落漁樵。',32,'全唐诗/poet.song.136000.json','["裴相功名冠四朝，許渾身世落漁樵。", "若論風月江山主，丁卯橋應勝午橋。"]'),
('7ba82f1c-bc3e-49d8-8435-ea5c3635ab57','時鳥','陸游','宋','宋诗','song-poetry','','[]','日出鳴布穀，月落鳴子規。',96,'全唐诗/poet.song.136000.json','["日出鳴布穀，月落鳴子規。", "一氣之所感，彼亦不自知。", "架犁最晚至，適當農事時。", "丁壯戴星出，力作孰敢遲。", "鳴者既有警，聞者得以思。", "乃知失時輩，强聒終何爲。", "百舌亦能言，今默乃其宜。", "我作時鳥篇，用繼豳人詩。"]'),
('24827e80-ed62-4428-b959-b76b02cddeb1','齒髮嘆','陸游','宋','宋诗','song-poetry','','[]','樂天悲脫髮，退之嘆墮齒。',72,'全唐诗/poet.song.136000.json','["樂天悲脫髮，退之嘆墮齒。", "吾年垂九十，此事已晚矣。", "髮脫妨危冠，齒墮廢大嚼。", "晨興對清鏡，何以慰寂寞。", "造物本無心，豈欲使汝衰。", "曷不望長空，兩曜無停時。"]'),
('99cafd61-75ee-407d-aac1-2790b9cfb62b','送春','陸游','宋','宋诗','song-poetry','','[]','新葉張翠幄，落花作紅茵。',96,'全唐诗/poet.song.136000.json','["新葉張翠幄，落花作紅茵。", "山蔬旨且柔，家釀清而淳。", "以我垂老境，送此將歸春。", "我固惜流年，春亦記陳人。", "江山處處佳，風月日日新。", "蹇馿度松岡，短檝橫烟津。", "蘭亭人已遠，遺韵猶清真。", "却下木柵市，天風吹角巾。"]'),
('ada480d4-b4ad-4862-b32d-aa3ba6e4bc34','初夏二首  其一','陸游','宋','宋诗','song-poetry','','[]','新綠陰中燕子飛，數家烟火自相依。',64,'全唐诗/poet.song.136000.json','["新綠陰中燕子飛，數家烟火自相依。", "童誇犢健浮溪過，婦閔蠶饑負葉歸。", "地暖小畦花汞長，泥融幽徑藥苗肥。", "却居樂事何堪數，一醉旗亭又典衣。"]'),
('0d65fa7c-aad5-4ca3-9d0f-88189c927403','初夏二首  其二','陸游','宋','宋诗','song-poetry','','[]','江鄉初夏暑猶輕，霽日園林有晚鶑。',64,'全唐诗/poet.song.136000.json','["江鄉初夏暑猶輕，霽日園林有晚鶑。", "聊置尊罍師北海，盡除屏障學東平。", "綠槐露溼單衣爽，紅藥風翻病眼明。", "每感流年成絕嘆，白頭自笑未忘情。"]'),
('ee83cd94-de82-4582-b8e8-75856d6bc90b','初夏即事','陸游','宋','宋诗','song-poetry','','[]','夏景遽如許，先從草木知。',48,'全唐诗/poet.song.136000.json','["夏景遽如許，先從草木知。", "朱櫻連蒂剪，紅藥带花移。", "病起單衣怯，身閑晝漏遲。", "空齋無長事，簾影看參差。"]'),
('571ec3b3-7bf7-46d5-9b46-edaa1e5f2f5c','古壽人至聞五郎頗有老態作長句自遣','陸游','宋','宋诗','song-poetry','','[]','齒落髮斑兒亦老，志衰力惰我寧悲。',64,'全唐诗/poet.song.136000.json','["齒落髮斑兒亦老，志衰力惰我寧悲。", "埋盆便可爲池看，折竹何妨作馬騎。", "點誦內篇莊叟語，長歌半格白公詩。", "此身未死須安頓，除却山村百不宜。"]'),
('cb5e3ee2-037c-4208-8c45-6dce43ed1419','郊行','陸游','宋','宋诗','song-poetry','','[]','春郊無處不堪行，滿路人家笑語聲。',64,'全唐诗/poet.song.136000.json','["春郊無處不堪行，滿路人家笑語聲。", "賣劍買牛知盜息，乞漿得酒喜時平。", "西村日落川雲暝，東嶺虹收海氣清。", "農事方興戒遊惰，爲君來往主齊盟。"]'),
('11aea26e-357e-41ab-a0f5-13393cba94d2','小園','陸游','宋','宋诗','song-poetry','','[]','小園草木手栽培，袤丈清池數尺臺。',64,'全唐诗/poet.song.136000.json','["小園草木手栽培，袤丈清池數尺臺。", "拄杖倦時閑倚壁，芳醪熟後喜傳杯。", "春蕪滿地鹿忘去，夏木成陰鶑自來。", "堪笑山童慚飽食，時時走報一花開。"]'),
('071c5078-3053-48d3-878f-2334045d55be','初夏雜興五首  其一','陸游','宋','宋诗','song-poetry','','[]','隠趣與誰論，深居湖上村。',48,'全唐诗/poet.song.136000.json','["隠趣與誰論，深居湖上村。", "避蘭寧改路，惜筍不開園。", "庭草饒生意，溪沙記漲痕。", "愁來時淺酌，隨事有鷄豚。"]'),
('ca81d93b-cf40-47a0-abd1-1447a06607a2','初夏雜興五首  其二','陸游','宋','宋诗','song-poetry','','[]','避寂諸緣息，安貧百慮寬。',48,'全唐诗/poet.song.136000.json','["避寂諸緣息，安貧百慮寬。", "懶如常抱疾，退似本無官。", "皎潔鶴翎扇，嵯峨龜屋冠。", "何勞問唐舉，徹屋是清寒。"]'),
('7681c73a-24b5-4bf4-b329-461cac2b9171','初夏雜興五首  其三','陸游','宋','宋诗','song-poetry','','[]','咄咄無窮事，騰騰暫寓身。',48,'全唐诗/poet.song.136000.json','["咄咄無窮事，騰騰暫寓身。", "月生知改朔，花盡覺經春。", "市鬨朝沽酒，巫歌夜樂神。", "興來隨衆出，一笑不妨新。"]'),
('2cf1512d-bce3-4f82-af2b-b70a912290db','初夏雜興五首  其四','陸游','宋','宋诗','song-poetry','','[]','移花得微雨，晒藥遇新晴。',48,'全唐诗/poet.song.136000.json','["移花得微雨，晒藥遇新晴。", "悶裏家書到，貧時糴價平。", "身方抱沉疾，天乃相餘生。", "莫恨村醪薄，燈前與細傾。"]'),
('d9ff9a00-b135-4330-ba31-63b3c17a9a52','初夏雜興五首  其五','陸游','宋','宋诗','song-poetry','','[]','倦甚惟思睡，閑來却要行。',48,'全唐诗/poet.song.136000.json','["倦甚惟思睡，閑來却要行。", "疏泉入幽圃，映樹覘流鶑。", "藥品從僧問，琴材就客評。", "轉頭還一日，正爾送餘生。"]'),
('dcc462ef-4820-44da-bf43-36dbb4725141','思子虡','陸游','宋','宋诗','song-poetry','','[]','里堠迢迢阻問津，年光冉冉苦催人。',64,'全唐诗/poet.song.136000.json','["里堠迢迢阻問津，年光冉冉苦催人。", "未能免俗予嗟老，豈不懷歸汝念親。", "家釀湖蒓誰共醉，江雲淮月又經春。", "新詩題罷無從寄，獨倚危闌一愴神。"]'),
('64190765-652a-440c-a25f-48b6a8bac72e','偶思蜀道有賦','陸游','宋','宋诗','song-poetry','','[]','天回驛畔江如染，鳳集城邊柳似搓。',64,'全唐诗/poet.song.136000.json','["天回驛畔江如染，鳳集城邊柳似搓。", "萬事已隨流水去，一尊將奈夕陽何。", "是非無定言何益，窮達徐觀得孰多。", "幸有漁蓑歸故里，不妨高枕且酣歌。"]'),
('7326fe85-f0d2-4411-bb82-a21334cd49fb','書意','陸游','宋','宋诗','song-poetry','','[]','養得山林氣粗全，此懷無處不超然。',64,'全唐诗/poet.song.136000.json','["養得山林氣粗全，此懷無處不超然。", "日長琴弈茆簷下，歲晚江湖箬帽前。", "天上本令星主酒，俗間妄謂世無仙。", "今年茶比常年早，笑試西峰一掬泉。"]'),
('a70a9418-f5d0-410d-a95c-afe5302c6cdb','贈倪道士二首  其一','陸游','宋','宋诗','song-poetry','','[]','羽衣暫脫著戎衣，坐定方驚語入微。',32,'全唐诗/poet.song.136000.json','["羽衣暫脫著戎衣，坐定方驚語入微。", "歸隠玉霄應不出，他年容我扣巖扉。"]'),
('28e8f35b-05c9-4bad-9e51-044170c8315f','贈倪道士二首  其二','陸游','宋','宋诗','song-poetry','','[]','我坐虛名剩得窮，百年身墮畏途中。',32,'全唐诗/poet.song.136000.json','["我坐虛名剩得窮，百年身墮畏途中。", "看君一棹烟波樂，悔不常爲采藥翁。"]'),
('79e7dbb8-600c-4196-8e16-ec061b8f352a','哭李孟達','陸游','宋','宋诗','song-poetry','','[]','舊交多已謝明時，孟達奇才最所思。',64,'全唐诗/poet.song.136000.json','["舊交多已謝明時，孟達奇才最所思。", "晚歲立朝雖小試，平生苦學竟誰知。", "尊前一笑終無日，地下相從却有期。", "慟絕寢門霜日暮，短篇聊爲寫餘悲。"]'),
('6b7e33c4-04d4-4718-8935-6a0bf6d9102c','送黄文叔守福州','陸游','宋','宋诗','song-poetry','','[]','黄公天下士，遇主紹熙年。',96,'全唐诗/poet.song.136000.json','["黄公天下士，遇主紹熙年。", "議論前修似，聲名九牧傳。", "巨舟夷險濟，拱璧始終全。", "勇退先諸老，榮歸總十連。", "旌旄照關路，冠蓋盛離筵。", "內閣恩光重，宸毫墨色鮮。", "任方分斧鉞，歸即珥貂蟬。", "病叟難爲別，臨期一悵然。"]'),
('f0883cea-0288-495b-90c9-0759cb55f5cb','初夏雜詠五首  其一','陸游','宋','宋诗','song-poetry','','[]','揮袖謝人間，一窗如海寬。',48,'全唐诗/poet.song.136000.json','["揮袖謝人間，一窗如海寬。", "鹿麛爲老伴，松屑當朝餐。", "自悟達生理，儘容非意干。", "却嫌孤寂甚，支竈學燒丹。"]'),
('777a7bd6-c306-4448-a1b1-bb421106842f','初夏雜詠五首  其二','陸游','宋','宋诗','song-poetry','','[]','病退身仍健，年侵趣更高。',48,'全唐诗/poet.song.136000.json','["病退身仍健，年侵趣更高。", "芳醪溢蠻榼，短褐束郿縚。", "本不營三窟，何由挫一毫。", "烟帆幾時掛，長嘯破秋濤。"]'),
('e66ab582-5255-432b-98d4-1f9d6c2a5cfb','初夏雜詠五首  其三','陸游','宋','宋诗','song-poetry','','[]','屐路緣虛壁，棋軒枕小灘。',48,'全唐诗/poet.song.136000.json','["屐路緣虛壁，棋軒枕小灘。", "玄言不愧籍，熟睡却輸摶。", "咄咄書常懶，便便腹本寬。", "山園時節好，杏子已微丹。"]'),
('c09b5ab7-e74f-4c76-bf27-ec29365c4ea1','初夏雜詠五首  其四','陸游','宋','宋诗','song-poetry','','[]','去日驚鑽燧，窮途困負薪。',48,'全唐诗/poet.song.136000.json','["去日驚鑽燧，窮途困負薪。", "故人天末遠，薄俗眼邊新。", "踽踽飄零客，悠悠剩長身。", "寸心知已矣，端欲爲誰陳。"]'),
('3e1ee74d-ba44-4267-9c71-95f345bb71c9','初夏雜詠五首  其五','陸游','宋','宋诗','song-poetry','','[]','昔日江湖上，飄然無定居。',48,'全唐诗/poet.song.136000.json','["昔日江湖上，飄然無定居。", "頻傾京口酒，亦食武昌魚。", "北首心空壯，東歸憤不攄。", "豈知牙齒落，送老一茆廬。"]'),
('3921efe1-17ca-4f1f-9744-572fbfb269c4','即事','陸游','宋','宋诗','song-poetry','','[]','萬里山河拱至尊，羽林鐵騎若雲屯。',64,'全唐诗/poet.song.136000.json','["萬里山河拱至尊，羽林鐵騎若雲屯。", "群公先正不復作，故國世臣誰尚存。", "河洛可令終左衽，蒭蕘何自達修門。", "王師一日臨榆塞，小醜黄頭豈足吞。"]'),
('48e735bd-19c5-4fa5-b42b-72701963904e','漁扉','陸游','宋','宋诗','song-poetry','','[]','蜻蜓浦上一漁扉，回首人間萬事非。',64,'全唐诗/poet.song.136000.json','["蜻蜓浦上一漁扉，回首人間萬事非。", "賣藥山城携鶴去，看碑野寺策馿歸。", "偶因束带悲腰減，常爲梳頭感髮稀。", "午睡定知無客攪，曲肱閑看雨霏霏。"]'),
('26391558-0605-4563-bfab-efee2754bf0d','山行見三十年前題名悵然有賦','陸游','宋','宋诗','song-poetry','','[]','百年村落半丘墟，垂老經過一柅車。',64,'全唐诗/poet.song.136000.json','["百年村落半丘墟，垂老經過一柅車。", "金石闕訛秦漢舊，山川勝絕晉唐餘。", "醉題墨淡塵昏壁，詩社人亡泪濺裾。", "名宦半生成底事，早時恨不學犁鉏。"]'),
('30b8196c-0efa-423b-a753-8181e9657867','山房','陸游','宋','宋诗','song-poetry','','[]','柴門不掩俗人稀，成就山房一段奇。',64,'全唐诗/poet.song.136000.json','["柴門不掩俗人稀，成就山房一段奇。", "木葉最宜新雨後，鳥聲更勝暮春時。", "家貲屢罄緣耽酒，宿習猶存爲愛詩。", "別有一條差自慰，朮苗芎茁正離離。"]'),
('3df1e3f3-458a-42e9-87af-b67d8e42f6ea','縱筆四首  其一','陸游','宋','宋诗','song-poetry','','[]','兀兀一無爲，冥冥百不知。',48,'全唐诗/poet.song.136000.json','["兀兀一無爲，冥冥百不知。", "倦多惟嗜睡，食晚遂忘饑。", "開卷渾如夢，逢人不省誰。", "何須覓知識，木石即吾師。"]'),
('a0b9f980-8b12-4aaa-99e9-d4825fa48c76','縱筆四首  其二','陸游','宋','宋诗','song-poetry','','[]','一點湛空明，居然萬事輕。',48,'全唐诗/poet.song.136000.json','["一點湛空明，居然萬事輕。", "菜元勝肉食，車豈異徒行。", "幻境終何在，金丹本自成。", "信能如是解，土苴亦長生。"]'),
('f81c2c67-1138-42ef-9c4f-f7c20ccecfec','縱筆四首  其三','陸游','宋','宋诗','song-poetry','','[]','薙草除枯葉，勞人亦動心。',48,'全唐诗/poet.song.136000.json','["薙草除枯葉，勞人亦動心。", "無愁疏把酒，習懶罷彈琴。", "濯垢臨溪水，追凉就木陰。", "常尋省力處，外物孰能侵。"]'),
('b52ef37d-3f56-43dd-ae2b-5e872e7132fb','縱筆四首  其四','陸游','宋','宋诗','song-poetry','','[]','夢事飽曾經，靈臺了不驚。',48,'全唐诗/poet.song.136000.json','["夢事飽曾經，靈臺了不驚。", "冤親同一妄，魔佛兩皆平。", "應物如風過，投床即鼾聲。", "晨興拂几硯，猶恨太勞生。"]'),
('8a02569e-e36a-4ebe-afbb-0bafaa8117b0','窗下戲詠三首  其一','陸游','宋','宋诗','song-poetry','','[]','飛來山鳥語惺惚，却是幽人半睡中。',32,'全唐诗/poet.song.136000.json','["飛來山鳥語惺惚，却是幽人半睡中。", "新竹成陰無彈射，不妨同享北窗風。"]');
